code:
type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type FlatObject = Record<string, Primitive | unknown[]>;

function isTraversable(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  // Only recurse into plain objects — not Date, RegExp, Map, Set, Array, etc.
  return (proto === Object.prototype || proto === null) && !Array.isArray(value);
}

function flatten(
  obj: Record<string, unknown>,
  prefix: string,
  ancestors: WeakSet<object>,
  result: Record<string, unknown>
): void {
  if (ancestors.has(obj)) {
    // Circular reference detected — treat the node as a leaf to avoid infinite recursion.
    if (prefix) result[prefix] = obj;
    return;
  }

  ancestors.add(obj);

  const keys = Object.keys(obj);

  for (const key of keys) {
    // Sanitize empty-string keys to avoid producing leading/trailing/double dots.
    const safeKey = key === "" ? '""' : key;
    const newKey = prefix === "" ? safeKey : `${prefix}.${safeKey}`;
    const value = obj[key];

    if (isTraversable(value)) {
      if (Object.keys(value).length === 0) {
        // Empty plain object — preserve as a leaf so the path isn't silently dropped.
        result[newKey] = value;
      } else {
        flatten(value, newKey, ancestors, result);
      }
    } else {
      result[newKey] = value;
    }
  }

  // Remove from ancestors after processing so the same object reference
  // can legitimately appear in a separate, non-circular branch of the tree.
  ancestors.delete(obj);
}

export default function flattenObject(obj: Record<string, unknown>): Record<string, unknown> {
  if (!isTraversable(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${obj === null ? "null" : typeof obj}`
    );
  }

  const result: Record<string, unknown> = {};
  flatten(obj, "", new WeakSet(), result);
  return result;
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Expected a non-negative finite number for delay, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const argsToInvoke = pendingArgs;
      pendingArgs = null;
      if (argsToInvoke !== null) {
        fn(...argsToInvoke);
      }
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
      const argsToInvoke = pendingArgs;
      pendingArgs = null;
      if (argsToInvoke !== null) {
        fn(...argsToInvoke);
      }
    }
  };

  return debounced;
}

type NestedValue = string | number | boolean | null | undefined | Date | RegExp | unknown[] | NestedObject;
type NestedObject = { [key: string]: NestedValue };
type FlatObject = { [key: string]: NestedValue };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  // Catch Map, Set, Buffer, and other host objects
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  obj: NestedObject,
  prefix: string = "",
  seen: Set<object> = new Set()
): FlatObject {
  if (!isPlainObject(obj)) {
    // Guard: caller passed a non-plain-object at the top level
    return prefix ? { [prefix]: obj as NestedValue } : {};
  }

  // Circular reference guard
  if (seen.has(obj)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }
  seen.add(obj);

  const result: FlatObject = {};
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Preserve empty objects as leaf values so callers can distinguish
    // { a: {} } → { "a": {} } rather than silently swallowing the key
    if (prefix) result[prefix] = obj;
    seen.delete(obj);
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const compositeKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const nested = flattenObject(value, compositeKey, seen);
      Object.assign(result, nested);
    } else {
      result[compositeKey] = value;
    }
  }

  // Remove from seen so the same reference can appear in sibling branches
  seen.delete(obj);
  return result;
}

export default flattenObject;

type AnyFunction = (...args: never[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }
  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Delay must be a non-negative finite number, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let isFlushing = false;

  function cancel(): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  }

  function flush(): void {
    if (isFlushing) return;
    if (pendingArgs === undefined) return;

    const argsToApply = pendingArgs;
    cancel();

    isFlushing = true;
    try {
      fn(...argsToApply);
    } finally {
      isFlushing = false;
    }
  }

  function debounced(...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const argsToApply = pendingArgs;
      pendingArgs = undefined;

      if (argsToApply !== undefined && !isFlushing) {
        fn(...argsToApply);
      }
    }, delay);
  }

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  const flush = (): void => {
    if (timerId !== undefined && pendingArgs !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
      const args = pendingArgs;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const invokeArgs = pendingArgs;
      pendingArgs = undefined;
      if (invokeArgs !== undefined) {
        fn(...invokeArgs);
      }
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const invoke = () => {
    if (pendingArgs !== null) {
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    invoke();
  };

  return debounced;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, LRUNode<T>>;
  // Sentinel nodes: head.next = most recently used, tail.prev = least recently used
  private readonly head: LRUNode<T>;
  private readonly tail: LRUNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(`LRUCache capacity must be a non-negative integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = new LRUNode<T>("__head__", undefined as unknown as T);
    this.tail = new LRUNode<T>("__tail__", undefined as unknown as T);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);

    if (node === undefined) {
      return undefined;
    }

    // Promote to most recently used
    this.detach(node);
    this.insertAfterHead(node);

    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache accepts no entries — every write is a no-op
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      // Update value in place and promote to most recently used
      existing.value = value;
      this.detach(existing);
      this.insertAfterHead(existing);
      return;
    }

    // Evict the least recently used entry before inserting when at capacity
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev!;

      // Guard: only evict if lru is a real node (not the head sentinel)
      if (lru !== this.head) {
        this.detach(lru);
        this.map.delete(lru.key);
      }
    }

    const node = new LRUNode<T>(key, value);
    this.insertAfterHead(node);
    this.map.set(key, node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private detach(node: LRUNode<T>): void {
    // Both prev and next must be set for any node that was properly inserted
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private insertAfterHead(node: LRUNode<T>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }
}

class LRUNode<T> {
  key: string;
  value: T;
  prev: LRUNode<T> | null = null;
  next: LRUNode<T> | null = null;

  constructor(key: string, value: T) {
    this.key = key;
    this.value = value;
  }
}

export default LRUCache;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const fullRange = range(min, max);

  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Step value: */step or start-end/step
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let base: number[];
    if (rangePart === "*") {
      base = fullRange;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${rangePart}"`);
      if (start < min || end > max || start > end) {
        throw new Error(`Range "${rangePart}" out of bounds [${min}, ${max}]`);
      }
      base = range(start, end);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step base: "${rangePart}"`);
      if (start < min || start > max) {
        throw new Error(`Value ${start} out of bounds [${min}, ${max}]`);
      }
      base = range(start, max);
    }

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: "${field}"`);
    }
    if (start < min || end > max || start > end) {
      throw new Error(`Range "${field}" out of bounds [${min}, ${max}]`);
    }

    return range(start, end);
  }

  // Wildcard
  if (field === "*") {
    return fullRange;
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: "${field}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}, ${max}]`);
  }

  return [value];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const rawParts = [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr];

  const result = {} as CronResult;

  for (let i = 0; i < fields.length; i++) {
    const key = fields[i];
    const [min, max] = FIELD_RANGES[key];
    try {
      result[key] = parseField(rawParts[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid "${key}" field ("${rawParts[i]}"): ${(err as Error).message}`
      );
    }
  }

  return result;
}

type PlainValue = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = Record<string, unknown>;
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function isTraversable(value: unknown): value is NestedObject | unknown[] {
  return isPlainObject(value) || Array.isArray(value);
}

function flattenInto(
  input: NestedObject | unknown[],
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(input as object)) {
    throw new Error(
      `flattenObject: circular reference detected at key "${prefix}"`
    );
  }

  ancestors.add(input as object);

  const entries = Array.isArray(input)
    ? input.map((v, i) => [String(i), v] as [string, unknown])
    : Object.entries(input);

  for (const [key, value] of entries) {
    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (isTraversable(value)) {
      const childKeys = Array.isArray(value)
        ? value.length
        : Object.keys(value).length;

      if (childKeys === 0) {
        // Empty object/array — preserve as a leaf; flattening it would lose the key entirely
        result[fullKey] = value;
      } else {
        flattenInto(value as NestedObject | unknown[], fullKey, result, ancestors);
      }
    } else {
      result[fullKey] = value;
    }
  }

  // Remove after processing so the same reference in a sibling branch isn't
  // mistaken for a cycle (DAG-safe traversal)
  ancestors.delete(input as object);
}

function flattenObject(obj: NestedObject): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject: expected a plain object, got ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flattenInto(obj, "", result, new WeakSet());
  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both = Sunday
};

const FIELD_ORDER: Array<keyof CronFields> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function isInteger(value: number): boolean {
  return Number.isFinite(value) && Math.floor(value) === value;
}

function parseNumber(token: string, field: string): number {
  const trimmed = token.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new CronParseError(
      `Invalid numeric value "${trimmed}" in field "${field}"`
    );
  }
  const n = Number(trimmed);
  if (!isInteger(n)) {
    throw new CronParseError(
      `Non-integer value "${trimmed}" in field "${field}"`
    );
  }
  return n;
}

function assertInRange(
  value: number,
  config: FieldConfig,
  field: string,
  context: string
): void {
  if (value < config.min || value > config.max) {
    throw new CronParseError(
      `Value ${value} out of range [${config.min}-${config.max}] in ${context} for field "${field}"`
    );
  }
}

function generateRange(start: number, end: number, step: number): number[] {
  if (step < 1) {
    throw new CronParseError(`Step value must be >= 1, got ${step}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(
  segment: string,
  config: FieldConfig,
  field: string
): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new CronParseError(`Empty segment in field "${field}"`);
  }

  // Wildcard: * or */step
  if (trimmed === "*") {
    return generateRange(config.min, config.max, 1);
  }

  // Step with wildcard: */step
  if (trimmed.startsWith("*/")) {
    const stepPart = trimmed.slice(2);
    if (stepPart === "") {
      throw new CronParseError(`Missing step value after "*/" in field "${field}"`);
    }
    const step = parseNumber(stepPart, field);
    if (step === 0) {
      throw new CronParseError(`Step value cannot be 0 in field "${field}"`);
    }
    return generateRange(config.min, config.max, step);
  }

  // Range with optional step: start-end or start-end/step
  if (trimmed.includes("-")) {
    const slashIndex = trimmed.indexOf("/");
    const rangePart = slashIndex !== -1 ? trimmed.slice(0, slashIndex) : trimmed;
    const stepPart  = slashIndex !== -1 ? trimmed.slice(slashIndex + 1) : "1";

    const dashIndex = rangePart.indexOf("-");
    const startStr  = rangePart.slice(0, dashIndex);
    const endStr    = rangePart.slice(dashIndex + 1);

    if (startStr === "" || endStr === "") {
      throw new CronParseError(`Malformed range "${rangePart}" in field "${field}"`);
    }

    const start = parseNumber(startStr, field);
    const end   = parseNumber(endStr, field);
    assertInRange(start, config, field, `range start "${rangePart}"`);
    assertInRange(end, config, field, `range end "${rangePart}"`);

    if (start > end) {
      throw new CronParseError(
        `Range start ${start} > end ${end} in field "${field}"`
      );
    }

    if (stepPart === "") {
      throw new CronParseError(`Missing step value after "/" in field "${field}"`);
    }

    const step = parseNumber(stepPart, field);
    if (step === 0) {
      throw new CronParseError(`Step value cannot be 0 in field "${field}"`);
    }

    return generateRange(start, end, step);
  }

  // Step on a specific base value: value/step
  if (trimmed.includes("/")) {
    const parts = trimmed.split("/");
    if (parts.length !== 2) {
      throw new CronParseError(`Malformed step expression "${trimmed}" in field "${field}"`);
    }
    const base = parseNumber(parts[0], field);
    const step = parseNumber(parts[1], field);
    assertInRange(base, config, field, `step base "${trimmed}"`);
    if (step === 0) {
      throw new CronParseError(`Step value cannot be 0 in field "${field}"`);
    }
    return generateRange(base, config.max, step);
  }

  // Plain number
  const value = parseNumber(trimmed, field);
  assertInRange(value, config, field, `value "${trimmed}"`);
  return [value];
}

function parseField(
  expression: string,
  config: FieldConfig,
  field: string
): number[] {
  if (expression === null || expression === undefined) {
    throw new CronParseError(`Null or undefined expression for field "${field}"`);
  }

  const parts = expression.split(",");
  if (parts.length === 0) {
    throw new CronParseError(`Empty expression for field "${field}"`);
  }

  const valueSet = new Set<number>();

  for (const part of parts) {
    const values = parseSegment(part, config, field);
    for (const v of values) {
      // Normalize dayOfWeek: 7 (Sunday) → 0
      if (field === "dayOfWeek" && v === 7) {
        valueSet.add(0);
      } else {
        valueSet.add(v);
      }
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError("Cron expression must be a string");
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  // Collapse multiple spaces/tabs to a single space
  const normalized = trimmed.replace(/\s+/g, " ");
  const fields = normalized.split(" ");

  if (fields.length !== 5) {
    throw new CronParseError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config    = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(fields[i], config, fieldName);
  }

  return result;
}

export default parseCron;

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (key === undefined || key === null) {
      return undefined;
    }

    if (!this.cache.has(key)) {
      return undefined;
    }

    // Promote to most-recently-used by re-inserting at Map tail
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
  }

  set(key: string, value: T): void {
    if (key === undefined || key === null) {
      throw new TypeError(`LRUCache key must not be null or undefined`);
    }

    if (value === undefined) {
      throw new TypeError(
        `LRUCache value must not be undefined — use delete() to remove a key`
      );
    }

    if (this.capacity === 0) {
      // Zero-capacity cache: accept the write silently but store nothing
      return;
    }

    if (this.cache.has(key)) {
      // Update existing key: delete first so re-insertion lands at tail
      this.cache.delete(key);
      this.cache.set(key, value);
      return;
    }

    // Evict least-recently-used (Map iterator yields insertion order, so
    // the very first key is the oldest / least-recently-used entry)
    if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  get size(): number {
    return this.cache.size;
  }

  has(key: string): boolean {
    return this.cache.has(key);
  }

  delete(key: string): boolean {
    return this.cache.delete(key);
  }

  clear(): void {
    this.cache.clear();
  }
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_META: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}–${max}] in expression part "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new SyntaxError(`Expected an integer, got "${raw}" in "${context}"`);
  }
  return parseInt(raw, 10);
}

function expandRange(start: number, end: number, step: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start (${start}) must be ≤ end (${end})`);
  }
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSinglePart(part: string, min: number, max: number): number[] {
  // Detect and reject multiple slashes early
  const slashCount = (part.match(/\//g) ?? []).length;
  if (slashCount > 1) {
    throw new SyntaxError(`Multiple slashes are not allowed in "${part}"`);
  }

  // Step expression: <range-or-*> / <step>
  if (slashCount === 1) {
    const slashIdx = part.indexOf('/');
    const base  = part.slice(0, slashIdx);
    const stepRaw = part.slice(slashIdx + 1);

    if (!base || !stepRaw) {
      throw new SyntaxError(`Malformed step expression "${part}"`);
    }

    const step = parseInteger(stepRaw, part);
    if (step === 0) {
      throw new RangeError(`Step value cannot be zero in "${part}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (base === '*') {
      rangeMin = min;
      rangeMax = max;
    } else if (base.includes('-')) {
      const dashParts = base.split('-');
      if (dashParts.length !== 2 || !dashParts[0] || !dashParts[1]) {
        throw new SyntaxError(`Invalid range in step expression "${part}"`);
      }
      rangeMin = parseInteger(dashParts[0], part);
      rangeMax = parseInteger(dashParts[1], part);
    } else {
      rangeMin = parseInteger(base, part);
      rangeMax = max;
    }

    assertInRange(rangeMin, min, max, part);
    assertInRange(rangeMax, min, max, part);

    return expandRange(rangeMin, rangeMax, step);
  }

  // Wildcard
  if (part === '*') {
    return expandRange(min, max, 1);
  }

  // Range: <start>-<end>
  if (part.includes('-')) {
    const dashParts = part.split('-');
    if (dashParts.length !== 2 || !dashParts[0] || !dashParts[1]) {
      throw new SyntaxError(`Invalid range expression "${part}"`);
    }
    const start = parseInteger(dashParts[0], part);
    const end   = parseInteger(dashParts[1], part);
    assertInRange(start, min, max, part);
    assertInRange(end,   min, max, part);
    return expandRange(start, end, 1);
  }

  // Single numeric value
  const value = parseInteger(part, part);
  assertInRange(value, min, max, part);
  return [value];
}

function parseField(field: string, min: number, max: number): number[] {
  if (!field || field.trim() === '') {
    throw new SyntaxError(`Cron field must not be empty`);
  }

  const parts = field.split(',');
  if (parts.some(p => p === '')) {
    throw new SyntaxError(`Empty segment in comma list "${field}"`);
  }

  const seen = new Set<number>();

  for (const part of parts) {
    for (const value of parseSinglePart(part.trim(), min, max)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (expression == null || typeof expression !== 'string') {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === '') {
    throw new SyntaxError('Cron expression must not be empty');
  }

  // Split on any run of whitespace
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields separated by whitespace; ` +
      `received ${fields.length} field(s) in "${expression}"`
    );
  }

  const fieldNames: FieldName[] = ['minute', 'hour', 'dayOfMonth', 'month', 'dayOfWeek'];

  const result = {} as CronExpression;

  for (let i = 0; i < 5; i++) {
    const name = fieldNames[i];
    const { min, max } = FIELD_META[name];
    try {
      result[name] = parseField(fields[i], min, max);
    } catch (err) {
      // Re-throw with field context so callers know exactly where the failure was
      const message = err instanceof Error ? err.message : String(err);
      throw new (err instanceof RangeError ? RangeError : SyntaxError)(
        `Invalid ${name} field ("${fields[i]}"): ${message}`
      );
    }
  }

  return result;
}

type AnyFunction = (...args: unknown[]) => unknown;

interface DebouncedFunction<T extends AnyFunction> {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
}

function debounce<T extends AnyFunction>(fn: T, delay: number): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  const normalizedDelay = Number.isFinite(delay) && delay >= 0 ? delay : 0;

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const invoke = (): void => {
    if (pendingArgs !== null) {
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  };

  const clearTimer = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;
    clearTimer();
    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, normalizedDelay);
  };

  debounced.cancel = (): void => {
    clearTimer();
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    clearTimer();
    invoke();
  };

  return debounced;
}

export default debounce;

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Expected a non-negative finite number for delay, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  const flush = (): void => {
    if (timerId !== null && pendingArgs !== null) {
      clearTimeout(timerId);
      timerId = null;
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const argsToCall = pendingArgs;
      pendingArgs = null;
      if (argsToCall !== null) {
        fn(...argsToCall);
      }
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const satisfies readonly FieldConfig[];

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^-?\d+$/.test(trimmed)) {
    throw new Error(`Invalid integer "${trimmed}" in ${context}`);
  }
  const n = Number(trimmed);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    throw new Error(`Non-integer value "${trimmed}" in ${context}`);
  }
  return n;
}

function assertInBounds(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of range [${config.min}–${config.max}] for field "${config.name}"`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const ctx = `field "${config.name}"`;

  // Step expression: */step  |  start/step  |  start-end/step
  if (segment.includes("/")) {
    const slashIndex = segment.indexOf("/");
    const rangeStr = segment.slice(0, slashIndex);
    const stepStr  = segment.slice(slashIndex + 1);

    if (!stepStr) throw new Error(`Missing step value after "/" in ${ctx}`);
    const step = parseInteger(stepStr, `${ctx} step`);
    if (step <= 0) throw new Error(`Step must be a positive integer in ${ctx}, got ${step}`);

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      start = config.min;
      end   = config.max;
    } else if (rangeStr.includes("-")) {
      const dashIndex = rangeStr.indexOf("-");
      start = parseInteger(rangeStr.slice(0, dashIndex), `${ctx} range start`);
      end   = parseInteger(rangeStr.slice(dashIndex + 1), `${ctx} range end`);
    } else {
      start = parseInteger(rangeStr, `${ctx} step base`);
      end   = config.max;
    }

    assertInBounds(start, config);
    assertInBounds(end,   config);

    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in ${ctx}`);
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return buildRange(config.min, config.max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIndex = segment.indexOf("-");
    const start = parseInteger(segment.slice(0, dashIndex), `${ctx} range start`);
    const end   = parseInteger(segment.slice(dashIndex + 1), `${ctx} range end`);

    assertInBounds(start, config);
    assertInBounds(end,   config);

    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in ${ctx}`);
    }

    return buildRange(start, end);
  }

  // Single value
  const value = parseInteger(segment, ctx);
  assertInBounds(value, config);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || field.trim() === "") {
    throw new Error(`Empty value for field "${config.name}"`);
  }

  const segments = field.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new Error(`Empty segment in comma-separated list for field "${config.name}"`);
    }
    for (const v of parseSegment(trimmed, config)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: unknown): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error("Cron expression cannot be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields as [
    string, string, string, string, string
  ];

  return {
    minute:     parseField(minuteStr,     FIELD_CONFIGS[0]),
    hour:       parseField(hourStr,       FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthStr, FIELD_CONFIGS[2]),
    month:      parseField(monthStr,      FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dayOfWeekStr,  FIELD_CONFIGS[4]),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    throw new TypeError(
      `deepMerge expects two plain objects, received: ${typeof target}, ${typeof source}`
    );
  }

  const output: PlainObject = Object.assign({}, target);

  for (const key of Object.keys(source)) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

    const sourceVal = source[key];
    const targetVal = output[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      output[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      output[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      output[key] = sourceVal;
    }
    // If sourceVal is undefined, preserve the target value (no-op)
  }

  return output as T & S;
}

export default deepMerge;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: (keyof CronResult)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function range(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Invalid range: ${start}-${end} (start must be <= end)`);
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function validateValue(value: number, config: FieldConfig, context: string): void {
  if (!Number.isInteger(value)) {
    throw new TypeError(`Invalid value in ${context}: "${value}" is not an integer`);
  }
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} in ${context} is out of range [${config.min}, ${config.max}]`
    );
  }
}

function parseNumber(token: string, context: string): number {
  const n = Number(token);
  if (isNaN(n)) {
    throw new TypeError(`Invalid number "${token}" in ${context}`);
  }
  return n;
}

function parseSegment(segment: string, config: FieldConfig, fieldName: string): number[] {
  const context = `field "${fieldName}", segment "${segment}"`;

  // Step value: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseNumber(stepPart, context);
    if (!Number.isInteger(step) || step < 1) {
      throw new RangeError(`Step value must be a positive integer in ${context}`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = config.min;
      end = config.max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-");
      start = parseNumber(s, context);
      end = parseNumber(e, context);
      validateValue(start, config, context);
      validateValue(end, config, context);
    } else {
      start = parseNumber(rangePart, context);
      validateValue(start, config, context);
      end = config.max;
    }

    if (start > end) {
      throw new RangeError(`Invalid range ${start}-${end} in ${context}`);
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return range(config.min, config.max);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [s, e] = segment.split("-");
    const start = parseNumber(s, context);
    const end = parseNumber(e, context);
    validateValue(start, config, context);
    validateValue(end, config, context);
    return range(start, end);
  }

  // Single number
  const value = parseNumber(segment, context);
  validateValue(value, config, context);
  return [value];
}

function parseField(field: string, config: FieldConfig, fieldName: string): number[] {
  const segments = field.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new TypeError(`Empty segment in field "${fieldName}"`);
    }
    const values = parseSegment(trimmed, config, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length} in "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(fields[i], config, fieldName);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { delimiter?: string; maxDepth?: number } = {}
): FlattenedObject {
  const { delimiter = ".", maxDepth = 100 } = options;

  if (delimiter === "" ) {
    throw new Error("Delimiter must be a non-empty string");
  }

  if (!isPlainObject(input)) {
    throw new TypeError("Input must be a plain object");
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(`Maximum depth of ${maxDepth} exceeded at key "${prefix}"`);
    }

    if (!isPlainObject(current)) {
      result[prefix] = current as Primitive;
      return;
    }

    if (seen.has(current)) {
      throw new TypeError(`Circular reference detected at key "${prefix}"`);
    }

    const keys = Object.keys(current);

    if (keys.length === 0) {
      // Preserve empty objects as-is under the prefix key, only if prefix is set
      if (prefix !== "") {
        result[prefix] = {} as unknown as Primitive;
      }
      return;
    }

    seen.add(current);

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

      const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
      recurse(current[key], newKey, depth + 1);
    }

    seen.delete(current);
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
      return result;
    }
    obj.forEach((item, index) => {
      const key = prefix ? `${prefix}.${index}` : `${index}`;
      if (item !== null && typeof item === "object") {
        flattenObject(item as NestedObject, key, result);
      } else {
        result[key] = item as Primitive;
      }
    });
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

type Scalar = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Scalar | unknown[] | object };
type FlatObject = Record<string, Scalar | unknown[] | object>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: NestedObject,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key "${prefix}"`
    );
  }

  ancestors.add(obj);

  const keys = Object.keys(obj);

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      // Recurse into non-empty plain objects only.
      // Empty plain objects, arrays, Dates, Maps, Sets, etc. are treated as leaf values.
      flattenObjectInternal(value, fullKey, result, ancestors);
    } else {
      result[fullKey] = value as Scalar | unknown[] | object;
    }
  }

  ancestors.delete(obj);
}

export default function flattenObject(obj: NestedObject): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flattenObjectInternal(obj, "", result, new WeakSet<object>());
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = "[]";
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : String(index);
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    const sanitizedKey = key.includes(".") ? `[${key}]` : key;
    const newKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;
    if (!this.map.has(key)) return undefined;

    const value = this.map.get(key) as T;
    // Re-insert to mark as most recently used
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("LRUCache does not support storing undefined as a value");
    }

    if (this.map.has(key)) {
      // Remove first so re-insertion moves it to most-recently-used position
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      // Evict the least recently used entry (first key in insertion order)
      const lruKey = this.map.keys().next().value;
      if (lruKey !== undefined) {
        this.map.delete(lruKey);
      }
    }

    this.map.set(key, value);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (typeof key !== "string") return false;
    return this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;
    return this.map.delete(key);
  }

  clear(): void {
    this.map.clear();
  }

  keys(): IterableIterator<string> {
    return this.map.keys();
  }

  values(): IterableIterator<T> {
    return this.map.values();
  }

  entries(): IterableIterator<[string, T]> {
    return this.map.entries();
  }
}

export default LRUCache;

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Expected a non-negative finite number for delay, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  const flush = (): void => {
    if (timerId === null || pendingArgs === null) {
      return;
    }
    const argsToInvoke = pendingArgs;
    cancel();
    fn(...argsToInvoke);
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      const argsToInvoke = pendingArgs;
      timerId = null;
      pendingArgs = null;
      if (argsToInvoke !== null) {
        fn(...argsToInvoke);
      }
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

interface DLinkedNode<T> {
  key: string;
  value: T;
  prev: DLinkedNode<T> | null;
  next: DLinkedNode<T> | null;
}

function createNode<T>(key: string, value: T): DLinkedNode<T> {
  return { key, value, prev: null, next: null };
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLinkedNode<T>>;
  // Sentinel head (most-recently-used side) and tail (least-recently-used side)
  private readonly head: DLinkedNode<T>;
  private readonly tail: DLinkedNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinels simplify boundary conditions — no null-checks on every splice
    this.head = createNode<T>("__head__", undefined as unknown as T);
    this.tail = createNode<T>("__tail__", undefined as unknown as T);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    // Promote to most-recently-used position
    this.detach(node);
    this.attachAfterHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      // Storing undefined is indistinguishable from a cache miss on get();
      // reject eagerly to prevent silent data loss
      throw new TypeError("LRUCache does not accept undefined as a value");
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      // Update in-place and promote — no eviction needed
      existing.value = value;
      this.detach(existing);
      this.attachAfterHead(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node = createNode<T>(key, value);
    this.map.set(key, node);
    this.attachAfterHead(node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // --- private helpers ---

  private detach(node: DLinkedNode<T>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private attachAfterHead(node: DLinkedNode<T>): void {
    const after = this.head.next!;
    this.head.next = node;
    node.prev = this.head;
    node.next = after;
    after.prev = node;
  }

  private evictLRU(): void {
    const lru = this.tail.prev!;
    if (lru === this.head) {
      // Sentinels are adjacent — nothing to evict (capacity-check guards this)
      return;
    }
    this.detach(lru);
    this.map.delete(lru.key);
  }
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (source === undefined) return target;
  if (target === undefined) return source;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

      const sourceVal = source[key];
      const targetVal = result[key];

      result[key] = deepMerge(targetVal, sourceVal);
    }

    return result;
  }

  return source;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value) as unknown;
  return proto === Object.prototype || proto === null;
}

// Guard against prototype pollution attacks
const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function mergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  // Both arrays → concatenate into a new array (no mutation of inputs)
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  // Both plain objects → recurse
  if (isPlainObject(target) && isPlainObject(source)) {
    // Break circular references in source to prevent infinite recursion
    if (seen.has(source)) {
      return seen.get(source);
    }

    const result: PlainObject = {};
    // Register before recursing so back-edges resolve to this partial result
    seen.set(source, result);

    // Seed with a shallow copy of target (safe keys only)
    for (const key of Object.keys(target)) {
      if (!UNSAFE_KEYS.has(key)) {
        result[key] = target[key];
      }
    }

    // Merge source keys on top
    for (const key of Object.keys(source)) {
      if (UNSAFE_KEYS.has(key)) continue;
      result[key] = mergeInternal(result[key], source[key], seen);
    }

    return result;
  }

  // Scalar, mismatched types, null, class instances, Dates, etc.
  // → source wins outright; undefined source leaves target in place
  return source === undefined ? target : source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  return mergeInternal(target, source, new WeakMap()) as T & S;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    throw new TypeError("Both target and source must be plain objects");
  }

  const output: PlainObject = Object.assign({}, target);

  for (const key of Object.keys(source)) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

    const sourceVal = source[key];
    const targetVal = output[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      output[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      output[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal === undefined) {
      // Do not overwrite existing target value with undefined
      // unless target also has no value for this key
      if (!(key in output)) {
        output[key] = sourceVal;
      }
    } else {
      output[key] = sourceVal;
    }
  }

  return output as T & S;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
      return result;
    }
    obj.forEach((item, index) => {
      const key = prefix ? `${prefix}.${index}` : `${index}`;
      if (item !== null && typeof item === "object") {
        flattenObject(item as NestedObject, key, result);
      } else {
        result[key] = item as Primitive;
      }
    });
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

// Guard against prototype pollution attacks
const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function mergeInner(
  target: PlainObject,
  source: PlainObject,
  visited: WeakMap<object, object>
): PlainObject {
  // Circular reference guard: if we've already started merging this source
  // object, return the partially-built target to break the cycle
  if (visited.has(source)) {
    return target;
  }
  visited.set(source, target);

  // Shallow-copy target so we never mutate the original
  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    // Skip keys that could corrupt the prototype chain
    if (UNSAFE_KEYS.has(key)) continue;

    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      // Concatenate arrays: target first, source second
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      // Both sides are plain objects — recurse
      result[key] = mergeInner(targetVal, sourceVal, visited);
    } else if (sourceVal !== undefined) {
      // Source wins for all other defined values; skip explicit `undefined`
      // to avoid silently wiping out target keys
      result[key] = sourceVal;
    }
    // sourceVal === undefined → keep existing targetVal unchanged
  }

  return result;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  // Gracefully degrade non-plain-object inputs rather than throwing or
  // silently returning garbage
  const safeTarget: PlainObject = isPlainObject(target) ? target : {};
  const safeSource: PlainObject = isPlainObject(source) ? source : {};

  return mergeInner(safeTarget, safeSource, new WeakMap()) as T & S;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value as string;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { delimiter?: string; maxDepth?: number } = {}
): FlatObject {
  const { delimiter = ".", maxDepth = Infinity } = options;

  if (delimiter === "" || delimiter == null) {
    throw new Error("Delimiter must be a non-empty string");
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `Expected a plain object, got ${input === null ? "null" : typeof input}`
    );
  }

  const result: FlatObject = {};

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      result[prefix] = current as Primitive | unknown[];
      return;
    }

    if (isPlainObject(current)) {
      const keys = Object.keys(current);

      if (keys.length === 0) {
        if (prefix !== "") {
          result[prefix] = {};
        }
        return;
      }

      for (const key of keys) {
        if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

        const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
        recurse((current as Record<string, unknown>)[key], newKey, depth + 1);
      }
    } else {
      if (prefix !== "") {
        result[prefix] = current as Primitive | unknown[];
      }
    }
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function expandRange(start: number, end: number, step: number, min: number, max: number, context: string): number[] {
  assertInRange(start, min, max, context);
  assertInRange(end, min, max, context);

  if (start > end) {
    throw new RangeError(`Range start ${start} is greater than end ${end} in field "${context}"`);
  }

  if (step < 1) {
    throw new RangeError(`Step must be >= 1 in field "${context}"`);
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number, context: string): number[] {
  // Wildcard with optional step: * or */n
  if (segment.startsWith("*")) {
    if (segment === "*") {
      return expandRange(min, max, 1, min, max, context);
    }

    if (segment.startsWith("*/")) {
      const step = parseInt(segment.slice(2), 10);
      if (isNaN(step)) {
        throw new SyntaxError(`Invalid step value in "${segment}" for field "${context}"`);
      }
      return expandRange(min, max, step, min, max, context);
    }

    throw new SyntaxError(`Invalid wildcard expression "${segment}" for field "${context}"`);
  }

  // Range with optional step: n-m or n-m/s
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step)) {
      throw new SyntaxError(`Invalid range expression "${segment}" for field "${context}"`);
    }

    return expandRange(start, end, step, min, max, context);
  }

  // Step on a numeric base: n/s
  if (segment.includes("/")) {
    const [basePart, stepPart] = segment.split("/");
    const base = parseInt(basePart, 10);
    const step = parseInt(stepPart, 10);

    if (isNaN(base) || isNaN(step)) {
      throw new SyntaxError(`Invalid step expression "${segment}" for field "${context}"`);
    }

    return expandRange(base, max, step, min, max, context);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" for field "${context}"`);
  }

  assertInRange(value, min, max, context);
  return [value];
}

function parseField(expression: string, min: number, max: number, context: string): number[] {
  const segments = expression.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field "${context}"`);
    }
    for (const value of parseSegment(trimmed, min, max, context)) {
      valueSet.add(value);
    }
  }

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (context === "dayOfWeek" && valueSet.has(7)) {
    valueSet.delete(7);
    valueSet.add(0);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return {
    minute:     parseField(minuteExpr,  FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max,     fields[0]),
    hour:       parseField(hourExpr,    FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max,       fields[1]),
    dayOfMonth: parseField(domExpr,     FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max, fields[2]),
    month:      parseField(monthExpr,   FIELD_RANGES.month.min,      FIELD_RANGES.month.max,      fields[3]),
    dayOfWeek:  parseField(dowExpr,     FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max,  fields[4]),
  };
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      if (pendingArgs !== null) {
        fn(...pendingArgs);
      }
      timerId = null;
      pendingArgs = null;
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    if (pendingArgs !== null) {
      fn(...pendingArgs);
      pendingArgs = null;
    }
  };

  return debounced;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  seen: WeakSet<object> = new WeakSet()
): FlatObject {
  if (!isPlainObject(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (seen.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix}"`
    );
  }

  seen.add(input as object);

  const entries = Object.entries(input);

  if (entries.length === 0) {
    if (prefix !== "") {
      result[prefix] = {};
    }
    seen.delete(input as object);
    return result;
  }

  for (const [key, value] of entries) {
    if (key === "") continue; // skip empty string keys for safety

    const fullKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flattenObject(value, fullKey, result, seen);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  seen.delete(input as object);
  return result;
}

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: string;
  min: number;
  max: number;
}

const FIELD_CONFIGS: [keyof CronExpression, FieldConfig][] = [
  ["minute",     { name: "minute",     min: 0,  max: 59 }],
  ["hour",       { name: "hour",       min: 0,  max: 23 }],
  ["dayOfMonth", { name: "dayOfMonth", min: 1,  max: 31 }],
  ["month",      { name: "month",      min: 1,  max: 12 }],
  ["dayOfWeek",  { name: "dayOfWeek",  min: 0,  max: 7  }],
];

function assertInRange(value: number, config: FieldConfig): void {
  if (!Number.isInteger(value) || value < config.min || value > config.max) {
    throw new RangeError(
      `${config.name}: value ${value} is outside valid range [${config.min}, ${config.max}]`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  const n = Number(raw);
  if (!Number.isInteger(n) || raw.trim() === "" || /[^0-9]/.test(raw.trim())) {
    throw new SyntaxError(`Expected an integer in "${context}", got "${raw}"`);
  }
  return n;
}

function expandWildcard(config: FieldConfig): number[] {
  const values: number[] = [];
  for (let i = config.min; i <= config.max; i++) values.push(i);
  return values;
}

function expandRange(token: string, config: FieldConfig): number[] {
  const parts = token.split("-");
  if (parts.length !== 2 || parts[0] === "" || parts[1] === "") {
    throw new SyntaxError(`${config.name}: malformed range "${token}"`);
  }
  const start = parseInteger(parts[0], token);
  const end   = parseInteger(parts[1], token);
  assertInRange(start, config);
  assertInRange(end,   config);
  if (start > end) {
    throw new RangeError(
      `${config.name}: range start ${start} exceeds end ${end} in "${token}"`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i++) values.push(i);
  return values;
}

function expandStep(token: string, config: FieldConfig): number[] {
  const slashIdx = token.indexOf("/");
  const base     = token.slice(0, slashIdx);
  const stepRaw  = token.slice(slashIdx + 1);

  if (stepRaw === "") {
    throw new SyntaxError(`${config.name}: missing step value in "${token}"`);
  }

  const step = parseInteger(stepRaw, token);
  if (step <= 0) {
    throw new RangeError(`${config.name}: step must be positive, got ${step}`);
  }

  let start: number;
  let end: number;

  if (base === "*") {
    start = config.min;
    end   = config.max;
  } else if (base.includes("-")) {
    const rangeParts = base.split("-");
    if (rangeParts.length !== 2 || rangeParts[0] === "" || rangeParts[1] === "") {
      throw new SyntaxError(`${config.name}: malformed range in step "${token}"`);
    }
    start = parseInteger(rangeParts[0], token);
    end   = parseInteger(rangeParts[1], token);
    assertInRange(start, config);
    assertInRange(end,   config);
    if (start > end) {
      throw new RangeError(
        `${config.name}: range start ${start} exceeds end ${end} in "${token}"`
      );
    }
  } else {
    start = parseInteger(base, token);
    assertInRange(start, config);
    end = config.max;
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) values.push(i);
  return values;
}

function parseToken(token: string, config: FieldConfig): number[] {
  if (token === "") {
    throw new SyntaxError(`${config.name}: empty token encountered`);
  }
  if (token === "*")         return expandWildcard(token as "*", config);
  if (token.includes("/"))   return expandStep(token, config);
  if (token.includes("-"))   return expandRange(token, config);

  const value = parseInteger(token, config.name);
  assertInRange(value, config);
  return [value];
}

// Overload to satisfy TypeScript narrowing on the wildcard branch
function expandWildcard(_token: "*", config: FieldConfig): number[] {
  const values: number[] = [];
  for (let i = config.min; i <= config.max; i++) values.push(i);
  return values;
}

function parseField(expression: string, config: FieldConfig): number[] {
  const parts = expression.split(",");
  if (parts.length === 0) {
    throw new SyntaxError(`${config.name}: empty field expression`);
  }

  const seen = new Set<number>();
  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new SyntaxError(
        `${config.name}: empty element in comma list "${expression}"`
      );
    }
    for (const v of parseToken(trimmed, config)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, found ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const [key, config] = FIELD_CONFIGS[i];
    result[key] = parseField(fields[i], config);
  }

  // Normalize dayOfWeek: both 0 and 7 represent Sunday — unify to 0
  const dowSet = new Set(result.dayOfWeek);
  if (dowSet.has(7)) {
    dowSet.delete(7);
    dowSet.add(0);
    result.dayOfWeek = Array.from(dowSet).sort((a, b) => a - b);
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (source === undefined) return target;
  if (target === undefined) return source;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      if (!Object.prototype.hasOwnProperty.call(source, key)) continue;
      const sourceVal = source[key];
      const targetVal = result[key];
      result[key] = deepMerge(targetVal, sourceVal);
    }

    return result;
  }

  return source;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (source === undefined) return target;
  if (target === undefined) return source;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = {};

    const allKeys = new Set([
      ...Object.keys(target),
      ...Object.keys(source),
    ]);

    for (const key of allKeys) {
      const hasTarget = Object.prototype.hasOwnProperty.call(target, key);
      const hasSource = Object.prototype.hasOwnProperty.call(source, key);

      if (hasTarget && hasSource) {
        result[key] = deepMerge(target[key], source[key]);
      } else if (hasSource) {
        result[key] = structuredClone(source[key]);
      } else {
        result[key] = structuredClone(target[key]);
      }
    }

    return result;
  }

  return source;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

const DANGEROUS_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  if (source === undefined) return target;
  if (source === null) return null;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    if (seen.has(source)) {
      return seen.get(source);
    }

    const result: PlainObject = Object.assign(Object.create(null), target);
    seen.set(source, result);

    for (const key of Object.keys(source)) {
      if (DANGEROUS_KEYS.has(key)) continue;
      result[key] = mergeInternal(target[key], source[key], seen);
    }

    return result;
  }

  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  return mergeInternal(target, source, new WeakMap()) as T & S;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n or start/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in step: "${rangePart}"`);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step start: "${rangePart}"`);
      end = max;
    }

    validateRange(start, end, min, max, field);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const parts = field.split("-");
    if (parts.length !== 2) throw new Error(`Invalid range: "${field}"`);
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range values: "${field}"`);
    validateRange(start, end, min, max, field);
    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: "${field}"`);
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in field "${field}"`);
  }
  return [value];
}

function validateRange(
  start: number,
  end: number,
  min: number,
  max: number,
  field: string
): void {
  if (start < min || start > max) {
    throw new Error(`Start value ${start} out of range [${min}, ${max}] in field "${field}"`);
  }
  if (end < min || end > max) {
    throw new Error(`End value ${end} out of range [${min}, ${max}] in field "${field}"`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} is greater than end ${end} in field "${field}"`);
  }
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return {
    minute: parseField(minuteStr, ...FIELD_RANGES.minute),
    hour: parseField(hourStr, ...FIELD_RANGES.hour),
    dayOfMonth: parseField(dayOfMonthStr, ...FIELD_RANGES.dayOfMonth),
    month: parseField(monthStr, ...FIELD_RANGES.month),
    dayOfWeek: parseField(dayOfWeekStr, ...FIELD_RANGES.dayOfWeek),
  };
}

export default parseCron;

type DebounceFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebounceFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const invoke = () => {
    if (pendingArgs !== null) {
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    invoke();
  };

  return debounced;
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = Math.floor(capacity);
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key) as T;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value as string;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      if (pendingArgs !== null) {
        fn(...pendingArgs);
        pendingArgs = null;
      }
      timerId = null;
    }, delay);
  };

  debounced.cancel = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    if (pendingArgs !== null) {
      fn(...pendingArgs);
      pendingArgs = null;
    }
  };

  return debounced;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { min: 0, max: 59, name: "minute" },
  { min: 0, max: 23, name: "hour" },
  { min: 1, max: 31, name: "dayOfMonth" },
  { min: 1, max: 12, name: "month" },
  { min: 0, max: 6, name: "dayOfWeek" },
] as const;

function parseInteger(value: string, fieldName: string): number {
  const trimmed = value.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Invalid value "${trimmed}" in field "${fieldName}": must be a non-negative integer`);
  }
  const num = parseInt(trimmed, 10);
  if (!Number.isFinite(num)) {
    throw new Error(`Invalid value "${trimmed}" in field "${fieldName}": not a finite number`);
  }
  return num;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in ${context}`);
  }
}

function expandWildcard(config: FieldConfig): number[] {
  return Array.from({ length: config.max - config.min + 1 }, (_, i) => config.min + i);
}

function expandStep(expression: string, config: FieldConfig): number[] {
  const [basePart, stepPart] = expression.split("/");
  if (stepPart === undefined || stepPart.trim() === "") {
    throw new Error(`Invalid step expression "${expression}" in field "${config.name}"`);
  }

  const step = parseInteger(stepPart, config.name);
  if (step <= 0) {
    throw new Error(`Step value must be >= 1 in field "${config.name}", got ${step}`);
  }

  let rangeMin: number;
  let rangeMax: number;

  if (basePart === "*") {
    rangeMin = config.min;
    rangeMax = config.max;
  } else if (basePart.includes("-")) {
    const [low, high] = parseRange(basePart, config);
    rangeMin = low;
    rangeMax = high;
  } else {
    rangeMin = parseInteger(basePart, config.name);
    assertInRange(rangeMin, config.min, config.max, `field "${config.name}"`);
    rangeMax = config.max;
  }

  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }

  if (values.length === 0) {
    throw new Error(`Step expression "${expression}" in field "${config.name}" produces no values`);
  }

  return values;
}

function parseRange(expression: string, config: FieldConfig): [number, number] {
  const parts = expression.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range expression "${expression}" in field "${config.name}": expected exactly one "-"`);
  }

  const low = parseInteger(parts[0], config.name);
  const high = parseInteger(parts[1], config.name);

  assertInRange(low, config.min, config.max, `range start in field "${config.name}"`);
  assertInRange(high, config.min, config.max, `range end in field "${config.name}"`);

  if (low > high) {
    throw new Error(`Range start ${low} is greater than end ${high} in field "${config.name}"`);
  }

  return [low, high];
}

function expandRange(expression: string, config: FieldConfig): number[] {
  const [low, high] = parseRange(expression, config);
  return Array.from({ length: high - low + 1 }, (_, i) => low + i);
}

function expandSingleValue(expression: string, config: FieldConfig): number[] {
  const value = parseInteger(expression, config.name);
  assertInRange(value, config.min, config.max, `field "${config.name}"`);
  return [value];
}

function expandSegment(segment: string, config: FieldConfig): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new Error(`Empty segment in field "${config.name}"`);
  }

  if (trimmed === "*") {
    return expandWildcard(config);
  }

  if (trimmed.includes("/")) {
    return expandStep(trimmed, config);
  }

  if (trimmed.includes("-")) {
    return expandRange(trimmed, config);
  }

  return expandSingleValue(trimmed, config);
}

function expandField(expression: string, config: FieldConfig): number[] {
  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error(`Empty expression for field "${config.name}"`);
  }

  if (!trimmed.includes(",")) {
    return expandSegment(trimmed, config);
  }

  const segments = trimmed.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = expandSegment(segment, config);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error(`parseCron: expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("parseCron: expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `parseCron: expected 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: expandField(minuteExpr, FIELD_CONFIGS[0]),
    hour: expandField(hourExpr, FIELD_CONFIGS[1]),
    dayOfMonth: expandField(dayOfMonthExpr, FIELD_CONFIGS[2]),
    month: expandField(monthExpr, FIELD_CONFIGS[3]),
    dayOfWeek: expandField(dayOfWeekExpr, FIELD_CONFIGS[4]),
  };
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
};

// dayOfWeek allows 0–7 where 7 is an alias for Sunday (0); normalized after parsing
const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  7 }, // 7 = Sunday alias, normalized to 0
] as const;

function parseIntStrict(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Non-integer value "${raw}" in field "${fieldName}"`);
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Could not parse "${raw}" as integer in field "${fieldName}"`);
  }
  return n;
}

function assertInRange(n: number, min: number, max: number, context: string): void {
  if (n < min || n > max) {
    throw new RangeError(`${context}: ${n} is outside valid range [${min}, ${max}]`);
  }
}

function expandStep(rangeMin: number, rangeMax: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step value must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string,
): number[] {
  // Guard: reject empty or whitespace-only segments
  if (!segment || segment.trim() === "") {
    throw new Error(`Empty segment encountered in field "${fieldName}"`);
  }

  const slashIdx = segment.indexOf("/");

  if (slashIdx !== -1) {
    // Step expression: <range-or-wildcard>/<step>
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount > 1) {
      throw new Error(`Multiple "/" in segment "${segment}" in field "${fieldName}"`);
    }

    const rangePart = segment.slice(0, slashIdx);
    const stepPart  = segment.slice(slashIdx + 1);

    if (stepPart === "" || stepPart === "*") {
      throw new Error(`Missing or invalid step value in "${segment}" in field "${fieldName}"`);
    }

    const step = parseIntStrict(stepPart, fieldName);
    if (step <= 0) {
      throw new RangeError(`Step must be ≥ 1 in field "${fieldName}", got ${step}`);
    }

    if (rangePart === "*") {
      return expandStep(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [startRaw, endRaw, ...extra] = rangePart.split("-");
      if (extra.length > 0) {
        throw new Error(`Malformed range "${rangePart}" in field "${fieldName}"`);
      }
      const start = parseIntStrict(startRaw, fieldName);
      const end   = parseIntStrict(endRaw, fieldName);
      assertInRange(start, min, max, `Range start in field "${fieldName}"`);
      assertInRange(end, min, max, `Range end in field "${fieldName}"`);
      if (start > end) {
        throw new RangeError(
          `Range start ${start} > range end ${end} in field "${fieldName}"`,
        );
      }
      return expandStep(start, end, step);
    }

    // Single-number base with step: e.g. "5/15" → start at 5, step 15 to max
    const start = parseIntStrict(rangePart, fieldName);
    assertInRange(start, min, max, `Step base in field "${fieldName}"`);
    return expandStep(start, max, step);
  }

  // Wildcard
  if (segment === "*") {
    return expandStep(min, max, 1);
  }

  // Range: e.g. "9-17"
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new Error(`Malformed range "${segment}" in field "${fieldName}"`);
    }
    const start = parseIntStrict(parts[0], fieldName);
    const end   = parseIntStrict(parts[1], fieldName);
    assertInRange(start, min, max, `Range start in field "${fieldName}"`);
    assertInRange(end,   min, max, `Range end in field "${fieldName}"`);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} > range end ${end} in field "${fieldName}"`,
      );
    }
    return expandStep(start, end, 1);
  }

  // Plain integer
  const n = parseIntStrict(segment, fieldName);
  assertInRange(n, min, max, `Value in field "${fieldName}"`);
  return [n];
}

function parseField(
  expression: string,
  min: number,
  max: number,
  fieldName: string,
): number[] {
  if (!expression || expression.trim() === "") {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  const segments = expression.split(",");
  if (segments.some((s) => s.trim() === "")) {
    throw new Error(
      `Trailing/leading/double comma in field "${fieldName}": "${expression}"`,
    );
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), min, max, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (expression === null || expression === undefined) {
    throw new TypeError("Cron expression must be a string, received null/undefined");
  }
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be blank");
  }

  const tokens = trimmed.split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 space-separated fields, got ${tokens.length}: "${trimmed}"`,
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(tokens[i], min, max, name);
  }

  // Normalize dayOfWeek: 7 is a widely-used alias for Sunday (0)
  if (result.dayOfWeek.includes(7)) {
    const normalized = new Set(result.dayOfWeek.map((d) => (d === 7 ? 0 : d)));
    result.dayOfWeek = Array.from(normalized).sort((a, b) => a - b);
  }

  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(field: string, min: number, max: number): number[] {
  const results = new Set<number>();

  const parts = field.split(",");

  for (const part of parts) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    if (trimmed.startsWith("*/")) {
      const step = parseInt(trimmed.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${trimmed}"`);
      }
      for (let i = min; i <= max; i += step) results.add(i);
      continue;
    }

    if (trimmed.includes("/")) {
      const [rangePart, stepPart] = trimmed.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${trimmed}"`);
      }
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        const start = parseInt(startStr, 10);
        const end = parseInt(endStr, 10);
        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range in step expression: "${trimmed}"`);
        }
        validateRange(start, end, min, max, trimmed);
        for (let i = start; i <= end; i += step) results.add(i);
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new Error(`Invalid start value in step expression: "${trimmed}"`);
        }
        validateValue(start, min, max, trimmed);
        for (let i = start; i <= max; i += step) results.add(i);
      }
      continue;
    }

    if (trimmed.includes("-")) {
      const [startStr, endStr] = trimmed.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: "${trimmed}"`);
      }
      validateRange(start, end, min, max, trimmed);
      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    const value = parseInt(trimmed, 10);
    if (isNaN(value)) {
      throw new Error(`Invalid value: "${trimmed}"`);
    }
    validateValue(value, min, max, trimmed);
    results.add(value);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateValue(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}, ${max}] in expression: "${context}"`
    );
  }
}

function validateRange(start: number, end: number, min: number, max: number, context: string): void {
  if (start > end) {
    throw new Error(`Range start ${start} is greater than end ${end} in expression: "${context}"`);
  }
  validateValue(start, min, max, context);
  validateValue(end, min, max, context);
}

export default function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteField,
    hourField,
    dayOfMonthField,
    monthField,
    dayOfWeekField,
  ].map((field, index) => {
    const name = fieldNames[index];
    const [min, max] = FIELD_RANGES[name];
    try {
      return parseField(field, min, max);
    } catch (err) {
      throw new Error(
        `Error parsing ${name} field "${field}": ${(err as Error).message}`
      );
    }
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value as string;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

type PlainObject = Record<string, unknown>;

function isPlainObject(val: unknown): val is PlainObject {
  if (val === null || typeof val !== "object") return false;
  const proto = Object.getPrototypeOf(val);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    if (seen.has(source)) {
      return seen.get(source);
    }

    const result: PlainObject = {};
    seen.set(source, result);

    const keys = new Set([
      ...Object.keys(target),
      ...Object.keys(source),
    ]);

    for (const key of keys) {
      const inTarget = Object.prototype.hasOwnProperty.call(target, key);
      const inSource = Object.prototype.hasOwnProperty.call(source, key);

      if (inTarget && inSource) {
        result[key] = mergeInternal(target[key], source[key], seen);
      } else if (inSource) {
        const val = source[key];
        // Deep-clone plain objects and arrays pulled directly from source
        // to avoid aliasing the source reference in the result
        if (isPlainObject(val)) {
          result[key] = mergeInternal({}, val, seen);
        } else if (Array.isArray(val)) {
          result[key] = [...val];
        } else {
          result[key] = val;
        }
      } else {
        const val = target[key];
        if (isPlainObject(val)) {
          result[key] = mergeInternal(val, {}, seen);
        } else if (Array.isArray(val)) {
          result[key] = [...val];
        } else {
          result[key] = val;
        }
      }
    }

    return result;
  }

  // Primitive, class instance, Date, RegExp, etc. — source wins
  return source;
}

export default function deepMerge(
  target: PlainObject,
  source: PlainObject
): PlainObject {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: expected a plain object for 'target', got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: expected a plain object for 'source', got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInternal(target, source, new WeakMap()) as PlainObject;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel nodes: head = most recent end, tail = least recent end
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isFinite(capacity) || !Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, received: ${capacity}`
      );
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels eliminate null-checks on boundary operations
    this.head = { key: "__head__", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "__tail__", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // A zero-capacity cache is valid but silently discards all entries
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.addAfterHead(node);

    if (this.map.size > this.capacity) {
      const evicted = this.detachBeforeTail();
      // evicted can only be null if the list is empty, which cannot happen here
      // since we just inserted a node and capacity >= 1
      if (evicted !== null) {
        this.map.delete(evicted.key);
      }
    }
  }

  get size(): number {
    return this.map.size;
  }

  private addAfterHead(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    // head.next is always non-null (tail sentinel at minimum)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private detachNode(node: Node<T>): void {
    // Sentinels guarantee prev and next are never null for real nodes
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    this.detachNode(node);
    this.addAfterHead(node);
  }

  private detachBeforeTail(): Node<T> | null {
    const node = this.tail.prev;
    if (node === null || node === this.head) {
      // List is empty (only sentinels remain) — should never happen during normal use
      return null;
    }
    this.detachNode(node);
    return node;
  }
}

export default LRUCache;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type NestedObject = {
  [key: string]: Primitive | NestedObject | unknown[] | unknown;
};

type FlattenedObject = Record<string, Primitive | unknown[]>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { preserveArrays?: boolean } = {}
): FlattenedObject {
  const { preserveArrays = true } = options;

  if (!isPlainObject(input)) {
    throw new TypeError(
      `Expected a plain object, got ${input === null ? "null" : typeof input}`
    );
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string): void {
    if (isPlainObject(current)) {
      if (seen.has(current as object)) {
        throw new Error(
          `Circular reference detected at key "${prefix}"`
        );
      }

      const keys = Object.keys(current as NestedObject);

      if (keys.length === 0) {
        if (prefix !== "") {
          result[prefix] = {} as unknown as Primitive;
        }
        return;
      }

      seen.add(current as object);

      for (const key of keys) {
        if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

        const sanitizedKey = key.includes(".")
          ? `["${key}"]`
          : key;

        const nextPrefix =
          prefix === "" ? sanitizedKey : `${prefix}.${sanitizedKey}`;

        recurse((current as NestedObject)[key], nextPrefix);
      }

      seen.delete(current as object);
    } else if (Array.isArray(current)) {
      if (preserveArrays || current.length === 0) {
        result[prefix] = current as unknown[];
      } else {
        if (current.length === 0) {
          result[prefix] = current as unknown[];
          return;
        }
        for (let i = 0; i < current.length; i++) {
          recurse(current[i], `${prefix}[${i}]`);
        }
      }
    } else {
      result[prefix] = current as Primitive;
    }
  }

  recurse(input, "");

  return result;
}

export default flattenObject;

type AnyFunction = (...args: any[]) => any;

interface DebouncedFunction<T extends AnyFunction> {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => ReturnType<T> | undefined;
}

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number,
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  const safeDelay = Number.isFinite(delay) && delay >= 0 ? delay : 0;

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let pendingContext: unknown;

  const cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
    pendingContext = undefined;
  };

  const flush = (): ReturnType<T> | undefined => {
    if (timerId === undefined || pendingArgs === undefined) {
      return undefined;
    }

    clearTimeout(timerId);
    timerId = undefined;

    // Snapshot and clear before invoking to prevent re-entrancy issues
    // if `fn` itself triggers the debounced function again.
    const args = pendingArgs;
    const ctx = pendingContext;
    pendingArgs = undefined;
    pendingContext = undefined;

    return fn.apply(ctx, args) as ReturnType<T>;
  };

  const debounced = function (
    this: unknown,
    ...args: Parameters<T>
  ): void {
    pendingArgs = args;
    pendingContext = this;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout((): void => {
      timerId = undefined;

      // Snapshot and clear before invoking to guard against re-entrancy.
      const savedArgs = pendingArgs;
      const savedCtx = pendingContext;
      pendingArgs = undefined;
      pendingContext = undefined;

      if (savedArgs !== undefined) {
        fn.apply(savedCtx, savedArgs);
      }
    }, safeDelay);
  } as DebouncedFunction<T>;

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
type CronField = (typeof FIELD_NAMES)[number];

export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

// dayOfWeek max is 7 — both 0 and 7 represent Sunday; normalized to 0 on output
const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const UINT_RE = /^\d+$/;

function parseUInt(s: string, context: string): number {
  if (!UINT_RE.test(s)) {
    throw new Error(`Expected a non-negative integer for ${context}, got "${s}"`);
  }
  const n = parseInt(s, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow in ${context}: "${s}"`);
  }
  return n;
}

function assertInRange(value: number, field: CronField, context: string): void {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is outside the valid range [${min}, ${max}] for field "${field}" in ${context}`
    );
  }
}

function expand(start: number, end: number, step: number, context: string): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new Error(`Step must be a positive integer in ${context}, got ${step}`);
  }
  if (start > end) {
    throw new Error(`Range start (${start}) must not exceed end (${end}) in ${context}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseToken(token: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const ctx = `"${token}" (field "${field}")`;

  if (token === "") {
    throw new Error(`Empty token encountered in field "${field}"`);
  }

  // Wildcard: * or */step
  if (token === "*") {
    return expand(min, max, 1, ctx);
  }

  if (token.startsWith("*/")) {
    const stepStr = token.slice(2);
    if (stepStr === "") {
      throw new Error(`Missing step value after "*/" in field "${field}"`);
    }
    const step = parseUInt(stepStr, `step in ${ctx}`);
    if (step === 0) throw new Error(`Step cannot be zero in field "${field}"`);
    return expand(min, max, step, ctx);
  }

  const slashIdx = token.indexOf("/");

  // Determine whether a range dash is present (ignore a leading minus — none expected, but guard it)
  const rangePartForDashCheck = slashIdx !== -1 ? token.slice(0, slashIdx) : token;
  const dashIdx = rangePartForDashCheck.indexOf("-");
  const hasDash = dashIdx > 0; // dash at position 0 would be a malformed negative number

  // Range: start-end  or  start-end/step
  if (hasDash) {
    let step = 1;
    let rangePart = token;

    if (slashIdx !== -1) {
      rangePart = token.slice(0, slashIdx);
      const stepStr = token.slice(slashIdx + 1);
      if (stepStr === "") throw new Error(`Missing step value in ${ctx}`);
      step = parseUInt(stepStr, `step in ${ctx}`);
      if (step === 0) throw new Error(`Step cannot be zero in ${ctx}`);
    }

    const rDashIdx = rangePart.indexOf("-");
    const startStr = rangePart.slice(0, rDashIdx);
    const endStr   = rangePart.slice(rDashIdx + 1);

    if (startStr === "") throw new Error(`Missing range start in ${ctx}`);
    if (endStr === "")   throw new Error(`Missing range end in ${ctx}`);
    if (endStr.includes("-")) throw new Error(`Invalid range format (multiple dashes) in ${ctx}`);

    const rangeStart = parseUInt(startStr, `range start in ${ctx}`);
    const rangeEnd   = parseUInt(endStr,   `range end in ${ctx}`);

    assertInRange(rangeStart, field, ctx);
    assertInRange(rangeEnd,   field, ctx);

    if (rangeStart > rangeEnd) {
      throw new Error(`Range start (${rangeStart}) exceeds end (${rangeEnd}) in ${ctx}`);
    }

    return expand(rangeStart, rangeEnd, step, ctx);
  }

  // Number/step: num/step — start from num, step to field max (common cron extension)
  if (slashIdx !== -1) {
    const numStr  = token.slice(0, slashIdx);
    const stepStr = token.slice(slashIdx + 1);
    if (numStr === "")  throw new Error(`Missing start value in ${ctx}`);
    if (stepStr === "") throw new Error(`Missing step value in ${ctx}`);
    const start = parseUInt(numStr,  `start in ${ctx}`);
    const step  = parseUInt(stepStr, `step in ${ctx}`);
    if (step === 0) throw new Error(`Step cannot be zero in ${ctx}`);
    assertInRange(start, field, ctx);
    return expand(start, max, step, ctx);
  }

  // Plain number
  const num = parseUInt(token, `value in field "${field}"`);
  assertInRange(num, field, ctx);
  return [num];
}

function parseField(expr: string, field: CronField): number[] {
  const trimmed = expr.trim();
  if (trimmed === "") {
    throw new Error(`Empty expression for field "${field}"`);
  }

  const tokens = trimmed.split(",");
  const values = new Set<number>();

  for (const raw of tokens) {
    const token = raw.trim();
    if (token === "") {
      throw new Error(
        `Empty segment in comma-separated list for field "${field}": "${trimmed}"`
      );
    }
    for (const v of parseToken(token, field)) {
      values.add(v);
    }
  }

  // Normalize dayOfWeek: 7 is an alias for Sunday (0)
  const normalized =
    field === "dayOfWeek"
      ? new Set([...values].map(v => (v === 7 ? 0 : v)))
      : values;

  return [...normalized].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string argument, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("parseCron received an empty cron expression");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 space-separated fields, ` +
      `got ${parts.length} in: "${expression}"`
    );
  }

  return {
    minute:     parseField(parts[0], "minute"),
    hour:       parseField(parts[1], "hour"),
    dayOfMonth: parseField(parts[2], "dayOfMonth"),
    month:      parseField(parts[3], "month"),
    dayOfWeek:  parseField(parts[4], "dayOfWeek"),
  };
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

const FIELD_ORDER: (keyof CronExpression)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function validateRange(values: number[], min: number, max: number, field: string): void {
  for (const v of values) {
    if (v < min || v > max) {
      throw new RangeError(
        `Value ${v} out of range [${min}, ${max}] for field "${field}"`
      );
    }
  }
}

function parseField(raw: string, field: keyof CronExpression): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list — recurse on each part and flatten
  if (raw.includes(",")) {
    const values = raw
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step value: */n or start-end/n
  if (raw.includes("/")) {
    const [rangePart, stepStr] = raw.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${raw}" for field "${field}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) {
        throw new SyntaxError(`Invalid range in "${raw}" for field "${field}"`);
      }
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) {
        throw new SyntaxError(`Invalid expression "${raw}" for field "${field}"`);
      }
      end = max;
    }

    validateRange([start, end], min, max, field);
    if (start > end) {
      throw new RangeError(`Start ${start} exceeds end ${end} for field "${field}"`);
    }
    return rangeArray(start, end, step);
  }

  // Wildcard
  if (raw === "*") {
    return rangeArray(min, max);
  }

  // Range: start-end
  if (raw.includes("-")) {
    const [startStr, endStr] = raw.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${raw}" for field "${field}"`);
    }
    validateRange([start, end], min, max, field);
    if (start > end) {
      throw new RangeError(`Start ${start} exceeds end ${end} for field "${field}"`);
    }
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(raw, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${raw}" for field "${field}"`);
  }
  validateRange([value], min, max, field);
  return [value];
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length} in expression "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(parts[i], field);
  }

  // Normalize dayOfWeek: treat 7 as equivalent to 0 (both = Sunday)
  if (result.dayOfWeek.includes(7) && !result.dayOfWeek.includes(0)) {
    result.dayOfWeek = [0, ...result.dayOfWeek.filter((d) => d !== 7)].sort(
      (a, b) => a - b
    );
  } else if (result.dayOfWeek.includes(7)) {
    result.dayOfWeek = result.dayOfWeek.filter((d) => d !== 7);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Readonly<Record<FieldName, { min: number; max: number }>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: ReadonlyArray<FieldName> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function isNonNegativeInteger(s: string): boolean {
  return /^\d+$/.test(s);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${min}–${max}] in ${context}`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new RangeError(`Step must be a positive integer, got ${step}`);
  if (start > end) throw new RangeError(`Range start (${start}) exceeds end (${end})`);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, fieldName: FieldName): number[] {
  const { min, max } = FIELD_RANGES[fieldName];
  const ctx = `field "${fieldName}" segment "${segment}"`;

  // ── step: */N  |  start-end/N  |  N/N ────────────────────────────────────
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Ambiguous step expression in ${ctx}`);
    }
    const [base, stepRaw] = slashParts;

    if (!isNonNegativeInteger(stepRaw)) {
      throw new SyntaxError(`Non-integer step "${stepRaw}" in ${ctx}`);
    }
    const step = Number(stepRaw);
    if (step === 0) throw new RangeError(`Step cannot be zero in ${ctx}`);

    if (base === "*") {
      return expandRange(min, max, step);
    }

    if (base.includes("-")) {
      const rangeParts = base.split("-");
      if (rangeParts.length !== 2 || !isNonNegativeInteger(rangeParts[0]) || !isNonNegativeInteger(rangeParts[1])) {
        throw new SyntaxError(`Invalid range "${base}" in ${ctx}`);
      }
      const start = Number(rangeParts[0]);
      const end   = Number(rangeParts[1]);
      assertInRange(start, min, max, ctx);
      assertInRange(end,   min, max, ctx);
      return expandRange(start, end, step);
    }

    if (isNonNegativeInteger(base)) {
      const start = Number(base);
      assertInRange(start, min, max, ctx);
      return expandRange(start, max, step);
    }

    throw new SyntaxError(`Unparseable base "${base}" in ${ctx}`);
  }

  // ── wildcard ──────────────────────────────────────────────────────────────
  if (segment === "*") {
    return expandRange(min, max, 1);
  }

  // ── plain range: N-M ──────────────────────────────────────────────────────
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2 || !isNonNegativeInteger(parts[0]) || !isNonNegativeInteger(parts[1])) {
      throw new SyntaxError(`Invalid range "${segment}" in ${ctx}`);
    }
    const start = Number(parts[0]);
    const end   = Number(parts[1]);
    assertInRange(start, min, max, ctx);
    assertInRange(end,   min, max, ctx);
    if (start > end) throw new RangeError(`Range start (${start}) > end (${end}) in ${ctx}`);
    return expandRange(start, end, 1);
  }

  // ── single value ──────────────────────────────────────────────────────────
  if (isNonNegativeInteger(segment)) {
    const value = Number(segment);
    assertInRange(value, min, max, ctx);
    return [value];
  }

  throw new SyntaxError(`Unrecognized token "${segment}" in ${ctx}`);
}

function parseField(raw: string, fieldName: FieldName): number[] {
  if (raw.length === 0) {
    throw new SyntaxError(`Empty value for field "${fieldName}"`);
  }

  // ── comma-separated list ──────────────────────────────────────────────────
  const segments = raw.split(",");
  if (segments.some((s) => s.length === 0)) {
    throw new SyntaxError(`Empty segment in comma list for field "${fieldName}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment, fieldName)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || expression.trim().length === 0) {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields; got ${parts.length} in "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(parts[i], fieldName);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { min: 0, max: 59, name: "minute" },
  { min: 0, max: 23, name: "hour" },
  { min: 1, max: 31, name: "dayOfMonth" },
  { min: 1, max: 12, name: "month" },
  { min: 0, max: 7, name: "dayOfWeek" },
] as const;

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function parseInteger(value: string, fieldName: string): number {
  const trimmed = value.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new CronParseError(
      `Invalid integer "${trimmed}" in field "${fieldName}"`
    );
  }
  const num = parseInt(trimmed, 10);
  if (!isFinite(num)) {
    throw new CronParseError(
      `Non-finite integer "${trimmed}" in field "${fieldName}"`
    );
  }
  return num;
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  fieldName: string,
  context?: string
): void {
  if (value < min || value > max) {
    const ctx = context ? ` (${context})` : "";
    throw new CronParseError(
      `Value ${value}${ctx} is out of range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

function generateRange(
  start: number,
  end: number,
  step: number,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (start > end) {
    throw new CronParseError(
      `Range start ${start} is greater than end ${end} in field "${fieldName}"`
    );
  }
  if (step < 1) {
    throw new CronParseError(
      `Step value ${step} must be >= 1 in field "${fieldName}"`
    );
  }
  assertInRange(start, min, max, fieldName, "range start");
  assertInRange(end, min, max, fieldName, "range end");

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  config: FieldConfig
): number[] {
  const { min, max, name } = config;
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new CronParseError(`Empty segment in field "${name}"`);
  }

  // Wildcard: "*"
  if (trimmed === "*") {
    return generateRange(min, max, 1, min, max, name);
  }

  // Step with wildcard: "*/N"
  if (trimmed.startsWith("*/")) {
    const stepStr = trimmed.slice(2);
    if (stepStr === "") {
      throw new CronParseError(
        `Missing step value after "*/" in field "${name}"`
      );
    }
    const step = parseInteger(stepStr, name);
    if (step < 1) {
      throw new CronParseError(
        `Step value ${step} must be >= 1 in field "${name}"`
      );
    }
    return generateRange(min, max, step, min, max, name);
  }

  // Range with optional step: "N-M" or "N-M/S"
  if (/^\d+-\d+(\/\d+)?$/.test(trimmed)) {
    const slashIndex = trimmed.indexOf("/");
    let rangePart: string;
    let step = 1;

    if (slashIndex !== -1) {
      rangePart = trimmed.slice(0, slashIndex);
      const stepStr = trimmed.slice(slashIndex + 1);
      if (stepStr === "") {
        throw new CronParseError(
          `Missing step value after "/" in field "${name}"`
        );
      }
      step = parseInteger(stepStr, name);
    } else {
      rangePart = trimmed;
    }

    const dashIndex = rangePart.indexOf("-");
    const startStr = rangePart.slice(0, dashIndex);
    const endStr = rangePart.slice(dashIndex + 1);

    const start = parseInteger(startStr, name);
    const end = parseInteger(endStr, name);

    return generateRange(start, end, step, min, max, name);
  }

  // Plain number: "N"
  if (/^\d+$/.test(trimmed)) {
    const value = parseInteger(trimmed, name);
    assertInRange(value, min, max, name);
    return [value];
  }

  throw new CronParseError(
    `Unrecognized segment format "${trimmed}" in field "${name}"`
  );
}

function parseField(
  fieldStr: string,
  config: FieldConfig
): number[] {
  if (typeof fieldStr !== "string") {
    throw new CronParseError(
      `Field "${config.name}" must be a string, got ${typeof fieldStr}`
    );
  }

  const trimmed = fieldStr.trim();

  if (trimmed === "") {
    throw new CronParseError(`Field "${config.name}" is empty`);
  }

  // Split on commas to handle comma-separated lists
  const segments = trimmed.split(",");

  if (segments.length === 0) {
    throw new CronParseError(
      `Field "${config.name}" produced no segments after splitting`
    );
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment, config);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (config.name === "dayOfWeek" && valueSet.has(7)) {
    valueSet.delete(7);
    valueSet.add(0);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError(
      `Cron expression must be a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new CronParseError("Cron expression is empty");
  }

  // Split on whitespace
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;

  const minute = parseField(minuteStr, FIELD_CONFIGS[0]);
  const hour = parseField(hourStr, FIELD_CONFIGS[1]);
  const dayOfMonth = parseField(domStr, FIELD_CONFIGS[2]);
  const month = parseField(monthStr, FIELD_CONFIGS[3]);
  const dayOfWeek = parseField(dowStr, FIELD_CONFIGS[4]);

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Expected a non-negative finite number for delay, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const invoke = (): void => {
    if (pendingArgs !== null) {
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    invoke();
  };

  return debounced;
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): ReturnType<T> | undefined;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError("First argument must be a function");
  }

  const normalizedDelay = Math.max(0, Number.isFinite(delay) ? delay : 0);

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const argsToInvoke = pendingArgs;
      pendingArgs = undefined;
      if (argsToInvoke !== undefined) {
        fn(...argsToInvoke);
      }
    }, normalizedDelay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = function (): ReturnType<T> | undefined {
    if (timerId === undefined || pendingArgs === undefined) {
      return undefined;
    }

    clearTimeout(timerId);
    timerId = undefined;

    const argsToInvoke = pendingArgs;
    pendingArgs = undefined;

    return fn(...argsToInvoke) as ReturnType<T>;
  };

  return debounced;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both = Sunday
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

class CronParseError extends Error {
  constructor(message: string) {
    super(`CronParseError: ${message}`);
    this.name = "CronParseError";
  }
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new CronParseError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseNumber(token: string, context: string): number {
  const trimmed = token.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new CronParseError(
      `Expected integer, got "${trimmed}" in field "${context}"`
    );
  }
  const n = parseInt(trimmed, 10);
  if (isNaN(n)) {
    throw new CronParseError(
      `Failed to parse integer "${trimmed}" in field "${context}"`
    );
  }
  return n;
}

function range(from: number, to: number): number[] {
  if (from > to) return [];
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(
  token: string,
  min: number,
  max: number,
  context: string
): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new CronParseError(`Empty segment in field "${context}"`);
  }

  // Wildcard: "*"
  if (trimmed === "*") {
    return range(min, max);
  }

  // Step: "*/N" or "R-S/N"
  if (trimmed.includes("/")) {
    const slashIdx = trimmed.indexOf("/");
    const basePart = trimmed.slice(0, slashIdx);
    const stepPart = trimmed.slice(slashIdx + 1);

    if (stepPart === "" || stepPart.includes("/")) {
      throw new CronParseError(
        `Invalid step expression "${trimmed}" in field "${context}"`
      );
    }

    const step = parseNumber(stepPart, context);
    if (step <= 0) {
      throw new CronParseError(
        `Step must be >= 1, got ${step} in field "${context}"`
      );
    }

    let from: number;
    let to: number;

    if (basePart === "*") {
      from = min;
      to = max;
    } else if (basePart.includes("-")) {
      const hyphenIdx = basePart.indexOf("-");
      from = parseNumber(basePart.slice(0, hyphenIdx), context);
      to   = parseNumber(basePart.slice(hyphenIdx + 1), context);
      assertInRange(from, min, max, context);
      assertInRange(to,   min, max, context);
      if (from > to) {
        throw new CronParseError(
          `Range start ${from} > end ${to} in field "${context}"`
        );
      }
    } else {
      from = parseNumber(basePart, context);
      assertInRange(from, min, max, context);
      to = max;
    }

    const result: number[] = [];
    for (let i = from; i <= to; i += step) result.push(i);
    return result;
  }

  // Range: "N-M"
  if (trimmed.includes("-")) {
    const hyphenIdx = trimmed.indexOf("-");
    const from = parseNumber(trimmed.slice(0, hyphenIdx), context);
    const to   = parseNumber(trimmed.slice(hyphenIdx + 1), context);
    assertInRange(from, min, max, context);
    assertInRange(to,   min, max, context);
    if (from > to) {
      throw new CronParseError(
        `Range start ${from} > end ${to} in field "${context}"`
      );
    }
    return range(from, to);
  }

  // Plain number
  const n = parseNumber(trimmed, context);
  assertInRange(n, min, max, context);
  return [n];
}

function parseField(
  expression: string,
  min: number,
  max: number,
  context: string
): number[] {
  if (expression === null || expression === undefined) {
    throw new CronParseError(`Missing value for field "${context}"`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError(`Empty value for field "${context}"`);
  }

  const segments = trimmed.split(",");
  const values: number[] = [];

  for (const segment of segments) {
    const parsed = parseSegment(segment, min, max, context);
    values.push(...parsed);
  }

  return unique(values);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Both 0 and 7 represent Sunday — normalize 7 → 0
  const normalized = values.map((v) => (v === 7 ? 0 : v));
  return unique(normalized);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError("Expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError("Expression must not be empty");
  }

  // Normalize whitespace: collapse multiple spaces/tabs into one
  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new CronParseError(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const { min, max } = FIELD_RANGES[fieldName];
    let values = parseField(parts[i], min, max, fieldName);

    if (fieldName === "dayOfWeek") {
      values = normalizeDayOfWeek(values);
    }

    result[fieldName] = values;
  }

  return result;
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => ReturnType<T> | undefined;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError("First argument must be a function");
  }

  if (typeof delay !== "number" || !isFinite(delay) || delay < 0) {
    throw new RangeError("Delay must be a non-negative finite number");
  }

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let pendingThis: unknown;

  function cancel(): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
    pendingThis = undefined;
  }

  function flush(): ReturnType<T> | undefined {
    if (pendingArgs === undefined) {
      return undefined;
    }

    const args = pendingArgs;
    const ctx = pendingThis;

    cancel();

    return fn.apply(ctx, args) as ReturnType<T>;
  }

  function debounced(this: unknown, ...args: Parameters<T>): void {
    pendingArgs = args;
    pendingThis = this;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const capturedArgs = pendingArgs;
      const capturedThis = pendingThis;
      pendingArgs = undefined;
      pendingThis = undefined;
      if (capturedArgs !== undefined) {
        fn.apply(capturedThis, capturedArgs);
      }
    }, delay);
  }

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced as DebouncedFunction<T>;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      result[newKey] = JSON.stringify(value);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, LRUNode<T>>;
  private readonly head: LRUNode<T>; // most-recent sentinel
  private readonly tail: LRUNode<T>; // least-recent sentinel

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes eliminate null-checks on every pointer manipulation
    this.head = new LRUNode<T>("__head__", undefined as unknown as T);
    this.tail = new LRUNode<T>("__tail__", undefined as unknown as T);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (key === undefined || key === null) return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (key === undefined || key === null) {
      throw new TypeError(`LRUCache key must be a non-null string, got: ${key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // At capacity — evict the least-recently-used node (just before tail)
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev!;

      // Guard: only evict if it's not the head sentinel
      // (only possible if capacity is honoured, but be paranoid)
      if (lru !== this.head) {
        this.removeNode(lru);
        this.map.delete(lru.key);
      }
    }

    const node = new LRUNode<T>(key, value);
    this.insertAtFront(node);
    this.map.set(key, node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private moveToFront(node: LRUNode<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private removeNode(node: LRUNode<T>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertAtFront(node: LRUNode<T>): void {
    const after = this.head.next!;
    node.prev = this.head;
    node.next = after;
    this.head.next = node;
    after.prev = node;
  }
}

class LRUNode<T> {
  key: string;
  value: T;
  prev: LRUNode<T> | null = null;
  next: LRUNode<T> | null = null;

  constructor(key: string, value: T) {
    this.key = key;
    this.value = value;
  }
}

export default LRUCache;

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number,
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Expected a non-negative finite number for delay, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  function invoke(): void {
    if (pendingArgs !== null) {
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  }

  function clearTimer(): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
  }

  function debounced(...args: Parameters<T>): void {
    pendingArgs = args;
    clearTimer();
    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, delay);
  }

  debounced.cancel = function (): void {
    clearTimer();
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    clearTimer();
    invoke();
  };

  return debounced;
}

interface DLinkedNode<T> {
  key: string;
  value: T;
  prev: DLinkedNode<T> | null;
  next: DLinkedNode<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLinkedNode<T>>;
  private readonly head: DLinkedNode<T>;
  private readonly tail: DLinkedNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinel head and tail nodes eliminate null-checks on insert/remove
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("LRUCache does not allow storing undefined as a value");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: DLinkedNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;

    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head.next;
    while (current !== null && current !== this.tail) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private insertAtFront(node: DLinkedNode<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: DLinkedNode<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: DLinkedNode<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) return;

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      this.cache.delete(this.cache.keys().next().value as string);
    }
    this.cache.set(key, value);
  }
}

export type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldBounds = { min: number; max: number };

const FIELD_NAMES = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const satisfies ReadonlyArray<keyof ParsedCron>;

const FIELD_BOUNDS: Record<keyof ParsedCron, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both represent Sunday
};

function parseNonNegativeInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new RangeError(
      `Expected a non-negative integer but got "${trimmed}" in "${context}"`
    );
  }
  const n = Number(trimmed);
  if (!Number.isSafeInteger(n)) {
    throw new RangeError(`Integer "${trimmed}" exceeds safe integer range in "${context}"`);
  }
  return n;
}

function assertWithinBounds(value: number, bounds: FieldBounds, context: string): void {
  if (value < bounds.min || value > bounds.max) {
    throw new RangeError(
      `Value ${value} is outside the valid range [${bounds.min}–${bounds.max}] in "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start (${start}) must not exceed end (${end})`);
  }
  if (step < 1) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseAtom(token: string, bounds: FieldBounds): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty token encountered`);
  }

  // Step expressions: "*/N", "X/N", "X-Y/N"
  if (trimmed.includes("/")) {
    const slashCount = (trimmed.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new SyntaxError(`Too many "/" characters in "${trimmed}"`);
    }
    const slashIdx = trimmed.indexOf("/");
    const basePart = trimmed.slice(0, slashIdx);
    const stepPart = trimmed.slice(slashIdx + 1);

    if (basePart === "" || stepPart === "") {
      throw new SyntaxError(`Malformed step expression "${trimmed}"`);
    }

    const step = parseNonNegativeInteger(stepPart, trimmed);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1 in "${trimmed}"`);
    }

    let start: number;
    let end: number;

    if (basePart === "*") {
      start = bounds.min;
      end   = bounds.max;
    } else if (basePart.includes("-")) {
      const hyphenCount = (basePart.match(/-/g) ?? []).length;
      if (hyphenCount !== 1) {
        throw new SyntaxError(`Malformed range in step expression "${trimmed}"`);
      }
      const dashIdx = basePart.indexOf("-");
      start = parseNonNegativeInteger(basePart.slice(0, dashIdx), trimmed);
      end   = parseNonNegativeInteger(basePart.slice(dashIdx + 1), trimmed);
    } else {
      // "X/N" means: from X to max, stepping by N
      start = parseNonNegativeInteger(basePart, trimmed);
      end   = bounds.max;
    }

    assertWithinBounds(start, bounds, trimmed);
    assertWithinBounds(end,   bounds, trimmed);

    return expandRange(start, end, step);
  }

  // Range expressions: "X-Y"
  if (trimmed.includes("-")) {
    const hyphenCount = (trimmed.match(/-/g) ?? []).length;
    if (hyphenCount !== 1) {
      throw new SyntaxError(`Malformed range expression "${trimmed}"`);
    }
    const dashIdx = trimmed.indexOf("-");
    const start = parseNonNegativeInteger(trimmed.slice(0, dashIdx), trimmed);
    const end   = parseNonNegativeInteger(trimmed.slice(dashIdx + 1), trimmed);
    assertWithinBounds(start, bounds, trimmed);
    assertWithinBounds(end,   bounds, trimmed);
    return expandRange(start, end, 1);
  }

  // Wildcard: "*"
  if (trimmed === "*") {
    return expandRange(bounds.min, bounds.max, 1);
  }

  // Single numeric value
  const n = parseNonNegativeInteger(trimmed, trimmed);
  assertWithinBounds(n, bounds, trimmed);
  return [n];
}

function parseFieldExpression(expr: string, bounds: FieldBounds): number[] {
  const trimmed = expr.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Field expression must not be empty`);
  }

  const rawValues = trimmed
    .split(",")
    .flatMap((part) => parseAtom(part, bounds));

  // Deduplicate and sort ascending
  return [...new Set(rawValues)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron requires a string argument`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Cron expression must not be empty`);
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 space-separated fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name   = FIELD_NAMES[i];
    const bounds = FIELD_BOUNDS[name];

    let values = parseFieldExpression(parts[i], bounds);

    // Normalize dayOfWeek: 7 is an alias for 0 (Sunday)
    if (name === "dayOfWeek" && values.includes(7)) {
      values = [...new Set(values.map((v) => (v === 7 ? 0 : v)))].sort(
        (a, b) => a - b
      );
    }

    if (values.length === 0) {
      throw new RangeError(
        `Field "${name}" resolved to an empty value set from expression "${parts[i]}"`
      );
    }

    result[name] = values;
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, fieldName: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  if (expr.includes(",")) {
    const parts = expr.split(",").flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(parts)].sort((a, b) => a - b);
  }

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value in field "${fieldName}": ${expr}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in field "${fieldName}": ${expr}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range out of bounds in field "${fieldName}": ${expr} (valid: ${min}-${max})`);
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value in field "${fieldName}": ${expr}`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of range in field "${fieldName}" (valid: ${min}-${max})`);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields but got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr];

  return fieldNames.reduce((acc, name, i) => {
    acc[name] = parseField(exprs[i], name);
    return acc;
  }, {} as CronFields);
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const argsToCall = pendingArgs;
      pendingArgs = null;
      if (argsToCall !== null) {
        fn(...argsToCall);
      }
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
      const argsToCall = pendingArgs;
      pendingArgs = null;
      if (argsToCall !== null) {
        fn(...argsToCall);
      }
    }
  };

  return debounced;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

function parseStrictInt(raw: string, fieldName: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(
      `Field "${fieldName}": "${raw}" is not a valid non-negative integer`
    );
  }
  return parseInt(raw, 10);
}

function generateRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function assertInBounds(
  value: number,
  config: FieldConfig,
  context: string
): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `Field "${config.name}": ${context} value ${value} is out of valid range [${config.min}, ${config.max}]`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  if (segment === "*") {
    return generateRange(min, max);
  }

  const slashIndex = segment.indexOf("/");
  if (slashIndex !== -1) {
    // Step value: must be */N or range/N
    const stepStr = segment.slice(slashIndex + 1);
    const step = parseStrictInt(stepStr, name);

    if (step === 0) {
      throw new Error(`Field "${name}": step value must not be zero`);
    }

    const prefix = segment.slice(0, slashIndex);
    let rangeStart = min;
    let rangeEnd = max;

    if (prefix !== "*") {
      const dashIndex = prefix.indexOf("-");
      if (dashIndex === -1) {
        rangeStart = parseStrictInt(prefix, name);
        assertInBounds(rangeStart, config, "step base");
        rangeEnd = max;
      } else {
        const startStr = prefix.slice(0, dashIndex);
        const endStr = prefix.slice(dashIndex + 1);

        if (startStr.includes("-") || endStr.includes("-")) {
          throw new Error(
            `Field "${name}": malformed range in step expression "${segment}"`
          );
        }

        rangeStart = parseStrictInt(startStr, name);
        rangeEnd = parseStrictInt(endStr, name);
        assertInBounds(rangeStart, config, "range start");
        assertInBounds(rangeEnd, config, "range end");

        if (rangeStart > rangeEnd) {
          throw new Error(
            `Field "${name}": range start ${rangeStart} exceeds range end ${rangeEnd} in "${segment}"`
          );
        }
      }
    }

    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      result.push(i);
    }
    return result;
  }

  const dashIndex = segment.indexOf("-");
  if (dashIndex !== -1) {
    const startStr = segment.slice(0, dashIndex);
    const endStr = segment.slice(dashIndex + 1);

    if (startStr === "" || endStr === "") {
      throw new Error(
        `Field "${name}": malformed range "${segment}" — missing bound`
      );
    }

    if (endStr.includes("-")) {
      throw new Error(
        `Field "${name}": malformed range "${segment}" — multiple dashes`
      );
    }

    const start = parseStrictInt(startStr, name);
    const end = parseStrictInt(endStr, name);

    assertInBounds(start, config, "range start");
    assertInBounds(end, config, "range end");

    if (start > end) {
      throw new Error(
        `Field "${name}": range start ${start} exceeds range end ${end} in "${segment}"`
      );
    }

    return generateRange(start, end);
  }

  // Single value
  const value = parseStrictInt(segment, name);

  // Accept 7 as Sunday alias in dayOfWeek only
  if (name === "dayOfWeek" && value === 7) {
    return [0];
  }

  assertInBounds(value, config, "literal");
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (field.trim() === "") {
    throw new Error(`Field "${config.name}" must not be empty`);
  }

  if (!field.includes(",")) {
    return parseSegment(field.trim(), config);
  }

  const parts = field.split(",");

  if (parts.some((p) => p.trim() === "")) {
    throw new Error(
      `Field "${config.name}": list "${field}" contains an empty segment`
    );
  }

  const seen = new Set<number>();

  for (const part of parts) {
    const values = parseSegment(part.trim(), config);
    for (const v of values) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expected a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute: parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour: parseField(hourRaw, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw, FIELD_CONFIGS[2]),
    month: parseField(monthRaw, FIELD_CONFIGS[3]),
    dayOfWeek: parseField(dowRaw, FIELD_CONFIGS[4]),
  };
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;

    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head.next;
    while (current !== null && current !== this.tail) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) return;

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of expr.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) values.add(i);
      continue;
    }

    if (trimmed.startsWith("*/")) {
      const step = parseInt(trimmed.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${trimmed}"`);
      }
      for (let i = min; i <= max; i += step) values.add(i);
      continue;
    }

    if (trimmed.includes("/")) {
      const [rangePart, stepPart] = trimmed.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${trimmed}"`);
      }
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        const start = parseInt(startStr, 10);
        const end = parseInt(endStr, 10);
        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range in step expression: "${trimmed}"`);
        }
        if (start < min || end > max || start > end) {
          throw new Error(`Range out of bounds [${min}-${max}]: "${trimmed}"`);
        }
        for (let i = start; i <= end; i += step) values.add(i);
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start) || start < min || start > max) {
          throw new Error(`Value out of bounds [${min}-${max}]: "${trimmed}"`);
        }
        for (let i = start; i <= max; i += step) values.add(i);
      }
      continue;
    }

    if (trimmed.includes("-")) {
      const [startStr, endStr] = trimmed.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: "${trimmed}"`);
      }
      if (start < min || end > max || start > end) {
        throw new Error(`Range out of bounds [${min}-${max}]: "${trimmed}"`);
      }
      for (let i = start; i <= end; i++) values.add(i);
      continue;
    }

    const num = parseInt(trimmed, 10);
    if (isNaN(num)) {
      throw new Error(`Invalid value: "${trimmed}"`);
    }
    if (num < min || num > max) {
      throw new Error(`Value ${num} out of bounds [${min}-${max}]`);
    }
    values.add(num);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const [minuteRange, hourRange, domRange, monthRange, dowRange] =
    fieldNames.map((f) => FIELD_RANGES[f]);

  return {
    minute: parseField(minuteExpr, ...minuteRange),
    hour: parseField(hourExpr, ...hourRange),
    dayOfMonth: parseField(domExpr, ...domRange),
    month: parseField(monthExpr, ...monthRange),
    dayOfWeek: parseField(dowExpr, ...dowRange),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | unknown[] | unknown;
};

type FlattenedObject = Record<string, Primitive | unknown[]>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    maxDepth?: number;
    preserveArrays?: boolean;
  } = {}
): FlattenedObject {
  const {
    delimiter = ".",
    maxDepth = Infinity,
    preserveArrays = true,
  } = options;

  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      if (prefix !== "") {
        result[prefix] = current as Primitive;
      }
      return;
    }

    if (preserveArrays && Array.isArray(current)) {
      if (prefix !== "") {
        result[prefix] = current;
      }
      return;
    }

    if (isPlainObject(current)) {
      if (seen.has(current as object)) {
        throw new TypeError(
          `Circular reference detected at key: "${prefix}"`
        );
      }

      seen.add(current as object);

      const keys = Object.keys(current as NestedObject);

      if (keys.length === 0) {
        if (prefix !== "") {
          result[prefix] = current as Record<string, never>;
        }
        seen.delete(current as object);
        return;
      }

      for (const key of keys) {
        if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

        const sanitizedKey = key.includes(delimiter)
          ? `[${key}]`
          : key;

        const newKey = prefix === "" ? sanitizedKey : `${prefix}${delimiter}${sanitizedKey}`;
        const value = (current as NestedObject)[key];

        recurse(value, newKey, depth + 1);
      }

      seen.delete(current as object);
    } else {
      if (prefix !== "") {
        result[prefix] = current as Primitive;
      }
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  // Undefined source leaves target intact; null source explicitly overwrites
  if (source === undefined) return target;
  if (source === null) return null;

  // Both arrays → concatenate (never mutate originals)
  if (Array.isArray(source) && Array.isArray(target)) {
    return [...target, ...source];
  }

  // Both plain objects → recursive merge
  if (isPlainObject(source) && isPlainObject(target)) {
    // Guard against circular references in source graph
    const existing = seen.get(source as object);
    if (existing !== undefined) return existing;

    const result: PlainObject = { ...target };
    seen.set(source as object, result);

    for (const key of Object.keys(source)) {
      // Prototype-pollution guard
      if (UNSAFE_KEYS.has(key)) continue;

      result[key] = mergeInternal(target[key], source[key], seen);
    }

    return result;
  }

  // All other cases: source overwrites (includes type mismatches, primitives,
  // Date, RegExp, Map, Set, etc. — no silent structural corruption)
  return source;
}

export default function deepMerge(
  target: PlainObject,
  source: PlainObject
): PlainObject {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: expected a plain object for 'target', received ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: expected a plain object for 'source', received ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInternal(target, source, new WeakMap()) as PlainObject;
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  function debounced(...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const args = pendingArgs!;
      pendingArgs = null;
      fn(...args);
    }, delay);
  }

  debounced.cancel = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
      const args = pendingArgs!;
      pendingArgs = null;
      fn(...args);
    }
  };

  return debounced;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(`Capacity must be a non-negative integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) {
      return undefined;
    }
    // Promote to most-recently-used by re-inserting at tail
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.capacity === 0) {
      // Zero-capacity cache: accept no entries
      return;
    }

    if (this.cache.has(key)) {
      // Remove first so re-insertion places it at tail (most-recently-used)
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Evict least-recently-used: Map iteration is insertion-ordered,
      // so the first key is always the LRU entry
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  get size(): number {
    return this.cache.size;
  }

  has(key: string): boolean {
    return this.cache.has(key);
  }

  delete(key: string): boolean {
    return this.cache.delete(key);
  }

  clear(): void {
    this.cache.clear();
  }
}

export default LRUCache;

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMergeInner(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, object>
): unknown {
  // Source is absent — nothing to merge
  if (source === undefined) return target;

  // Source is null — explicit null overwrites
  if (source === null) return null;

  // Both are arrays — concatenate (deep-clone source entries to avoid aliasing)
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  // Both are plain objects — recurse
  if (isPlainObject(target) && isPlainObject(source)) {
    // Guard against circular references in source
    if (seen.has(source as object)) {
      return seen.get(source as object) as unknown;
    }

    // Shallow-copy target so we never mutate the original
    const result: PlainObject = Object.assign(Object.create(null), target);
    seen.set(source as object, result);

    for (const key of Object.keys(source)) {
      // Prototype-pollution guard
      if (UNSAFE_KEYS.has(key)) continue;

      result[key] = deepMergeInner(target[key], source[key], seen);
    }

    return result;
  }

  // All other cases: source overwrites target.
  // If source is itself an object (non-plain, e.g. Date/Map), return it directly
  // without cloning — caller owns their references.
  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  return deepMergeInner(target, source, new WeakMap()) as T & S;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function expandRange(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function parseField(field: string, fieldMin: number, fieldMax: number): number[] {
  const values = new Set<number>();

  for (const part of field.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      expandRange(fieldMin, fieldMax).forEach((v) => values.add(v));
      continue;
    }

    if (trimmed.startsWith("*/")) {
      const step = parseInt(trimmed.slice(2), 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${trimmed}"`);
      for (let i = fieldMin; i <= fieldMax; i += step) values.add(i);
      continue;
    }

    if (trimmed.includes("/")) {
      const [rangePart, stepPart] = trimmed.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${trimmed}"`);

      let rangeMin = fieldMin;
      let rangeMax = fieldMax;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [lo, hi] = rangePart.split("-").map((n) => parseInt(n, 10));
          if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: "${rangePart}"`);
          rangeMin = lo;
          rangeMax = hi;
        } else {
          rangeMin = parseInt(rangePart, 10);
          if (isNaN(rangeMin)) throw new Error(`Invalid value: "${rangePart}"`);
          rangeMax = rangeMin;
        }
      }

      validateBounds(rangeMin, rangeMax, fieldMin, fieldMax, trimmed);
      for (let i = rangeMin; i <= rangeMax; i += step) values.add(i);
      continue;
    }

    if (trimmed.includes("-")) {
      const [lo, hi] = trimmed.split("-").map((n) => parseInt(n, 10));
      if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: "${trimmed}"`);
      validateBounds(lo, hi, fieldMin, fieldMax, trimmed);
      if (lo > hi) throw new Error(`Range start exceeds end: "${trimmed}"`);
      expandRange(lo, hi).forEach((v) => values.add(v));
      continue;
    }

    const num = parseInt(trimmed, 10);
    if (isNaN(num)) throw new Error(`Invalid cron value: "${trimmed}"`);
    validateBounds(num, num, fieldMin, fieldMax, trimmed);
    values.add(num);
  }

  return Array.from(values).sort((a, b) => a - b);
}

function validateBounds(
  lo: number,
  hi: number,
  fieldMin: number,
  fieldMax: number,
  raw: string
): void {
  if (lo < fieldMin || hi > fieldMax) {
    throw new Error(
      `Value "${raw}" out of range [${fieldMin}, ${fieldMax}]`
    );
  }
}

function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce((acc, name, index) => {
    const [min, max] = FIELD_RANGES[name];
    acc[name] = parseField(parts[index], min, max);
    return acc;
  }, {} as CronFields);
}

export default parseCron;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6  },
] as const;

function parseInteger(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new Error(`Empty numeric value in field "${fieldName}"`);
  }
  const num = Number(trimmed);
  if (!Number.isFinite(num) || !Number.isInteger(num)) {
    throw new Error(`Non-integer value "${raw}" in field "${fieldName}"`);
  }
  return num;
}

function assertInRange(value: number, min: number, max: number, fieldName: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${min}–${max}] for field "${fieldName}"`
    );
  }
}

function generateSequence(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  // Step expression: */n  |  start/n  |  start-end/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const basePart = segment.slice(0, slashIdx);
    const stepPart = segment.slice(slashIdx + 1);

    if (basePart === "" || stepPart === "") {
      throw new Error(`Malformed step expression "${segment}" in field "${name}"`);
    }

    const step = parseInteger(stepPart, name);
    if (step <= 0) {
      throw new RangeError(`Step must be positive in field "${name}", got ${step}`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (basePart === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (basePart.includes("-")) {
      const dashParts = basePart.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Malformed range "${basePart}" in field "${name}"`);
      }
      rangeStart = parseInteger(dashParts[0], name);
      rangeEnd   = parseInteger(dashParts[1], name);
      assertInRange(rangeStart, min, max, name);
      assertInRange(rangeEnd,   min, max, name);
      if (rangeStart > rangeEnd) {
        throw new RangeError(
          `Range start (${rangeStart}) exceeds end (${rangeEnd}) in field "${name}"`
        );
      }
    } else {
      rangeStart = parseInteger(basePart, name);
      assertInRange(rangeStart, min, max, name);
      rangeEnd = max;
    }

    return generateSequence(rangeStart, rangeEnd, step);
  }

  // Wildcard: *
  if (segment === "*") {
    return generateSequence(min, max, 1);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new Error(`Malformed range "${segment}" in field "${name}"`);
    }
    const start = parseInteger(parts[0], name);
    const end   = parseInteger(parts[1], name);
    assertInRange(start, min, max, name);
    assertInRange(end,   min, max, name);
    if (start > end) {
      throw new RangeError(
        `Range start (${start}) exceeds end (${end}) in field "${name}"`
      );
    }
    return generateSequence(start, end, 1);
  }

  // Single value
  const value = parseInteger(segment, name);
  assertInRange(value, min, max, name);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const segments = raw.split(",");

  if (segments.length === 0) {
    throw new Error(`Empty field for "${config.name}"`);
  }

  const collected = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(
        `Empty segment (consecutive or trailing comma) in field "${config.name}"`
      );
    }
    for (const v of parseSegment(trimmed, config)) {
      collected.add(v);
    }
  }

  return Array.from(collected).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must contain exactly 5 whitespace-separated fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    result[config.name] = parseField(fields[i], config);
  }

  return result;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    if (!this.cache.has(key)) {
      return undefined;
    }

    // Refresh recency: delete and re-insert to move to end of Map iteration order
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete() to remove an entry");
    }

    if (this.cache.has(key)) {
      // Update existing: delete first to refresh insertion order
      this.cache.delete(key);
      this.cache.set(key, value);
      return;
    }

    if (this.cache.size >= this.capacity) {
      // Evict the least-recently-used entry (first key in Map)
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    return this.cache.delete(key);
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    return this.cache.has(key);
  }

  clear(): void {
    this.cache.clear();
  }

  get size(): number {
    return this.cache.size;
  }

  get maxCapacity(): number {
    return this.capacity;
  }
}

export default LRUCache;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (key === undefined || key === null) return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.promoteToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (key === undefined || key === null) {
      throw new TypeError(`LRUCache key must not be null or undefined`);
    }
    if (value === undefined) {
      throw new TypeError(`LRUCache value must not be undefined — use delete if removal is intended`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.promoteToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  private promoteToHead(node: Node<T>): void {
    if (node === this.head) return; // already most recent, nothing to do
    this.detach(node);
    this.insertAtHead(node);
  }

  private insertAtHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node; // first node ever inserted
    }
  }

  private detach(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      // node is head
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      // node is tail
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private evictTail(): void {
    if (this.tail === null) return; // nothing to evict — should never happen in normal use

    const lru = this.tail;
    this.detach(lru);

    const deleted = this.map.delete(lru.key);
    if (!deleted) {
      // Invariant violation: map and list are out of sync — a serious bug
      throw new Error(`LRUCache internal invariant violated: tail key "${lru.key}" missing from map`);
    }
  }
}

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInner(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  if (Array.isArray(source)) {
    if (seen.has(source)) return seen.get(source);
    const result = Array.isArray(target)
      ? [...target, ...source]
      : [...source];
    seen.set(source, result);
    return result;
  }

  if (!isPlainObject(source)) {
    return source;
  }

  if (seen.has(source)) return seen.get(source);

  const base: PlainObject = isPlainObject(target) ? { ...target } : {};
  seen.set(source, base);

  for (const key of Object.keys(source)) {
    if (UNSAFE_KEYS.has(key)) continue;
    base[key] = mergeInner(base[key], source[key], seen);
  }

  return base;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: target must be a plain object, got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: source must be a plain object, got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInner(target, source, new WeakMap()) as T & S;
}

type DebounceFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebounceFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const invoke = () => {
    if (pendingArgs !== null) {
      fn(...pendingArgs);
      pendingArgs = null;
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    invoke();
  };

  return debounced;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = Record<string, Primitive | unknown[]>;

function flattenObject(
  obj: unknown,
  prefix = "",
  result: FlatObject = {},
  visited = new WeakSet<object>()
): FlatObject {
  if (obj === null || obj === undefined) {
    if (prefix) {
      result[prefix] = obj as Primitive;
    }
    return result;
  }

  if (typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) {
      result[prefix] = obj as Primitive | unknown[];
    }
    return result;
  }

  const record = obj as Record<string, unknown>;

  if (visited.has(record)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix}"`
    );
  }

  visited.add(record);

  const keys = Object.keys(record);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = {} as unknown as Primitive;
    }
    visited.delete(record);
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(record, key)) {
      continue;
    }

    const sanitizedKey = String(key);
    const newPrefix = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = record[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, newPrefix, result, visited);
    } else {
      result[newPrefix] = value as Primitive | unknown[];
    }
  }

  visited.delete(record);
  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>; // sentinel: most recently used end
  private readonly tail: Node<T>; // sentinel: least recently used end

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes to avoid null checks on boundary conditions
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete to remove an entry");
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // Returns keys from most-recently-used to least-recently-used
  keys(): string[] {
    const result: string[] = [];
    let current = this.head.next;
    while (current !== null && current !== this.tail) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) {
      return; // empty cache, nothing to evict
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

export default function deepMerge<
  T extends Record<string, unknown>,
  S extends Record<string, unknown>,
>(target: T, source: S): T & S {
  if (!isPlainObject(target) && !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: Record<string, unknown> = isPlainObject(target)
    ? { ...target }
    : {};

  if (!isPlainObject(source)) {
    return result as T & S;
  }

  for (const key of Object.keys(source)) {
    if (UNSAFE_KEYS.has(key)) continue;

    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(
        targetVal as Record<string, unknown>,
        sourceVal as Record<string, unknown>,
      );
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return (
    typeof value === "object" &&
    value !== null &&
    !Array.isArray(value) &&
    !(value instanceof Date) &&
    !(value instanceof RegExp) &&
    !(value instanceof Map) &&
    !(value instanceof Set) &&
    !(value instanceof Error) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  ancestors = new Set<object>()
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    throw new TypeError(`flattenObject requires a plain object, got: ${typeof obj}`);
  }

  if (ancestors.has(obj)) {
    throw new TypeError("flattenObject detected a circular reference");
  }

  ancestors.add(obj);
  const result: FlatObject = {};

  for (const key of Object.keys(obj)) {
    if (key === "") {
      // Empty string keys would produce ambiguous dot-notation paths — skip safely
      continue;
    }

    const value = obj[key];
    const flatKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      const nested = flattenObject(value, flatKey, ancestors);
      // An empty nested object contributes no leaf keys — omit it entirely
      for (const nestedKey of Object.keys(nested)) {
        result[nestedKey] = nested[nestedKey];
      }
    } else {
      result[flatKey] = value;
    }
  }

  // Backtrack: allow the same object instance to appear in sibling subtrees
  // without being misidentified as a cycle
  ancestors.delete(obj);

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

interface FieldConfig {
  readonly name: CronField;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function generateRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, fieldName: string): void {
  if (!Number.isFinite(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}-${max}] for field '${fieldName}'`
    );
  }
}

function parseStrictInteger(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new TypeError(`Empty numeric value encountered in field '${fieldName}'`);
  }
  if (!/^\d+$/.test(trimmed)) {
    throw new TypeError(
      `Non-numeric token '${trimmed}' is not allowed in field '${fieldName}'`
    );
  }
  return parseInt(trimmed, 10);
}

function parseField(token: string, config: FieldConfig): number[] {
  const { name, min, max } = config;
  const field = token.trim();

  if (field.length === 0) {
    throw new Error(`Field '${name}' is empty — all 5 cron fields are required`);
  }

  // Plain wildcard
  if (field === "*") {
    return generateRange(min, max);
  }

  // Step expression: base/step  (base may be *, a number, or a range N-M)
  if (field.includes("/")) {
    const slashIdx = field.lastIndexOf("/");
    const base = field.slice(0, slashIdx);
    const stepPart = field.slice(slashIdx + 1);

    if (base.length === 0) {
      throw new Error(`Missing base before '/' in field '${name}': '${field}'`);
    }
    if (stepPart.length === 0) {
      throw new Error(`Missing step value after '/' in field '${name}': '${field}'`);
    }

    const step = parseStrictInteger(stepPart, name);
    if (step === 0) {
      throw new RangeError(`Step value cannot be zero in field '${name}'`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (base === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (base.includes("-")) {
      const dashIdx = base.indexOf("-");
      const startStr = base.slice(0, dashIdx);
      const endStr = base.slice(dashIdx + 1);
      if (startStr.length === 0 || endStr.length === 0) {
        throw new Error(`Malformed range '${base}' in field '${name}'`);
      }
      rangeStart = parseStrictInteger(startStr, name);
      rangeEnd = parseStrictInteger(endStr, name);
    } else {
      rangeStart = parseStrictInteger(base, name);
      rangeEnd = max;
    }

    assertInRange(rangeStart, min, max, name);
    assertInRange(rangeEnd, min, max, name);

    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start ${rangeStart} exceeds end ${rangeEnd} in field '${name}'`
      );
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
    }
    return values;
  }

  // Comma-separated list (items must be plain integers per simplified spec)
  if (field.includes(",")) {
    const parts = field.split(",");
    const seen = new Set<number>();
    const values: number[] = [];

    for (const part of parts) {
      if (part.trim().length === 0) {
        throw new Error(
          `Empty item in comma-separated list for field '${name}': '${field}'`
        );
      }
      const n = parseStrictInteger(part, name);
      assertInRange(n, min, max, name);
      if (!seen.has(n)) {
        seen.add(n);
        values.push(n);
      }
    }

    return values.sort((a, b) => a - b);
  }

  // Range: N-M
  if (field.includes("-")) {
    const dashIdx = field.indexOf("-");
    const startStr = field.slice(0, dashIdx);
    const endStr = field.slice(dashIdx + 1);

    if (startStr.length === 0 || endStr.length === 0) {
      throw new Error(`Malformed range expression '${field}' in field '${name}'`);
    }

    const start = parseStrictInteger(startStr, name);
    const end = parseStrictInteger(endStr, name);

    assertInRange(start, min, max, name);
    assertInRange(end, min, max, name);

    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field '${name}'`
      );
    }

    return generateRange(start, end);
  }

  // Single numeric value
  const n = parseStrictInteger(field, name);
  assertInRange(n, min, max, name);
  return [n];
}

export default function parseCron(expression: string): CronResult {
  if (expression === null || expression === undefined) {
    throw new TypeError("Cron expression must be a non-null string");
  }

  if (typeof expression !== "string") {
    throw new TypeError(
      `Expected a string cron expression, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed.length === 0) {
    throw new Error("Cron expression cannot be an empty string");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 whitespace-separated fields, got ${fields.length}: '${expression}'`
    );
  }

  return {
    minute: parseField(fields[0], FIELD_CONFIGS[0]),
    hour: parseField(fields[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(fields[2], FIELD_CONFIGS[2]),
    month: parseField(fields[3], FIELD_CONFIGS[3]),
    dayOfWeek: parseField(fields[4], FIELD_CONFIGS[4]),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of field.split(",")) {
    if (part === "*") {
      for (let i = min; i <= max; i++) values.add(i);
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${part}`);
      }
      for (let i = min; i <= max; i += step) values.add(i);
    } else if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value in: ${part}`);
      }
      if (rangePart === "*") {
        for (let i = min; i <= max; i += step) values.add(i);
      } else if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        const start = parseInt(startStr, 10);
        const end = parseInt(endStr, 10);
        if (isNaN(start) || isNaN(end) || start > end) {
          throw new Error(`Invalid range in: ${part}`);
        }
        validateRange(start, end, min, max, part);
        for (let i = start; i <= end; i += step) values.add(i);
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) throw new Error(`Invalid value in: ${part}`);
        validateRange(start, start, min, max, part);
        for (let i = start; i <= max; i += step) values.add(i);
      }
    } else if (part.includes("-")) {
      const [startStr, endStr] = part.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end) || start > end) {
        throw new Error(`Invalid range: ${part}`);
      }
      validateRange(start, end, min, max, part);
      for (let i = start; i <= end; i++) values.add(i);
    } else {
      const num = parseInt(part, 10);
      if (isNaN(num)) throw new Error(`Invalid value: ${part}`);
      validateRange(num, num, min, max, part);
      values.add(num);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

function validateRange(
  start: number,
  end: number,
  min: number,
  max: number,
  context: string
): void {
  if (start < min || end > max) {
    throw new Error(
      `Value out of range [${min}-${max}] in: ${context}`
    );
  }
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max);
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
];

function parseNonNegativeInteger(str: string): number | null {
  if (!/^\d+$/.test(str)) return null;
  const n = parseInt(str, 10);
  return isNaN(n) ? null : n;
}

function assertInRange(value: number, min: number, max: number, fieldName: string, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `${context} ${value} is out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  if (segment === "") {
    throw new SyntaxError(`Empty segment in field "${fieldName}"`);
  }

  // Step: */N, start-end/N, or start/N
  if (segment.includes("/")) {
    const slashIndex = segment.lastIndexOf("/");
    const rangePart = segment.slice(0, slashIndex);
    const stepStr = segment.slice(slashIndex + 1);

    if (rangePart === "" || stepStr === "") {
      throw new SyntaxError(`Malformed step expression "${segment}" in field "${fieldName}"`);
    }

    const step = parseNonNegativeInteger(stepStr);
    if (step === null) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }
    if (step === 0) {
      throw new RangeError(`Step value must be a positive integer in field "${fieldName}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      [rangeMin, rangeMax] = parseRangeBounds(rangePart, min, max, fieldName);
    } else {
      const start = parseNonNegativeInteger(rangePart);
      if (start === null) {
        throw new SyntaxError(`Invalid start value "${rangePart}" in step expression for field "${fieldName}"`);
      }
      assertInRange(start, min, max, fieldName, "Step start value");
      rangeMin = start;
      rangeMax = max;
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: N-M
  if (segment.includes("-")) {
    const [rangeMin, rangeMax] = parseRangeBounds(segment, min, max, fieldName);
    return Array.from({ length: rangeMax - rangeMin + 1 }, (_, i) => rangeMin + i);
  }

  // Single integer
  const value = parseNonNegativeInteger(segment);
  if (value === null) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName, "Value");
  return [value];
}

function parseRangeBounds(rangePart: string, min: number, max: number, fieldName: string): [number, number] {
  const dashIndex = rangePart.indexOf("-");
  if (dashIndex <= 0 || dashIndex === rangePart.length - 1) {
    throw new SyntaxError(`Malformed range "${rangePart}" in field "${fieldName}"`);
  }

  const startStr = rangePart.slice(0, dashIndex);
  const endStr = rangePart.slice(dashIndex + 1);

  const start = parseNonNegativeInteger(startStr);
  const end = parseNonNegativeInteger(endStr);

  if (start === null) {
    throw new SyntaxError(`Invalid range start "${startStr}" in field "${fieldName}"`);
  }
  if (end === null) {
    throw new SyntaxError(`Invalid range end "${endStr}" in field "${fieldName}"`);
  }

  assertInRange(start, min, max, fieldName, "Range start");
  assertInRange(end, min, max, fieldName, "Range end");

  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must not be greater than range end (${end}) in field "${fieldName}"`
    );
  }

  return [start, end];
}

function parseFieldExpression(expression: string, min: number, max: number, fieldName: string): number[] {
  if (expression === "") {
    throw new SyntaxError(`Field "${fieldName}" cannot be empty`);
  }

  const segments = expression.split(",");
  if (segments.some((s) => s === "")) {
    throw new SyntaxError(`Field "${fieldName}" contains an empty comma-separated segment`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    for (const value of parseSegment(segment, min, max, fieldName)) {
      valueSet.add(value);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseFieldExpression(fields[i], min, max, name);
  }

  return result;
}

export default parseCron;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  6 },
];

function assertInteger(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `Invalid numeric value "${trimmed}" in field "${fieldName}" — only non-negative integers are allowed`
    );
  }
  return parseInt(trimmed, 10);
}

function assertInRange(value: number, min: number, max: number, fieldName: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} is out of the valid range [${min}–${max}] for field "${fieldName}"`
    );
  }
}

function buildRange(start: number, end: number, step: number, fieldName: string): number[] {
  if (step <= 0) {
    throw new Error(`Step must be >= 1, got ${step} in field "${fieldName}"`);
  }
  if (start > end) {
    throw new Error(
      `Range start ${start} exceeds end ${end} in field "${fieldName}"`
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(expr: string, min: number, max: number, fieldName: string): number[] {
  const trimmed = expr.trim();

  if (!trimmed) {
    throw new Error(`Empty segment encountered in field "${fieldName}"`);
  }

  // Step value: */N  |  start/N  |  start-end/N
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.indexOf("/");
    const baseExpr = trimmed.slice(0, slashIndex);
    const stepRaw  = trimmed.slice(slashIndex + 1);

    if (!stepRaw || !/^\d+$/.test(stepRaw.trim())) {
      throw new Error(
        `Invalid or missing step value "${stepRaw}" in field "${fieldName}"`
      );
    }
    const step = parseInt(stepRaw.trim(), 10);
    if (step < 1) {
      throw new Error(`Step value must be >= 1 in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (baseExpr === "*") {
      start = min;
      end   = max;
    } else if (baseExpr.includes("-")) {
      const dashIndex = baseExpr.indexOf("-");
      start = assertInteger(baseExpr.slice(0, dashIndex), fieldName);
      end   = assertInteger(baseExpr.slice(dashIndex + 1), fieldName);
      assertInRange(start, min, max, fieldName);
      assertInRange(end,   min, max, fieldName);
      if (start > end) {
        throw new Error(
          `Range start ${start} > end ${end} in field "${fieldName}"`
        );
      }
    } else {
      start = assertInteger(baseExpr, fieldName);
      assertInRange(start, min, max, fieldName);
      end = max;
    }

    return buildRange(start, end, step, fieldName);
  }

  // Range: start-end  (no slash — dash only, no comma at this level)
  if (trimmed.includes("-")) {
    const dashIndex = trimmed.indexOf("-");
    const start = assertInteger(trimmed.slice(0, dashIndex), fieldName);
    const end   = assertInteger(trimmed.slice(dashIndex + 1), fieldName);
    assertInRange(start, min, max, fieldName);
    assertInRange(end,   min, max, fieldName);
    if (start > end) {
      throw new Error(
        `Range start ${start} > end ${end} in field "${fieldName}"`
      );
    }
    return buildRange(start, end, 1, fieldName);
  }

  // Wildcard
  if (trimmed === "*") {
    return buildRange(min, max, 1, fieldName);
  }

  // Single numeric value
  const value = assertInteger(trimmed, fieldName);
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expr: string, min: number, max: number, fieldName: string): number[] {
  const trimmed = expr.trim();

  if (!trimmed) {
    throw new Error(`Field "${fieldName}" expression is empty`);
  }

  // Comma-separated list — split first, parse each segment independently
  if (trimmed.includes(",")) {
    const parts = trimmed.split(",");

    // Guard against trailing/leading/doubled commas
    if (parts.some((p) => p.trim() === "")) {
      throw new Error(
        `Empty element in comma-separated list for field "${fieldName}" — check for stray commas`
      );
    }

    const allValues = parts.flatMap((part) =>
      parseSegment(part, min, max, fieldName)
    );

    // Deduplicate and sort ascending — duplicates can arise from overlapping ranges
    return [...new Set(allValues)].sort((a, b) => a - b);
  }

  return parseSegment(trimmed, min, max, fieldName);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (!trimmed) {
    throw new Error("Cron expression must not be empty");
  }

  // Split on any run of whitespace — guards against tabs, multiple spaces, etc.
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 space-separated fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, FIELD_CONFIGS[0].min, FIELD_CONFIGS[0].max, FIELD_CONFIGS[0].name),
    hour:       parseField(hourExpr,   FIELD_CONFIGS[1].min, FIELD_CONFIGS[1].max, FIELD_CONFIGS[1].name),
    dayOfMonth: parseField(domExpr,    FIELD_CONFIGS[2].min, FIELD_CONFIGS[2].max, FIELD_CONFIGS[2].name),
    month:      parseField(monthExpr,  FIELD_CONFIGS[3].min, FIELD_CONFIGS[3].max, FIELD_CONFIGS[3].name),
    dayOfWeek:  parseField(dowExpr,    FIELD_CONFIGS[4].min, FIELD_CONFIGS[4].max, FIELD_CONFIGS[4].name),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`target must be a plain object, got: ${typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`source must be a plain object, got: ${typeof source}`);
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal === undefined) {
      // Don't overwrite existing target value with undefined
      // Only set if target also has no value for this key
      if (!(key in result)) {
        result[key] = sourceVal;
      }
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

const DANGEROUS_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInner(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  // Both plain objects → recursive merge
  if (isPlainObject(target) && isPlainObject(source)) {
    // Guard against circular references in source: register before recursing
    if (seen.has(source)) {
      return seen.get(source);
    }

    const result: PlainObject = {};
    seen.set(source, result);

    // Seed result with all target keys (skip dangerous keys)
    for (const key of Object.keys(target)) {
      if (DANGEROUS_KEYS.has(key)) continue;
      result[key] = target[key];
    }

    // Merge source keys over result
    for (const key of Object.keys(source)) {
      if (DANGEROUS_KEYS.has(key)) continue;
      // result[key] may already hold the target value — pass it as the new target
      result[key] = mergeInner(result[key], source[key], seen);
    }

    return result;
  }

  // Both arrays → concatenate (preserves order: target first, source second)
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  // Primitive, mismatched types, class instances, Dates, RegExps, etc.
  // Source always wins; if source is undefined, target is preserved
  return source === undefined ? target : source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: first argument must be a plain object, got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: second argument must be a plain object, got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInner(target, source, new WeakMap()) as T & S;
}

class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = Math.floor(capacity);
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value as string;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeValues(targetVal: unknown, sourceVal: unknown): unknown {
  if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
    return [...targetVal, ...sourceVal];
  }
  if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
    return mergeObjects(targetVal, sourceVal);
  }
  return sourceVal;
}

function mergeObjects(target: PlainObject, source: PlainObject): PlainObject {
  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    if (UNSAFE_KEYS.has(key)) {
      continue;
    }
    result[key] = Object.prototype.hasOwnProperty.call(result, key)
      ? mergeValues(result[key], source[key])
      : source[key];
  }

  return result;
}

export default function deepMerge(
  target: PlainObject,
  source: PlainObject
): PlainObject {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: target must be a plain object, got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: source must be a plain object, got ${
        source === null ? "null" : typeof source
      }`
    );
  }
  return mergeObjects(target, source);
}

class LRUCache<T> {
  private capacity: number;
