      pendingArgs = undefined;
      if (argsToCall !== undefined) {
        fn(...argsToCall);
      }
    }
  };

  return debounced;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseField(expr: string, field: keyof CronFields): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list — recurse on each part, flatten, deduplicate, sort
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard with optional step: * or */n
  if (expr.startsWith("*")) {
    const slashIdx = expr.indexOf("/");
    const step = slashIdx !== -1 ? parseInt(expr.slice(slashIdx + 1), 10) : 1;

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value in "${expr}" for field "${field}"`);
    }

    const result: number[] = [];
    for (let v = min; v <= max; v += step) {
      result.push(v);
    }
    return result;
  }

  // Range with optional step: a-b or a-b/n
  if (expr.includes("-")) {
    const [rangePart, stepPart] = expr.split("/");
    const [startStr, endStr]    = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    const step  = stepPart !== undefined ? parseInt(stepPart, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step)) {
      throw new SyntaxError(`Invalid range expression "${expr}" for field "${field}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in field "${field}"`);
    }
    if (step < 1) {
      throw new SyntaxError(`Step must be >= 1 in "${expr}" for field "${field}"`);
    }

    assertInRange(start, min, max, field);
    assertInRange(end,   min, max, field);

    const result: number[] = [];
    for (let v = start; v <= end; v += step) {
      result.push(v);
    }
    return result;
  }

  // Plain number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid token "${expr}" in field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const field = FIELD_NAMES[i];
    result[field] = parseField(parts[i], field);
  }

  // Normalise dayOfWeek: both 0 and 7 represent Sunday; keep 0 canonical
  result.dayOfWeek = [...new Set(result.dayOfWeek.map((d) => (d === 7 ? 0 : d)))].sort(
    (a, b) => a - b
  );

  return result;
}

type AnyFunction = (...args: unknown[]) => unknown;

interface DebouncedFunction<T extends AnyFunction> {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): ReturnType<T> | undefined;
}

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError("First argument must be a function");
  }
  if (typeof delay !== "number" || !isFinite(delay) || delay < 0) {
    throw new RangeError("Delay must be a non-negative finite number");
  }

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let pendingThis: unknown;

  function debounced(this: unknown, ...args: Parameters<T>): void {
    pendingArgs = args;
    pendingThis = this;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const argsToCall = pendingArgs!;
      const thisToCall = pendingThis;
      pendingArgs = undefined;
      pendingThis = undefined;
      fn.apply(thisToCall, argsToCall);
    }, delay);
  }

  debounced.cancel = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
    pendingThis = undefined;
  };

  debounced.flush = function (): ReturnType<T> | undefined {
    if (timerId === undefined || pendingArgs === undefined) {
      return undefined;
    }

    clearTimeout(timerId);
    timerId = undefined;

    const argsToCall = pendingArgs;
    const thisToCall = pendingThis;
    pendingArgs = undefined;
    pendingThis = undefined;

    return fn.apply(thisToCall, argsToCall) as ReturnType<T>;
  };

  return debounced as DebouncedFunction<T>;
}

