type Scalar = string | number | boolean | bigint | symbol | null | undefined;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInto(
  input: Record<string, unknown> | unknown[],
  result: Record<string, Scalar>,
  prefix: string,
  ancestors: WeakSet<object>,
): void {
  if (ancestors.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at path "${prefix || "(root)"}"`,
    );
  }

  ancestors.add(input as object);

  const entries: [string, unknown][] = Array.isArray(input)
    ? input.map((v, i) => [String(i), v])
    : Object.entries(input);

  for (const [key, value] of entries) {
    if (key === "") {
      // Empty-string keys would silently corrupt paths — surface them clearly.
      throw new TypeError(
        `Empty string key found under path "${prefix || "(root)"}"`,
      );
    }

    const path = prefix === "" ? key : `${prefix}.${key}`;

    if (Array.isArray(value)) {
      flattenInto(value, result, path, ancestors);
    } else if (isPlainObject(value)) {
      const keys = Object.keys(value);
      if (keys.length === 0) {
        // Preserve empty objects as leaf values so structural info isn't lost.
        result[path] = undefined;
      } else {
        flattenInto(value, result, path, ancestors);
      }
    } else {
      // Anything else (Date, RegExp, function, class instance, scalar) is a leaf.
      result[path] = value as Scalar;
    }
  }

  ancestors.delete(input as object);
}

export default function flattenObject(
  obj: Record<string, unknown>,
): Record<string, Scalar> {
  if (!isPlainObject(obj)) {
    throw new TypeError("flattenObject expects a plain object as input");
  }

  const result: Record<string, Scalar> = {};
  flattenInto(obj, result, "", new WeakSet());
  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (source === undefined) return target;
  if (target === undefined) return source;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

      const sourceVal = source[key];
      const targetVal = result[key];

      if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
        result[key] = deepMerge(targetVal, sourceVal);
      } else if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
        result[key] = [...targetVal, ...sourceVal];
      } else {
        result[key] = sourceVal;
      }
    }

    return result;
  }

  return source;
}

export default deepMerge;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) {
      return;
    }

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function mergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, object>
): unknown {
  // Undefined source value — preserve target as-is
  if (source === undefined) return target;

  // Both arrays — concatenate (shallow copy to avoid mutating inputs)
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  // Both plain objects — recurse
  if (isPlainObject(target) && isPlainObject(source)) {
    // Guard against circular references in source
    const cached = seen.get(source as object);
    if (cached !== undefined) return cached;

    const result: PlainObject = { ...target };
    seen.set(source as object, result);

    for (const key of Object.keys(source)) {
      // Prototype pollution guard
      if (UNSAFE_KEYS.has(key)) continue;

      result[key] = mergeInternal(
        Object.prototype.hasOwnProperty.call(target, key) ? target[key] : undefined,
        source[key],
        seen
      );
    }

    return result;
  }

  // All other cases — source overwrites target
  return source;
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: target must be a plain object, received ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: source must be a plain object, received ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInternal(target, source, new WeakMap()) as T & S;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, readonly [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function parseIntStrict(s: string, context: string): number {
  if (!/^\d+$/.test(s)) {
    throw new Error(`Invalid integer "${s}" in ${context}`);
  }
  const n = parseInt(s, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow "${s}" in ${context}`);
  }
  return n;
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of valid range [${min}, ${max}] in "${context}"`
    );
  }
}

function fillRange(start: number, end: number): number[] {
  if (start > end) {
    throw new Error(`Start (${start}) must not exceed end (${end})`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function parseRangeToken(
  token: string,
  min: number,
  max: number
): [number, number] {
  // Deliberately split only on the first dash to catch malformed tokens like
  // "1-5-3" rather than silently parsing them as "1-5".
  const dashIdx = token.indexOf("-");
  if (dashIdx <= 0) {
    throw new Error(`Invalid range token "${token}"`);
  }
  const startStr = token.slice(0, dashIdx);
  const endStr   = token.slice(dashIdx + 1);

  if (endStr.includes("-")) {
    throw new Error(`Malformed range "${token}": multiple dashes`);
  }

  const start = parseIntStrict(startStr, token);
  const end   = parseIntStrict(endStr,   token);

  assertInRange(start, min, max, token);
  assertInRange(end,   min, max, token);

  if (start > end) {
    throw new Error(`Range start (${start}) exceeds end (${end}) in "${token}"`);
  }

  return [start, end];
}

function parseSingleSegment(
  segment: string,
  min: number,
  max: number
): number[] {
  // Step expressions: */n  or  start-end/n  or  start/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const leftPart  = segment.slice(0, slashIdx);
    const rightPart = segment.slice(slashIdx + 1);

    const step = parseIntStrict(rightPart, segment);
    if (step < 1) {
      throw new Error(`Step must be >= 1 in "${segment}"`);
    }

    let start: number;
    let end: number;

    if (leftPart === "*") {
      start = min;
      end   = max;
    } else if (leftPart.includes("-")) {
      [start, end] = parseRangeToken(leftPart, min, max);
    } else {
      start = parseIntStrict(leftPart, segment);
      assertInRange(start, min, max, segment);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return fillRange(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [start, end] = parseRangeToken(segment, min, max);
    return fillRange(start, end);
  }

  // Single number
  const value = parseIntStrict(segment, segment);
  assertInRange(value, min, max, segment);
  return [value];
}

function parseField(token: string, min: number, max: number): number[] {
  if (!token || token.trim() === "") {
    throw new Error("Empty cron field token");
  }

  // Comma-separated list — process each segment independently then merge
  const segments = token.split(",");

  if (segments.length > 1) {
    const seen = new Set<number>();
    for (const segment of segments) {
      const trimmed = segment.trim();
      if (trimmed === "") {
        throw new Error(`Empty segment in comma-separated field "${token}"`);
      }
      for (const v of parseSingleSegment(trimmed, min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSingleSegment(token.trim(), min, max);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const tokens = trimmed.split(/\s+/);

  if (tokens.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields; got ${tokens.length}: "${trimmed}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const [min, max] = FIELD_RANGES[field];
    try {
      result[field] = parseField(tokens[i], min, max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid ${field} field ("${tokens[i]}"): ${message}`);
    }
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete to remove entries");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  private prependHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.removeNode(node);
    this.prependHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  function debounced(...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const args = pendingArgs!;
      pendingArgs = undefined;
      fn(...args);
    }, delay);
  }

  debounced.cancel = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
      const args = pendingArgs!;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  return debounced;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

const DANGEROUS_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInner(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  // Explicit undefined source → preserve target; null is a legitimate overwrite
  if (source === undefined) return target;

  // Both arrays → concatenate (no recursive merge; avoids duplicating nested refs)
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  // Both plain objects → deep merge
  if (isPlainObject(target) && isPlainObject(source)) {
    // Guard against circular references in the source graph
    if (seen.has(source)) return seen.get(source);

    const result: Record<string, unknown> = { ...target };
    seen.set(source, result);

    for (const key of Object.keys(source)) {
      // Prototype-pollution guard
      if (DANGEROUS_KEYS.has(key)) continue;
      result[key] = mergeInner(target[key], source[key], seen);
    }

    return result;
  }

  // Scalar, Date, RegExp, Map, Set, class instance, mismatched types → source wins
  return source;
}

export default function deepMerge(
  target: Record<string, unknown>,
  source: Record<string, unknown>
): Record<string, unknown> {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: 'target' must be a plain object (got ${target === null ? "null" : typeof target})`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: 'source' must be a plain object (got ${source === null ? "null" : typeof source})`
    );
  }

  return mergeInner(target, source, new WeakMap()) as Record<string, unknown>;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {},
  visited = new WeakSet<object>()
): Record<string, unknown> {
  if (obj === null || typeof obj !== "object") {
    if (prefix) result[prefix] = obj;
    return result;
  }

  if (visited.has(obj)) {
    if (prefix) result[prefix] = "[Circular]";
    return result;
  }

  visited.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj;
    visited.delete(obj);
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const sanitizedKey = String(key);
    const fullKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = (obj as Record<string, unknown>)[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      !(value instanceof Map) &&
      !(value instanceof Set)
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result, visited);
    } else {
      result[fullKey] = value;
    }
  }

  visited.delete(obj);
  return result;
}

export default flattenObject;

class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("Capacity must be a positive integer");
    }
    this.capacity = Math.floor(capacity);
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) {
