    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  const resolvedDelay = Number.isFinite(delay) && delay >= 0 ? delay : 0;

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let pendingContext: unknown;
  let hasPending = false;

  function clearPending(): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    hasPending = false;
    pendingArgs = undefined;
    pendingContext = undefined;
  }

  function invoke(): ReturnType<T> {
    const args = pendingArgs as Parameters<T>;
    const context = pendingContext;
    // Clear state BEFORE invoking to handle re-entrant calls safely
    hasPending = false;
    pendingArgs = undefined;
    pendingContext = undefined;
    return fn.apply(context, args) as ReturnType<T>;
  }

  function debounced(this: unknown, ...args: Parameters<T>): void {
    pendingArgs = args;
    pendingContext = this;
    hasPending = true;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      if (hasPending) {
        invoke();
      }
    }, resolvedDelay);
  }

  debounced.cancel = function (): void {
    clearPending();
  };

  debounced.flush = function (): ReturnType<T> | undefined {
    if (!hasPending) {
      return undefined;
    }
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    return invoke();
  };

  return debounced as DebouncedFunction<T>;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    if (!this.map.has(key)) {
      return undefined;
    }

    const value = this.map.get(key) as T;
    // Re-insert to mark as most recently used (Map preserves insertion order)
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError("Cache value must not be undefined; use delete() to remove entries");
    }

    if (this.map.has(key)) {
      // Update existing: remove first so re-insertion moves it to most-recent position
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      // Evict least recently used (first entry in Map iteration order)
      const lruKey = this.map.keys().next().value;
      if (lruKey !== undefined) {
        this.map.delete(lruKey);
      }
    }

    this.map.set(key, value);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }
    return this.map.delete(key);
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }
    return this.map.has(key);
  }

  clear(): void {
    this.map.clear();
  }

  get size(): number {
    return this.map.size;
  }

  get remainingCapacity(): number {
    return this.capacity - this.map.size;
  }

  keys(): IterableIterator<string> {
    return this.map.keys();
  }

  values(): IterableIterator<T> {
    return this.map.values();
  }

  entries(): IterableIterator<[string, T]> {
    return this.map.entries();
  }

  [Symbol.iterator](): IterableIterator<[string, T]> {
    return this.map[Symbol.iterator]();
  }

  toJSON(): Record<string, T> {
    return Object.fromEntries(this.map);
  }
}

