    if (!hasPending) {
      return;
    }

    const args = pendingArgs as Parameters<T>;
    cancel();
    fn(...args);
  }

  function debounced(...args: Parameters<T>): void {
    pendingArgs = args;
    hasPending = true;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const argsToCall = pendingArgs as Parameters<T>;
      pendingArgs = undefined;
      hasPending = false;
      fn(...argsToCall);
    }, delay);
  }

