    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete to remove entries");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) {
      return;
    }

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete to remove entries");
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependToHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  private prependToHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }
    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    const { prev, next } = node;

    if (prev !== null) {
      prev.next = next;
    } else {
      this.head = next;
    }

    if (next !== null) {
      next.prev = prev;
    } else {
      this.tail = prev;
    }

    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.removeNode(node);
    this.prependToHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type PlainObject = Record<string, unknown>;
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: PlainObject,
  prefix: string,
  ancestors: WeakSet<object>,
  result: FlatObject
): void {
  if (ancestors.has(obj)) {
    throw new Error(
      `Circular reference detected at key path: "${prefix}"`
    );
  }

  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value)) {
      const childKeys = Object.keys(value);

      if (childKeys.length === 0) {
        // Preserve empty objects as leaf values rather than silently
        // swallowing them — losing keys is worse than preserving unexpected values
        result[fullKey] = value;
      } else {
        flattenObjectInternal(value, fullKey, ancestors, result);
      }
    } else {
      result[fullKey] = value;
    }
  }

  // Remove on exit so sibling/cousin branches sharing the same object
  // reference are not incorrectly flagged as circular (DAG is valid)
  ancestors.delete(obj);
}

export default function flattenObject(obj: unknown): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flattenObjectInternal(obj, "", new WeakSet(), result);
  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type FlatValue = Primitive | Date | RegExp | Function | unknown[];

interface FlattenedObject {
  [key: string]: unknown;
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenRecursive(
  obj: Record<string, unknown>,
  prefix: string,
  result: FlattenedObject,
  visited: WeakSet<object>
): void {
  for (const key of Object.keys(obj)) {
    const value = obj[key];
    // Escape dots in keys to prevent silent collisions
    const escapedKey = key.replace(/\\/g, "\\\\").replace(/\./g, "\\.");
    const fullKey = prefix ? `${prefix}.${escapedKey}` : escapedKey;

    if (isPlainObject(value)) {
      if (visited.has(value as object)) {
        // Circular reference: treat as opaque leaf rather than infinite loop
        result[fullKey] = "[Circular]";
        continue;
      }
      const nested = value as Record<string, unknown>;
      const keys = Object.keys(nested);
      if (keys.length === 0) {
        // Empty plain object: preserve it as a leaf so the key isn't silently lost
        result[fullKey] = {};
      } else {
        visited.add(nested);
        flattenRecursive(nested, fullKey, result, visited);
        visited.delete(nested);
      }
    } else {
      result[fullKey] = value;
    }
  }
}

export default function flattenObject(
  input: Record<string, unknown>
): FlattenedObject {
  if (input === null || input === undefined) {
    throw new TypeError(
      `flattenObject requires a non-null object, received: ${input}`
    );
  }
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject requires a plain object, received: ${Object.prototype.toString.call(input)}`
    );
  }

  const result: FlattenedObject = {};
  const visited = new WeakSet<object>();
  visited.add(input);
  flattenRecursive(input, "", result, visited);
  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_NAMES = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

function clamp(value: number, min: number, max: number): boolean {
  return value >= min && value <= max;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || !clamp(value, min, max)) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseNumber(token: string, context: string): number {
  const trimmed = token.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new SyntaxError(`Expected a non-negative integer, got "${trimmed}" in field "${context}"`);
  }
  return parseInt(trimmed, 10);
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty segment in field "${fieldName}"`);
  }

  // Step value: */n or range/n
  if (trimmed.includes("/")) {
    const slashCount = (trimmed.match(/\//g) ?? []).length;
    if (slashCount > 1) {
      throw new SyntaxError(`Multiple "/" in segment "${trimmed}" of field "${fieldName}"`);
    }

    const [rangePart, stepPart] = trimmed.split("/");

    if (stepPart === "" || stepPart === undefined) {
      throw new SyntaxError(`Missing step value after "/" in segment "${trimmed}" of field "${fieldName}"`);
    }

    const step = parseNumber(stepPart, fieldName);
    if (step === 0) {
      throw new RangeError(`Step value cannot be 0 in field "${fieldName}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = parseRange(rangePart, min, max, fieldName);
        rangeMin = lo;
        rangeMax = hi;
      } else {
        const start = parseNumber(rangePart, fieldName);
        assertInRange(start, min, max, fieldName);
        rangeMin = start;
        rangeMax = max;
      }
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range: n-m
  if (trimmed.includes("-")) {
    const [lo, hi] = parseRange(trimmed, min, max, fieldName);
    const result: number[] = [];
    for (let i = lo; i <= hi; i++) {
      result.push(i);
    }
    return result;
  }

  // Wildcard
  if (trimmed === "*") {
    const result: number[] = [];
    for (let i = min; i <= max; i++) {
      result.push(i);
    }
    return result;
  }

  // Single number
  const value = parseNumber(trimmed, fieldName);
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseRange(
  token: string,
  min: number,
  max: number,
  fieldName: string
): [number, number] {
  const dashCount = (token.match(/-/g) ?? []).length;
  if (dashCount !== 1) {
    throw new SyntaxError(
      `Expected exactly one "-" in range "${token}" of field "${fieldName}"`
    );
  }
  const [loStr, hiStr] = token.split("-");
  const lo = parseNumber(loStr, fieldName);
  const hi = parseNumber(hiStr, fieldName);
  assertInRange(lo, min, max, fieldName);
  assertInRange(hi, min, max, fieldName);
  if (lo > hi) {
    throw new RangeError(
      `Range start ${lo} is greater than end ${hi} in field "${fieldName}"`
    );
  }
  return [lo, hi];
}

function parseField(expression: string, min: number, max: number, fieldName: string): number[] {
  if (typeof expression !== "string") {
    throw new TypeError(`Field "${fieldName}" must be a string`);
  }

  const segments = expression.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Field "${fieldName}" is empty`);
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment, min, max, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Normalize internal whitespace — split on any run of whitespace
  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const fieldName = FIELD_NAMES[i];
    const { min, max } = FIELD_RANGES[fieldName];
    result[fieldName] = parseField(parts[i], min, max, fieldName);
  }

  return result;
}

type DebounceFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebounceFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      if (pendingArgs !== undefined) {
        fn(...pendingArgs);
      }
      timerId = undefined;
      pendingArgs = undefined;
    }, delay);
  } as DebounceFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    if (pendingArgs !== undefined) {
      const args = pendingArgs;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  return debounced;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function isPlainObject(value: unknown): value is NestedObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype ||
    (value !== null && typeof value === "object" && !Array.isArray(value) && Object.getPrototypeOf(value) === null)
  );
}

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  seen: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (typeof input !== "object" && !Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (typeof input === "object" && input !== null) {
    if (seen.has(input)) {
      throw new TypeError(
        `Circular reference detected at key: "${prefix}"`
      );
    }
    seen.add(input);
  }

  if (Array.isArray(input)) {
    if (input.length === 0) {
      if (prefix !== "") {
        result[prefix] = undefined;
      }
    } else {
      input.forEach((item, index) => {
        const key = prefix !== "" ? `${prefix}.${index}` : `${index}`;
        flattenObject(item, key, result, seen);
      });
    }
    return result;
  }

  if (typeof input === "object" && input !== null) {
    const obj = input as Record<string, unknown>;
    const keys = Object.keys(obj);

    if (keys.length === 0) {
      if (prefix !== "") {
        result[prefix] = undefined;
      }
      return result;
    }

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(obj, key)) {
        continue;
      }

      const sanitizedKey = key.includes(".") ? `[${key}]` : key;
      const nextPrefix =
        prefix !== "" ? `${prefix}.${sanitizedKey}` : sanitizedKey;
      const value = obj[key];

      if (
        value !== null &&
        typeof value === "object" &&
        !Array.isArray(value)
      ) {
        flattenObject(value, nextPrefix, result, seen);
      } else {
        flattenObject(value, nextPrefix, result, seen);
      }
    }
  }

  return result;
}

export default flattenObject;

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => ReturnType<T> | undefined;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError("First argument must be a function");
  }

  if (typeof delay !== "number" || !Number.isFinite(delay) || delay < 0) {
    throw new RangeError("Delay must be a non-negative finite number");
  }

  let timerId: ReturnType<typeof setTimeout> | undefined = undefined;
  let pendingArgs: Parameters<T> | undefined = undefined;
  let hasPending = false;

  const debouncedFn = function (...args: Parameters<T>): void {
    pendingArgs = args;
    hasPending = true;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;

      if (hasPending && pendingArgs !== undefined) {
        const argsToCall = pendingArgs;
        hasPending = false;
        pendingArgs = undefined;
        fn(...argsToCall);
      }
    }, delay);
  };

  const cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    hasPending = false;
    pendingArgs = undefined;
  };

  const flush = (): ReturnType<T> | undefined => {
    if (!hasPending || pendingArgs === undefined) {
      return undefined;
    }

    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }

    const argsToCall = pendingArgs;
    hasPending = false;
    pendingArgs = undefined;

    return fn(...argsToCall) as ReturnType<T>;
  };

  debouncedFn.cancel = cancel;
  debouncedFn.flush = flush;

  return debouncedFn;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("LRUCache value must not be undefined");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.detach(node);
    this.prependHead(node);
  }

  private prependHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private detach(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private evictTail(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.detach(lru);
    this.map.delete(lru.key);
  }
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>; // most recently used sentinel
  private readonly tail: Node<T>; // least recently used sentinel

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(`LRUCache capacity must be a non-negative integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes — never evicted, never returned
    this.head = new Node<T>("__head__", undefined as unknown as T);
    this.tail = new Node<T>("__tail__", undefined as unknown as T);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache: accept the call but store nothing
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node = new Node<T>(key, value);
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  // ── internal helpers ──────────────────────────────────────────────────────

  private moveToFront(node: Node<T>): void {
    this.unlink(node);
    this.insertAtFront(node);
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    // head.next is always non-null (at minimum points to tail sentinel)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private unlink(node: Node<T>): void {
    // Both neighbours are always non-null because sentinels bound the list
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    // Defensive: lru should never be the head sentinel when capacity > 0
    if (lru === null || lru === this.head) {
      return;
    }
    this.unlink(lru);
    this.map.delete(lru.key);
  }
}

class Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null = null;
  next: Node<T> | null = null;

  constructor(key: string, value: T) {
    this.key = key;
    this.value = value;
  }
}

export default LRUCache;

class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new Error("Capacity must be greater than 0");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseInteger(raw: string, fieldName: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new SyntaxError(`Expected integer, got "${raw}" in field "${fieldName}"`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isFinite(n)) {
    throw new SyntaxError(`Non-finite integer "${raw}" in field "${fieldName}"`);
  }
  return n;
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  // Step: <range-or-wildcard>/<step>
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Multiple "/" in segment "${segment}" of field "${fieldName}"`);
    }
    const [rangePart, stepRaw] = slashParts;
    const step = parseInteger(stepRaw, fieldName);
    if (step <= 0) {
      throw new RangeError(`Step must be >= 1, got ${step} in field "${fieldName}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      [rangeMin, rangeMax] = parseRange(rangePart, min, max, fieldName);
    } else {
      rangeMin = parseInteger(rangePart, fieldName);
      assertInRange(rangeMin, min, max, fieldName);
      rangeMax = max;
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [start, end] = parseRange(segment, min, max, fieldName);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single number
  const num = parseInteger(segment, fieldName);
  assertInRange(num, min, max, fieldName);
  return [num];
}

function parseRange(
  raw: string,
  min: number,
  max: number,
  fieldName: string
): [number, number] {
  const dashParts = raw.split("-");
  if (dashParts.length !== 2) {
    throw new SyntaxError(`Invalid range "${raw}" in field "${fieldName}"`);
  }
  const start = parseInteger(dashParts[0], fieldName);
  const end = parseInteger(dashParts[1], fieldName);
  assertInRange(start, min, max, fieldName);
  assertInRange(end, min, max, fieldName);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} > end ${end} in field "${fieldName}"`
    );
  }
  return [start, end];
}

function parseField(
  raw: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (raw === "" || raw === undefined || raw === null) {
    throw new SyntaxError(`Empty value for field "${fieldName}"`);
  }

  const segments = raw.split(",");
  if (segments.some((s) => s === "")) {
    throw new SyntaxError(`Trailing or consecutive commas in field "${fieldName}": "${raw}"`);
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), min, max, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const { min, max } = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max, name);
  }

  return result;
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, { value: T; prev: string | null; next: string | null }>;
  private head: string | null = null;
  private tail: string | null = null;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;
    this.moveToHead(key);
    return node.value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.get(key)!.value = value;
      this.moveToHead(key);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evict();
    }

    this.map.set(key, { value, prev: null, next: this.head });

    if (this.head !== null) {
      this.map.get(this.head)!.prev = key;
    }

    this.head = key;

    if (this.tail === null) {
      this.tail = key;
    }
  }

  private moveToHead(key: string): void {
    if (this.head === key) return;

    const node = this.map.get(key)!;
    const { prev, next } = node;

    if (prev !== null) {
      this.map.get(prev)!.next = next;
    }

    if (next !== null) {
      this.map.get(next)!.prev = prev;
    }

    if (this.tail === key) {
      this.tail = prev;
    }

    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.map.get(this.head)!.prev = key;
    }

    this.head = key;
  }

  private evict(): void {
    if (this.tail === null) return;

    const evictedKey = this.tail;
    const evictedNode = this.map.get(evictedKey)!;

    if (evictedNode.prev !== null) {
      this.map.get(evictedNode.prev)!.next = null;
      this.tail = evictedNode.prev;
    } else {
      this.head = null;
      this.tail = null;
    }

    this.map.delete(evictedKey);
  }
}

export default LRUCache;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  return source !== undefined ? source : target;
}

export default deepMerge;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new CronParseError(
      `Value ${value} is out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function expandRange(start: number, end: number, min: number, max: number, field: string): number[] {
  if (start > end) {
    throw new CronParseError(
      `Invalid range ${start}-${end} in field "${field}": start must be <= end`
    );
  }
  assertInRange(start, min, max, field);
  assertInRange(end, min, max, field);

  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function expandStep(rangeOrWildcard: string, step: number, min: number, max: number, field: string): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new CronParseError(
      `Invalid step value ${step} in field "${field}": step must be a positive integer`
    );
  }

  let start = min;
  let end = max;

  if (rangeOrWildcard !== "*") {
    const parts = rangeOrWildcard.split("-");
    if (parts.length === 2) {
      const s = parseInt(parts[0]!, 10);
      const e = parseInt(parts[1]!, 10);
      if (isNaN(s) || isNaN(e)) {
        throw new CronParseError(
          `Invalid range "${rangeOrWildcard}" in step expression for field "${field}"`
        );
      }
      assertInRange(s, min, max, field);
      assertInRange(e, min, max, field);
      if (s > e) {
        throw new CronParseError(
          `Invalid range ${s}-${e} in field "${field}": start must be <= end`
        );
      }
      start = s;
      end = e;
    } else if (parts.length === 1) {
      const s = parseInt(parts[0]!, 10);
      if (isNaN(s)) {
        throw new CronParseError(
          `Invalid start value "${rangeOrWildcard}" in step expression for field "${field}"`
        );
      }
      assertInRange(s, min, max, field);
      start = s;
    } else {
      throw new CronParseError(
        `Invalid range "${rangeOrWildcard}" in step expression for field "${field}"`
      );
    }
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseToken(token: string, config: FieldConfig, field: string): number[] {
  const { min, max } = config;

  if (token.trim() === "") {
    throw new CronParseError(`Empty token in field "${field}"`);
  }

  // Step value: */n or range/n
  if (token.includes("/")) {
    const slashIndex = token.indexOf("/");
    const left = token.slice(0, slashIndex);
    const right = token.slice(slashIndex + 1);

    if (right === "" || right.includes("/")) {
      throw new CronParseError(
        `Invalid step expression "${token}" in field "${field}"`
      );
    }

    const step = parseInt(right, 10);
    if (isNaN(step) || right !== String(step)) {
      throw new CronParseError(
        `Invalid step value "${right}" in field "${field}": must be an integer`
      );
    }

    return expandStep(left, step, min, max, field);
  }

  // Wildcard
  if (token === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range: a-b
  if (token.includes("-")) {
    const dashIndex = token.indexOf("-");
    const left = token.slice(0, dashIndex);
    const right = token.slice(dashIndex + 1);

    const start = parseInt(left, 10);
    const end = parseInt(right, 10);

    if (isNaN(start) || left !== String(start)) {
      throw new CronParseError(
        `Invalid range start "${left}" in field "${field}"`
      );
    }
    if (isNaN(end) || right !== String(end)) {
      throw new CronParseError(
        `Invalid range end "${right}" in field "${field}"`
      );
    }

    return expandRange(start, end, min, max, field);
  }

  // Plain number
  const num = parseInt(token, 10);
  if (isNaN(num) || token !== String(num)) {
    throw new CronParseError(
      `Invalid value "${token}" in field "${field}": must be an integer, wildcard, range, or step`
    );
  }

  assertInRange(num, min, max, field);
  return [num];
}

function parseField(expression: string, config: FieldConfig, field: string): number[] {
  if (typeof expression !== "string") {
    throw new CronParseError(`Field "${field}" must be a string`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError(`Field "${field}" is empty`);
  }

  // Comma-separated list
  const parts = trimmed.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    const trimmedPart = part.trim();
    if (trimmedPart === "") {
      throw new CronParseError(
        `Empty element in comma-separated list for field "${field}"`
      );
    }
    const values = parseToken(trimmedPart, config, field);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i]!;
    const fieldExpr = fields[i]!;
    const config = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(fieldExpr, config, fieldName);
  }

  return result;
}

export default parseCron;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { min: 0, max: 59, name: "minute" },
  { min: 0, max: 23, name: "hour" },
  { min: 1, max: 31, name: "dayOfMonth" },
  { min: 1, max: 12, name: "month" },
  { min: 0, max: 6, name: "dayOfWeek" },
] as const;

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function parseInteger(value: string, fieldName: string): number {
  const trimmed = value.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new CronParseError(
      `Invalid integer "${value}" in field "${fieldName}"`
    );
  }
  const parsed = parseInt(trimmed, 10);
  if (!Number.isFinite(parsed)) {
    throw new CronParseError(
      `Non-finite integer "${value}" in field "${fieldName}"`
    );
  }
  return parsed;
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (value < min || value > max) {
    throw new CronParseError(
      `Value ${value} out of range [${min}, ${max}] in ${context}`
    );
  }
}

function expandWildcard(config: FieldConfig): number[] {
  return Array.from(
    { length: config.max - config.min + 1 },
    (_, i) => config.min + i
  );
}

function expandStep(expression: string, config: FieldConfig): number[] {
  const [baseStr, stepStr] = expression.split("/");

  if (stepStr === undefined || stepStr === "") {
    throw new CronParseError(
      `Malformed step expression "${expression}" in field "${config.name}"`
    );
  }

  const step = parseInteger(stepStr, config.name);
  if (step <= 0) {
    throw new CronParseError(
      `Step value must be >= 1 in field "${config.name}", got ${step}`
    );
  }

  let rangeMin: number;
  let rangeMax: number;

  if (baseStr === "*") {
    rangeMin = config.min;
    rangeMax = config.max;
  } else if (baseStr.includes("-")) {
    const [rangeMinStr, rangeMaxStr] = baseStr.split("-");
    rangeMin = parseInteger(rangeMinStr, config.name);
    rangeMax = parseInteger(rangeMaxStr ?? "", config.name);
    assertInRange(rangeMin, config.min, config.max, `field "${config.name}"`);
    assertInRange(rangeMax, config.min, config.max, `field "${config.name}"`);
    if (rangeMin > rangeMax) {
      throw new CronParseError(
        `Range start ${rangeMin} > end ${rangeMax} in field "${config.name}"`
      );
    }
  } else {
    rangeMin = parseInteger(baseStr, config.name);
    assertInRange(rangeMin, config.min, config.max, `field "${config.name}"`);
    rangeMax = config.max;
  }

  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }

  if (values.length === 0) {
    throw new CronParseError(
      `Step expression "${expression}" produced no values in field "${config.name}"`
    );
  }

  return values;
}

function expandRange(expression: string, config: FieldConfig): number[] {
  const parts = expression.split("-");
  if (parts.length !== 2) {
    throw new CronParseError(
      `Malformed range "${expression}" in field "${config.name}"`
    );
  }

  const [startStr, endStr] = parts;
  const start = parseInteger(startStr ?? "", config.name);
  const end = parseInteger(endStr ?? "", config.name);

  assertInRange(start, config.min, config.max, `field "${config.name}"`);
  assertInRange(end, config.min, config.max, `field "${config.name}"`);

  if (start > end) {
    throw new CronParseError(
      `Range start ${start} > end ${end} in field "${config.name}"`
    );
  }

  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function expandSingleToken(token: string, config: FieldConfig): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new CronParseError(
      `Empty token encountered in field "${config.name}"`
    );
  }

  if (trimmed === "*") {
    return expandWildcard(config);
  }

  if (trimmed.includes("/")) {
    return expandStep(trimmed, config);
  }

  if (trimmed.includes("-")) {
    return expandRange(trimmed, config);
  }

  const value = parseInteger(trimmed, config.name);
  assertInRange(value, config.min, config.max, `field "${config.name}"`);
  return [value];
}

function expandField(expression: string, config: FieldConfig): number[] {
  if (expression === null || expression === undefined) {
    throw new CronParseError(`Null or undefined expression for field "${config.name}"`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError(`Empty expression for field "${config.name}"`);
  }

  const tokens = trimmed.split(",");
  if (tokens.length === 0) {
    throw new CronParseError(`No tokens in field "${config.name}"`);
  }

  const valueSet = new Set<number>();

  for (const token of tokens) {
    const values = expandSingleToken(token, config);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError(
      `Expected a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(
      `Expected 5 fields, got ${fields.length} in expression "${trimmed}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;

  return {
    minute: expandField(minuteExpr!, FIELD_CONFIGS[0]!),
    hour: expandField(hourExpr!, FIELD_CONFIGS[1]!),
    dayOfMonth: expandField(dayOfMonthExpr!, FIELD_CONFIGS[2]!),
    month: expandField(monthExpr!, FIELD_CONFIGS[3]!),
    dayOfWeek: expandField(dayOfWeekExpr!, FIELD_CONFIGS[4]!),
  };
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): ReturnType<T> | undefined;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError("First argument must be a function");
  }

  if (typeof delay !== "number" || !isFinite(delay) || delay < 0) {
    throw new RangeError("Delay must be a non-negative finite number");
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const args = pendingArgs;
      pendingArgs = null;
      if (args !== null) {
        fn(...args);
      }
    }, delay);
  };

  debounced.cancel = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): ReturnType<T> | undefined {
    if (timerId === null || pendingArgs === null) {
      return undefined;
    }

    clearTimeout(timerId);
    timerId = null;

    const args = pendingArgs;
    pendingArgs = null;

    return fn(...args) as ReturnType<T>;
  };

  return debounced;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: [keyof CronFields, FieldConfig][] = [
  ["minute",     { min: 0,  max: 59 }],
  ["hour",       { min: 0,  max: 23 }],
  ["dayOfMonth", { min: 1,  max: 31 }],
  ["month",      { min: 1,  max: 12 }],
  ["dayOfWeek",  { min: 0,  max: 7  }],
];

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function assertInteger(value: number, label: string): void {
  if (!Number.isInteger(value) || !Number.isFinite(value)) {
    throw new CronParseError(`${label} must be a finite integer, got: ${value}`);
  }
}

function assertInRange(value: number, min: number, max: number, label: string): void {
  assertInteger(value, label);
  if (value < min || value > max) {
    throw new CronParseError(
      `${label} value ${value} is out of valid range [${min}, ${max}]`
    );
  }
}

function parseNumber(token: string, label: string): number {
  const trimmed = token.trim();
  if (trimmed === "" || !/^-?\d+$/.test(trimmed)) {
    throw new CronParseError(`Invalid numeric token "${token}" in field "${label}"`);
  }
  return parseInt(trimmed, 10);
}

function expandRange(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) {
    result.push(i);
  }
  return result;
}

function deduplicateAndSort(values: number[]): number[] {
  return Array.from(new Set(values)).sort((a, b) => a - b);
}

function parseSegment(
  segment: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  const { min, max } = config;
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new CronParseError(`Empty segment in field "${fieldName}"`);
  }

  // Step value: */n or range/n
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new CronParseError(
        `Invalid step expression "${trimmed}" in field "${fieldName}": multiple "/" found`
      );
    }

    const [rangePart, stepPart] = slashParts;
    const stepStr = stepPart.trim();

    if (stepStr === "" || !/^\d+$/.test(stepStr)) {
      throw new CronParseError(
        `Invalid step value "${stepStr}" in field "${fieldName}"`
      );
    }

    const step = parseInt(stepStr, 10);
    if (step === 0) {
      throw new CronParseError(
        `Step value cannot be zero in field "${fieldName}"`
      );
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart.trim() === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.trim().includes("-")) {
      const bounds = rangePart.trim().split("-");
      if (bounds.length !== 2) {
        throw new CronParseError(
          `Invalid range "${rangePart}" in field "${fieldName}"`
        );
      }
      rangeMin = parseNumber(bounds[0], fieldName);
      rangeMax = parseNumber(bounds[1], fieldName);
      assertInRange(rangeMin, min, max, `${fieldName} range start`);
      assertInRange(rangeMax, min, max, `${fieldName} range end`);
      if (rangeMin > rangeMax) {
        throw new CronParseError(
          `Range start ${rangeMin} exceeds range end ${rangeMax} in field "${fieldName}"`
        );
      }
    } else {
      rangeMin = parseNumber(rangePart.trim(), fieldName);
      assertInRange(rangeMin, min, max, `${fieldName} step base`);
      rangeMax = max;
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }

    if (result.length === 0) {
      throw new CronParseError(
        `Step expression "${trimmed}" in field "${fieldName}" produces no values`
      );
    }

    return result;
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(min, max);
  }

  // Range: n-m
  if (trimmed.includes("-")) {
    const parts = trimmed.split("-");
    if (parts.length !== 2) {
      throw new CronParseError(
        `Invalid range "${trimmed}" in field "${fieldName}": multiple "-" found`
      );
    }
    const rangeMin = parseNumber(parts[0], fieldName);
    const rangeMax = parseNumber(parts[1], fieldName);
    assertInRange(rangeMin, min, max, `${fieldName} range start`);
    assertInRange(rangeMax, min, max, `${fieldName} range end`);
    if (rangeMin > rangeMax) {
      throw new CronParseError(
        `Range start ${rangeMin} exceeds range end ${rangeMax} in field "${fieldName}"`
      );
    }
    return expandRange(rangeMin, rangeMax);
  }

  // Single number
  const value = parseNumber(trimmed, fieldName);
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(
  field: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  if (typeof field !== "string") {
    throw new CronParseError(`Field "${fieldName}" must be a string`);
  }

  const trimmed = field.trim();
  if (trimmed === "") {
    throw new CronParseError(`Field "${fieldName}" cannot be empty`);
  }

  const segments = trimmed.split(",");
  if (segments.length === 0) {
    throw new CronParseError(`Field "${fieldName}" contains no segments`);
  }

  const values: number[] = [];
  for (const segment of segments) {
    const segmentValues = parseSegment(segment, config, fieldName);
    values.push(...segmentValues);
  }

  const result = deduplicateAndSort(values);

  // Normalize dayOfWeek: treat 7 as 0 (both represent Sunday)
  if (fieldName === "dayOfWeek" && result.includes(7)) {
    const normalized = result.filter((v) => v !== 7);
    if (!normalized.includes(0)) {
      normalized.unshift(0);
    }
    return normalized.sort((a, b) => a - b);
  }

  return result;
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError("Cron expression cannot be empty");
  }

  // Collapse multiple whitespace into single spaces
  const normalized = trimmed.replace(/\s+/g, " ");
  const fields = normalized.split(" ");

  if (fields.length !== 5) {
    throw new CronParseError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const [fieldName, config] = FIELD_CONFIGS[i];
    result[fieldName] = parseField(fields[i], config, fieldName);
  }

  return result;
}

export default parseCron;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (source === undefined) return target;
  if (target === undefined) return source;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

      const sourceVal = source[key];
      const targetVal = result[key];

      if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
        result[key] = deepMerge(targetVal, sourceVal);
      } else if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
        result[key] = [...targetVal, ...sourceVal];
      } else {
        result[key] = sourceVal;
      }
    }

    return result;
  }

  return source;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    throw new TypeError(
      `deepMerge expects plain objects; received ${typeof target} and ${typeof source}`
    );
  }

  const output: PlainObject = Object.assign({}, target);

  for (const key of Object.keys(source)) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

    const sourceVal = source[key];
    const targetVal = output[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      output[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      output[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal === undefined) {
      // Do not overwrite existing target key with undefined from source
      if (!Object.prototype.hasOwnProperty.call(target, key)) {
        output[key] = undefined;
      }
    } else {
      output[key] = sourceVal;
    }
  }

  return output as T & S;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  const output: PlainObject = Object.assign({}, target);

  for (const key of Object.keys(source)) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

    const sourceVal = source[key];
    const targetVal = output[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      output[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      output[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      output[key] = sourceVal;
    }
  }

  return output as T & S;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatValue = Primitive | Date | RegExp | Array<unknown> | Function;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: FlatValue };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (value instanceof WeakMap) return false;
  if (value instanceof WeakSet) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: NestedObject,
  prefix: string,
  result: FlatObject,
  visited: WeakSet<object>
): void {
  if (visited.has(obj)) {
    // Circular reference — emit the key with a sentinel rather than silently
    // dropping it or looping forever.
    result[prefix] = "[Circular]" as unknown as FlatValue;
    return;
  }

  visited.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Empty plain object — preserve it so data isn't silently dropped.
    if (prefix !== "") {
      result[prefix] = {} as unknown as FlatValue;
    }
    visited.delete(obj);
    return;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    // Keys containing dots are escaped to avoid ambiguity.
    const escapedKey = key.includes(".") ? key.replace(/\./g, "\\.") : key;
    const fullKey = prefix === "" ? escapedKey : `${prefix}.${escapedKey}`;
    const value = obj[key];

    if (isPlainObject(value)) {
      flattenObjectInternal(value, fullKey, result, visited);
    } else {
      result[fullKey] = value as FlatValue;
    }
  }

  visited.delete(obj);
}

export default function flattenObject(input: unknown): FlatObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlatObject = {};
  const visited = new WeakSet<object>();
  flattenObjectInternal(input, "", result, visited);
  return result;
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  const normalizedDelay = Number.isFinite(delay) && delay >= 0 ? delay : 0;

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const invoke = (): void => {
    if (pendingArgs !== undefined) {
      const args = pendingArgs;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  const clearPending = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;
    clearPending();
    timerId = setTimeout(() => {
      timerId = undefined;
      invoke();
    }, normalizedDelay);
  };

  debounced.cancel = (): void => {
    clearPending();
    pendingArgs = undefined;
  };

  debounced.flush = (): void => {
    clearPending();
    invoke();
  };

  return debounced;
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, { key: string; value: T; prev: any; next: any }>;
  private head: { key: string; value: T | null; prev: any; next: any };
  private tail: { key: string; value: T | null; prev: any; next: any };

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.map = new Map();
    this.head = { key: "", value: null, prev: null, next: null };
    this.tail = { key: "", value: null, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private remove(node: { key: string; value: T | null; prev: any; next: any }): void {
    node.prev.next = node.next;
    node.next.prev = node.prev;
  }

  private insertFront(node: { key: string; value: T | null; prev: any; next: any }): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next.prev = node;
    this.head.next = node;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;
    this.remove(node);
    this.insertFront(node);
    return node.value as T;
  }

  set(key: string, value: T): void {
    const existing = this.map.get(key);
    if (existing) {
      existing.value = value;
      this.remove(existing);
      this.insertFront(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev;
      this.remove(lru);
      this.map.delete(lru.key);
    }

    const node = { key, value, prev: null, next: null };
    this.insertFront(node);
    this.map.set(key, node);
  }
}

export default LRUCache;

type Scalar = string | number | boolean | null | undefined | symbol | bigint;
type FlatResult = Record<string, Scalar | object>;

function isTraversable(value: unknown): value is Record<string | number, unknown> {
  if (value === null || value === undefined || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  // Only recurse into plain objects and arrays — treat Date, RegExp, Map, Set, etc. as leaf values
  return proto === Object.prototype || proto === Array.prototype || proto === null;
}

function flatten(
  input: unknown,
  prefix: string,
  seen: WeakSet<object>,
  result: FlatResult,
): void {
  if (!isTraversable(input)) {
    // Primitive or non-plain object at root level with no prefix — nothing to emit
    if (prefix !== "") {
      result[prefix] = input as Scalar;
    }
    return;
  }

  const obj = input as Record<string | number, unknown>;

  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : " in root object"}`,
    );
  }

  seen.add(obj);

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    // Preserve empty objects/arrays as leaf values so no information is silently dropped
    if (prefix !== "") {
      result[prefix] = obj;
    }
  } else {
    for (const [key, value] of entries) {
      // Guard against keys that contain dots, which would produce ambiguous paths
      if (key.includes(".")) {
        const safeKey = key.replace(/\./g, "\\.");
        const fullKey = prefix !== "" ? `${prefix}.${safeKey}` : safeKey;
        flatten(value, fullKey, seen, result);
      } else {
        const fullKey = prefix !== "" ? `${prefix}.${key}` : key;
        flatten(value, fullKey, seen, result);
      }
    }
  }

  // Remove from ancestor tracking so sibling branches containing the same reference don't false-positive
  seen.delete(obj);
}

export default function flattenObject(input: unknown): FlatResult {
  if (input === null || input === undefined) {
    return {};
  }

  if (typeof input !== "object") {
    throw new TypeError(`flattenObject expects an object, received ${typeof input}`);
  }

  const result: FlatResult = {};
  flatten(input, "", new WeakSet(), result);
  return result;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    // Clamp to 0 so a zero/negative capacity is a valid no-op cache
    this.capacity = Math.max(0, capacity);
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) {
      return undefined;
    }
    // Promote to most-recently-used by deleting and reinserting
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.capacity === 0) {
      // Zero-capacity cache: accept writes but never retain anything
      return;
    }

    if (this.cache.has(key)) {
      // Remove first so reinsertion moves it to most-recently-used position
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Map iterates in insertion order; first key is least recently used
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  get size(): number {
    return this.cache.size;
  }

  has(key: string): boolean {
    return this.cache.has(key);
  }

  clear(): void {
    this.cache.clear();
  }
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  visited: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive | Array<unknown>;
    }
    return result;
  }

  const obj = input as Record<string, unknown>;

  if (visited.has(obj)) {
    throw new Error(
      `Circular reference detected at key: "${prefix || "<root>"}"`
    );
  }

  visited.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {} as unknown as Primitive;
    }
    visited.delete(obj);
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const sanitizedKey = String(key);
    const newPrefix = prefix === "" ? sanitizedKey : `${prefix}.${sanitizedKey}`;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, newPrefix, result, visited);
    } else {
      result[newPrefix] = value as Primitive | Array<unknown>;
    }
  }

  visited.delete(obj);

  return result;
}

export default flattenObject;

export type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldName = keyof CronResult;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function assertNonNegativeInteger(raw: string, fieldName: FieldName): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `[parseCron] Invalid integer "${trimmed}" in field "${fieldName}". ` +
      `Only non-negative whole numbers are accepted.`
    );
  }
  return parseInt(trimmed, 10);
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  fieldName: FieldName,
  context: string,
): void {
  if (value < min || value > max) {
    throw new RangeError(
      `[parseCron] ${context} value ${value} is outside the valid range ` +
      `[${min}, ${max}] for field "${fieldName}".`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  fieldName: FieldName,
): number[] {
  if (step <= 0) {
    throw new Error(
      `[parseCron] Step must be a positive integer in field "${fieldName}", got ${step}.`
    );
  }
  if (start > end) {
    throw new RangeError(
      `[parseCron] Range start (${start}) exceeds end (${end}) in field "${fieldName}".`
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(
  token: string,
  { min, max }: { min: number; max: number },
  fieldName: FieldName,
): number[] {
  const trimmed = token.trim();

  if (!trimmed) {
    throw new Error(
      `[parseCron] Encountered an empty segment in field "${fieldName}".`
    );
  }

  // Step expression: "base/step" — base may be "*", "n", or "a-b"
  const slashIndex = trimmed.indexOf("/");
  if (slashIndex !== -1) {
    const baseToken = trimmed.slice(0, slashIndex);
    const stepToken = trimmed.slice(slashIndex + 1).trim();

    if (!stepToken || !/^\d+$/.test(stepToken)) {
      throw new Error(
        `[parseCron] Missing or invalid step value after "/" in segment ` +
        `"${trimmed}" for field "${fieldName}".`
      );
    }

    const step = parseInt(stepToken, 10);

    if (step <= 0) {
      throw new Error(
        `[parseCron] Step must be a positive integer in field "${fieldName}", got ${step}.`
      );
    }

    // Multiple slashes are not valid cron syntax — guard against them
    if (stepToken.includes("/")) {
      throw new Error(
        `[parseCron] Multiple "/" characters found in segment "${trimmed}" for field "${fieldName}".`
      );
    }

    let start: number;
    let end: number;

    if (baseToken === "*") {
      start = min;
      end   = max;
    } else if (baseToken.includes("-")) {
      const dashIndex = baseToken.indexOf("-");
      start = assertNonNegativeInteger(baseToken.slice(0, dashIndex), fieldName);
      end   = assertNonNegativeInteger(baseToken.slice(dashIndex + 1), fieldName);
      assertInRange(start, min, max, fieldName, "Range start");
      assertInRange(end,   min, max, fieldName, "Range end");
    } else {
      start = assertNonNegativeInteger(baseToken, fieldName);
      assertInRange(start, min, max, fieldName, "Step base");
      end = max;
    }

    return expandRange(start, end, step, fieldName);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(min, max, 1, fieldName);
  }

  // Range: "a-b"
  const dashIndex = trimmed.indexOf("-");
  if (dashIndex !== -1) {
    // Ensure the dash isn't at position 0 (would indicate a negative number)
    if (dashIndex === 0) {
      throw new Error(
        `[parseCron] Negative values are not supported in field "${fieldName}": "${trimmed}".`
      );
    }
    const start = assertNonNegativeInteger(trimmed.slice(0, dashIndex), fieldName);
    const end   = assertNonNegativeInteger(trimmed.slice(dashIndex + 1), fieldName);
    assertInRange(start, min, max, fieldName, "Range start");
    assertInRange(end,   min, max, fieldName, "Range end");
    return expandRange(start, end, 1, fieldName);
  }

  // Plain integer
  const value = assertNonNegativeInteger(trimmed, fieldName);
  assertInRange(value, min, max, fieldName, "Field");
  return [value];
}

function parseField(
  raw: string,
  range: { min: number; max: number },
  fieldName: FieldName,
): number[] {
  const token = raw.trim();

  if (!token) {
    throw new Error(`[parseCron] Field "${fieldName}" is empty.`);
  }

  const parts = token.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    const trimmedPart = part.trim();
    if (!trimmedPart) {
      throw new Error(
        `[parseCron] Empty segment in comma-separated list for field "${fieldName}". ` +
        `Check for trailing commas or consecutive commas.`
      );
    }
    for (const v of parseSegment(trimmedPart, range, fieldName)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(
      `[parseCron] Expected a string expression, received ${typeof expression}.`
    );
  }

  const trimmedExpression = expression.trim();

  if (!trimmedExpression) {
    throw new Error(`[parseCron] Expression must not be an empty string.`);
  }

  const fields = trimmedExpression.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `[parseCron] A cron expression must have exactly 5 space-separated fields ` +
      `(minute hour dayOfMonth month dayOfWeek), but got ${fields.length} field(s). ` +
      `Expression: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], FIELD_RANGES[fieldName], fieldName);
  }

  return result;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete to remove entries");
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependToHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  private prependToHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;
    if (this.head !== null) {
      this.head.prev = node;
    }
    this.head = node;
    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      this.head = node.next;
    }
    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      this.tail = node.prev;
    }
    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.removeNode(node);
    this.prependToHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) return;
    this.map.delete(this.tail.key);
    this.removeNode(this.tail);
  }
}

type NestedObject = { [key: string]: unknown };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInternal(
  obj: NestedObject,
  prefix: string,
  ancestors: WeakSet<object>,
  result: Record<string, unknown>
): void {
  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      if (ancestors.has(value)) {
        throw new Error(`Circular reference detected at key: "${fullKey}"`);
      }
      // Empty plain objects become leaf values — dropping them silently would
      // lose information that the caller may depend on.
      if (Object.keys(value).length === 0) {
        result[fullKey] = value;
      } else {
        flattenInternal(value, fullKey, ancestors, result);
      }
    } else {
      // Non-plain objects (Date, RegExp, Map, Set, …), arrays, and all
      // primitives (including null, undefined) are treated as leaf values.
      result[fullKey] = value;
    }
  }

  // Backtrack so siblings that share a reference are not misidentified
  // as circular — only true ancestor cycles are an error.
  ancestors.delete(obj);
}

export default function flattenObject(
  obj: Record<string, unknown>
): Record<string, unknown> {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: Record<string, unknown> = {};
  flattenInternal(obj, "", new WeakSet<object>(), result);
  return result;
}

type FieldName = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

type CronResult = {
  [K in FieldName]: number[];
};

type FieldRange = {
  min: number;
  max: number;
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const FIELD_RANGES: Record<FieldName, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  // Accept 0–7: both 0 and 7 represent Sunday; normalize 7→0 after expansion
  dayOfWeek:  { min: 0,  max: 7  },
};

function assertIntInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value)) {
    throw new RangeError(`Expected integer in "${context}", got ${value}`);
  }
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} in "${context}" is outside valid range [${min}, ${max}]`);
  }
}

function parseStrictInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^-?\d+$/.test(trimmed)) {
    throw new TypeError(`Expected an integer in "${context}", got "${raw}"`);
  }
  return parseInt(trimmed, 10);
}

function expandRange(start: number, end: number, step: number, context: string): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer in "${context}", got ${step}`);
  }
  if (start > end) {
    throw new RangeError(`Range start (${start}) must not exceed end (${end}) in "${context}"`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];
  const context = `${field}:${segment}`;

  // Step value: */n  |  a-b/n  |  a/n  (less common but valid)
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const rangePart = segment.slice(0, slashIdx);
    const stepPart  = segment.slice(slashIdx + 1);

    if (stepPart.includes("/")) {
      throw new SyntaxError(`Multiple "/" not allowed in segment "${context}"`);
    }

    const step = parseStrictInt(stepPart, context);
    if (step <= 0) {
      throw new RangeError(`Step must be positive in "${context}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end   = max;
    } else if (rangePart.includes("-")) {
      const [lo, hi] = parseRangeParts(rangePart, min, max, context);
      start = lo;
      end   = hi;
    } else {
      start = parseStrictInt(rangePart, context);
      assertIntInRange(start, min, max, context);
      // POSIX: a/n means a, a+n, a+2n, … up to max
      end = max;
    }

    return expandRange(start, end, step, context);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1, context);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [start, end] = parseRangeParts(segment, min, max, context);
    return expandRange(start, end, 1, context);
  }

  // Single value
  const value = parseStrictInt(segment, context);
  assertIntInRange(value, min, max, context);
  return [value];
}

function parseRangeParts(
  rangePart: string,
  min: number,
  max: number,
  context: string
): [number, number] {
  const dashIdx = rangePart.indexOf("-");
  if (dashIdx <= 0) {
    throw new SyntaxError(`Invalid range expression "${rangePart}" in "${context}"`);
  }

  const startStr = rangePart.slice(0, dashIdx);
  const endStr   = rangePart.slice(dashIdx + 1);

  if (endStr.includes("-")) {
    throw new SyntaxError(`Ambiguous range "${rangePart}" in "${context}"`);
  }

  const start = parseStrictInt(startStr, context);
  const end   = parseStrictInt(endStr,   context);

  assertIntInRange(start, min, max, context);
  assertIntInRange(end,   min, max, context);

  if (start > end) {
    throw new RangeError(`Range start (${start}) exceeds end (${end}) in "${context}"`);
  }

  return [start, end];
}

function parseField(raw: string, field: FieldName): number[] {
  if (raw === undefined || raw === null || raw.trim() === "") {
    throw new TypeError(`Field "${field}" is empty or missing`);
  }

  const parts = raw.split(",");
  if (parts.length === 0) {
    throw new SyntaxError(`Field "${field}" has no valid parts`);
  }

  const valueSet = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${field}" (value: "${raw}")`);
    }
    const values = parseSegment(trimmed, field);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  let result = Array.from(valueSet);

  // Normalize dayOfWeek: 7 (Sunday alias) → 0
  if (field === "dayOfWeek") {
    if (valueSet.has(7)) {
      result = result.filter((v) => v !== 7);
      result.push(0);
    }
  }

  // Deduplicate (after normalization) and sort numerically
  return Array.from(new Set(result)).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Split on whitespace runs — tolerates multiple spaces / tabs
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${trimmed}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const rawValue  = fields[i];
    result[fieldName] = parseField(rawValue, fieldName);
  }

  // Sanity-check: no field should ever be empty after expansion
  for (const field of FIELD_ORDER) {
    if (result[field].length === 0) {
      throw new RangeError(`Field "${field}" expanded to an empty set — check your expression`);
    }
  }

  return result;
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const invoke = () => {
    if (pendingArgs !== null) {
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  };

  const cancel = () => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  const flush = () => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    invoke();
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  const normalizedDelay = Math.max(0, Number.isFinite(delay) ? delay : 0);

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  const flush = (): void => {
    if (timerId !== null && pendingArgs !== null) {
      const argsToInvoke = pendingArgs;
      cancel();
      fn(...argsToInvoke);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      const argsToInvoke = pendingArgs;
      timerId = null;
      pendingArgs = null;
      if (argsToInvoke !== null) {
        fn(...argsToInvoke);
      }
    }, normalizedDelay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | unknown[] | Date | RegExp;
};

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  return true;
}

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlattenedObject = {},
  seen: WeakSet<object> = new WeakSet()
): FlattenedObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as null | undefined;
    }
    return result;
  }

  if (!isPlainObject(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (seen.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix}"`
    );
  }

  seen.add(input as object);

  const entries = Object.entries(input as NestedObject);

  if (entries.length === 0) {
    if (prefix !== "") {
      result[prefix] = {};
    }
    seen.delete(input as object);
    return result;
  }

  for (const [key, value] of entries) {
    if (key === "") {
      throw new TypeError(`Empty string key encountered at prefix: "${prefix}"`);
    }

    if (!/^[^.]+$/.test(key)) {
      throw new TypeError(
        `Key "${key}" contains a dot, which conflicts with dot-notation flattening`
      );
    }

    const fullKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flattenObject(value, fullKey, result, seen);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  seen.delete(input as object);

  return result;
}

export default flattenObject;

type AnyFunction = (...args: any[]) => any;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number,
): DebouncedFunction<T> {
  // Guard against NaN, negative, or non-finite delays — all collapse to 0
  const safeDelay = Number.isFinite(delay) && delay >= 0 ? delay : 0;

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let pendingContext: unknown;

  function invokePending(): void {
    // Snapshot and clear before calling to prevent re-entrancy issues
    // if fn itself triggers another flush/cancel
    const args = pendingArgs;
    const ctx = pendingContext;
    pendingArgs = undefined;
    pendingContext = undefined;

    if (args !== undefined) {
      fn.apply(ctx, args);
    }
  }

  const debounced = function (this: unknown, ...args: Parameters<T>): void {
    pendingArgs = args;
    pendingContext = this;

    // Reset the timer on every call — only the trailing edge fires
    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      invokePending();
    }, safeDelay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    // Discard captured arguments so a subsequent flush is a no-op
    pendingArgs = undefined;
    pendingContext = undefined;
  };

  debounced.flush = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    // Fires immediately with captured args, or no-ops if nothing is pending
    invokePending();
  };

  return debounced;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, received: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, received: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Cache value must not be undefined");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependToHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;

    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head;
    while (current !== null) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private prependToHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.removeNode(node);
    this.prependToHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isFinite(capacity) || !Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, received: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }
    if (!this.cache.has(key)) {
      return undefined;
    }
    // Safe: we just confirmed has(key), so get() will not be undefined here
    const value = this.cache.get(key) as T;
    // Re-insert to promote to most-recently-used position
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, received: ${typeof key}`);
    }
    // A zero-capacity cache can never store anything; silently discard
    if (this.capacity === 0) {
      return;
    }
    if (this.cache.has(key)) {
      // Remove first so the re-insert below promotes it to most-recently-used
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Map iterates in insertion order; the first key is the least recently used
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }
    this.cache.set(key, value);
  }

  get size(): number {
    return this.cache.size;
  }

  has(key: string): boolean {
    return this.cache.has(key);
  }

  clear(): void {
    this.cache.clear();
  }
}

export default LRUCache;

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new Error("Capacity must be a positive integer");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key)!;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  seen: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive | unknown[];
    }
    return result;
  }

  const obj = input as Record<string, unknown>;

  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key "${prefix}"`
    );
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {} as unknown as Primitive;
    }
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    if (key === "") {
      throw new TypeError(
        `Empty string keys are not supported (found at prefix "${prefix}")`
      );
    }

    const nextPrefix = prefix === "" ? key : `${prefix}.${key}`;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, nextPrefix, result, seen);
    } else {
      result[nextPrefix] = value as Primitive | unknown[];
    }
  }

  seen.delete(obj);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : String(index);
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (source === undefined) return target;
  if (target === undefined) return source;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

      const sourceVal = source[key];
      const targetVal = result[key];

      result[key] = deepMerge(targetVal, sourceVal);
    }

    return result;
  }

  return source;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? (JSON.stringify(value) as Primitive)
        : (value as Primitive);
    }
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    throw new TypeError(
      `deepMerge expects two plain objects, received: ${typeof target}, ${typeof source}`
    );
  }

  const output: PlainObject = Object.assign({}, target);

  for (const key of Object.keys(source)) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

    const sourceVal = source[key];
    const targetVal = output[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      output[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      output[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal === undefined) {
      // Do not overwrite existing target value with undefined
      // unless target also has no value for this key
      if (!Object.prototype.hasOwnProperty.call(output, key)) {
        output[key] = sourceVal;
      }
    } else {
      output[key] = sourceVal;
    }
  }

  return output as T & S;
}

export default deepMerge;

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Expected a non-negative finite number for delay, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const argsToCall = pendingArgs;
      pendingArgs = null;

      if (argsToCall !== null) {
        fn(...argsToCall);
      }
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    if (timerId === null) {
      // Nothing pending — flush is a no-op
      return;
    }

    clearTimeout(timerId);
    timerId = null;

    const argsToCall = pendingArgs;
    pendingArgs = null;

    if (argsToCall !== null) {
      fn(...argsToCall);
    }
  };

  return debounced;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlattenedObject = { [key: string]: Primitive };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const satisfies readonly FieldConfig[];

const INTEGER_PATTERN = /^\d+$/;

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of range [${config.min}–${config.max}] for field "${config.name}" in "${context}"`
    );
  }
}

function parseInteger(raw: string, config: FieldConfig, context: string): number {
  if (!INTEGER_PATTERN.test(raw)) {
    throw new SyntaxError(
      `Expected an integer but got "${raw}" in field "${config.name}" in "${context}"`
    );
  }
  const value = parseInt(raw, 10);
  assertInRange(value, config, context);
  return value;
}

function expandRange(from: number, to: number, step: number, config: FieldConfig, context: string): number[] {
  if (from > to) {
    throw new RangeError(
      `Range start ${from} exceeds end ${to} for field "${config.name}" in "${context}"`
    );
  }
  if (step <= 0) {
    throw new RangeError(
      `Step must be a positive integer but got ${step} for field "${config.name}" in "${context}"`
    );
  }
  const values: number[] = [];
  for (let v = from; v <= to; v += step) {
    values.push(v);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig, fullExpression: string): number[] {
  const trimmed = segment.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Empty segment encountered in field "${config.name}"`);
  }

  // Step values: */n, a-b/n, or a/n (a = start, range extends to max)
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.indexOf("/");
    const rangeStr = trimmed.slice(0, slashIndex);
    const stepStr  = trimmed.slice(slashIndex + 1);

    if (!INTEGER_PATTERN.test(stepStr)) {
      throw new SyntaxError(
        `Invalid step "${stepStr}" in field "${config.name}" in "${fullExpression}"`
      );
    }
    const step = parseInt(stepStr, 10);
    if (step <= 0) {
      throw new RangeError(
        `Step must be ≥ 1 but got ${step} in field "${config.name}" in "${fullExpression}"`
      );
    }

    if (rangeStr === "*") {
      return expandRange(config.min, config.max, step, config, fullExpression);
    }

    if (rangeStr.includes("-")) {
      const dashIndex = rangeStr.indexOf("-");
      const start = parseInteger(rangeStr.slice(0, dashIndex), config, fullExpression);
      const end   = parseInteger(rangeStr.slice(dashIndex + 1), config, fullExpression);
      return expandRange(start, end, step, config, fullExpression);
    }

    // Bare number: treat as start with step extending to max
    const start = parseInteger(rangeStr, config, fullExpression);
    return expandRange(start, config.max, step, config, fullExpression);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(config.min, config.max, 1, config, fullExpression);
  }

  // Range: a-b
  if (trimmed.includes("-")) {
    const dashIndex = trimmed.indexOf("-");
    const start = parseInteger(trimmed.slice(0, dashIndex), config, fullExpression);
    const end   = parseInteger(trimmed.slice(dashIndex + 1), config, fullExpression);
    return expandRange(start, end, 1, config, fullExpression);
  }

  // Single value
  return [parseInteger(trimmed, config, fullExpression)];
}

function parseField(raw: string, config: FieldConfig, fullExpression: string): number[] {
  if (raw === null || raw === undefined || raw.trim() === "") {
    throw new SyntaxError(`Missing or empty field "${config.name}" in "${fullExpression}"`);
  }

  // Comma-separated list — parse each segment independently and merge
  const segments = raw.split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    if (segment.trim() === "") {
      throw new SyntaxError(
        `Empty item in comma-separated list for field "${config.name}" in "${fullExpression}"`
      );
    }
    for (const value of parseSegment(segment, config, fullExpression)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = fields;

  return {
    minute:     parseField(minuteRaw,     FIELD_CONFIGS[0], trimmed),
    hour:       parseField(hourRaw,       FIELD_CONFIGS[1], trimmed),
    dayOfMonth: parseField(dayOfMonthRaw, FIELD_CONFIGS[2], trimmed),
    month:      parseField(monthRaw,      FIELD_CONFIGS[3], trimmed),
    dayOfWeek:  parseField(dayOfWeekRaw,  FIELD_CONFIGS[4], trimmed),
  };
}

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(val: unknown): val is PlainObject {
  if (val === null || typeof val !== "object") return false;
  const proto = Object.getPrototypeOf(val);
  return proto === Object.prototype || proto === null;
}

function mergeInner(
  target: PlainObject,
  source: PlainObject,
  ancestorSources: WeakSet<object>
): PlainObject {
  const result: PlainObject = { ...target };

  ancestorSources.add(source);

  for (const key of Object.keys(source)) {
    // Guard against prototype pollution
    if (UNSAFE_KEYS.has(key)) continue;

    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      // Concatenate arrays — shallow copy both sides to avoid mutating inputs
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      if (ancestorSources.has(sourceVal)) {
        // Circular reference in source tree — assign reference rather than
        // recursing infinitely; callers must not rely on deep equality here
        result[key] = sourceVal;
      } else {
        result[key] = mergeInner(targetVal, sourceVal, ancestorSources);
      }
    } else {
      // Scalar, Date, RegExp, Map, Set, null, undefined — source wins
      result[key] = sourceVal;
    }
  }

  // Remove from ancestor set so the same object can appear in sibling branches
  // without being falsely flagged as circular
  ancestorSources.delete(source);

  return result;
}

export default function deepMerge(
  target: PlainObject,
  source: PlainObject
): PlainObject {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: 'target' must be a plain object, got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: 'source' must be a plain object, got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInner(target, source, new WeakSet());
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<F extends AnyFunction> = {
  (...args: Parameters<F>): void;
  cancel: () => void;
  flush: () => ReturnType<F> | undefined;
};

export default function debounce<F extends AnyFunction>(
  fn: F,
  delay: number
): DebouncedFunction<F> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }
  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Delay must be a non-negative finite number, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<F> | undefined;
  let isCancelled = false;

  const cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
    isCancelled = false;
  };

  const flush = (): ReturnType<F> | undefined => {
    if (pendingArgs === undefined) {
      return undefined;
    }
    const args = pendingArgs;
    cancel();
    return fn(...args) as ReturnType<F>;
  };

  const debounced = (...args: Parameters<F>): void => {
    pendingArgs = args;
    isCancelled = false;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      if (!isCancelled && pendingArgs !== undefined) {
        const args = pendingArgs;
        pendingArgs = undefined;
        fn(...args);
      }
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInto(
  obj: PlainObject,
  prefix: string,
  result: PlainObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    // Circular reference — store sentinel instead of infinitely recursing
    result[prefix] = "[Circular]";
    return;
  }

  ancestors.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Empty plain object — preserve it as a leaf; dropping it silently loses information
    if (prefix !== "") {
      result[prefix] = obj;
    }
    ancestors.delete(obj);
    return;
  }

  for (const key of keys) {
    // Guard against prototype-polluted or unusual key names
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value: unknown = obj[key];
    const newKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flattenInto(value, newKey, result, ancestors);
    } else {
      // Arrays, Dates, RegExps, primitives, null, undefined — all stored as-is
      result[newKey] = value;
    }
  }

  // Pop from ancestor tracking so sibling subtrees with the same object
  // reference are flattened independently rather than treated as cycles
  ancestors.delete(obj);
}

export default function flattenObject(obj: unknown): PlainObject {
  if (!isPlainObject(obj)) {
    // Defensive: refuse to flatten non-plain-object inputs rather than silently
    // returning garbage or throwing deep inside the recursion
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: PlainObject = {};
  flattenInto(obj, "", result, new WeakSet<object>());
  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of field.split(",")) {
    if (part === "*") {
      range(min, max).forEach((v) => values.add(v));
      continue;
    }

    const stepMatch = part.match(/^(\*|(\d+)-(\d+))\s*\/\s*(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);
      const start = stepMatch[1] === "*" ? min : parseInt(stepMatch[2], 10);
      const end = stepMatch[1] === "*" ? max : parseInt(stepMatch[3], 10);
      if (start < min || end > max || start > end)
        throw new Error(`Step range ${start}-${end} out of bounds [${min}, ${max}]`);
      for (let i = start; i <= end; i += step) values.add(i);
      continue;
    }

    const rangeMatch = part.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const start = parseInt(rangeMatch[1], 10);
      const end = parseInt(rangeMatch[2], 10);
      if (start < min || end > max || start > end)
        throw new Error(`Range ${start}-${end} out of bounds [${min}, ${max}]`);
      range(start, end).forEach((v) => values.add(v));
      continue;
    }

    if (/^\d+$/.test(part)) {
      const num = parseInt(part, 10);
      if (num < min || num > max)
        throw new Error(`Value ${num} out of bounds [${min}, ${max}]`);
      values.add(num);
      continue;
    }

    throw new Error(`Invalid cron field segment: "${part}"`);
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new Error("Expression must be a string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}`);

  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  return keys.reduce((acc, key, i) => {
    const [min, max] = FIELD_RANGES[key];
    acc[key] = parseField(fields[i], min, max);
    return acc;
  }, {} as CronResult);
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get size(): number {
    return this.map.size;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.promoteToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete() to remove entries");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.promoteToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;

    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head;
    while (current !== null) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  // ── private helpers ──────────────────────────────────────────────────────────

  private prependHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;
    if (this.head !== null) {
      this.head.prev = node;
    }
    this.head = node;
    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      // node is head
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      // node is tail
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private promoteToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.removeNode(node);
    this.prependHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatValue = Primitive | unknown[] | ((...args: unknown[]) => unknown);
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: FlatValue };

function isPlainObject(value: unknown): value is NestedObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    !(value instanceof Date) &&
    !(value instanceof RegExp) &&
    !(value instanceof Map) &&
    !(value instanceof Set) &&
    !(value instanceof Error)
  );
}

function flattenObjectInternal(
  obj: NestedObject,
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>
): void {
  if (seen.has(obj)) {
    // Circular reference detected — treat the node as an opaque value to
    // avoid infinite recursion; store it under whatever key we reached it by.
    result[prefix] = "[Circular]" as unknown as FlatValue;
    return;
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Empty object — preserve it rather than silently dropping the key.
    if (prefix !== "") {
      result[prefix] = {} as unknown as FlatValue;
    }
    seen.delete(obj);
    return;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    // Guard against prototype-pollution style keys that could escape the
    // flattened namespace and corrupt the result object.
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const compositeKey = prefix === "" ? key : `${prefix}.${key}`;
    const value: unknown = obj[key];

    if (isPlainObject(value)) {
      flattenObjectInternal(value, compositeKey, result, seen);
    } else {
      result[compositeKey] = value as FlatValue;
    }
  }

  seen.delete(obj);
}

export default function flattenObject(input: unknown): FlatObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    // Non-object inputs have nothing to flatten; return empty rather than
    // throwing so callers don't need to guard every call site.
    return {};
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();

  flattenObjectInternal(input, "", result, seen);

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Readonly<Record<keyof CronFields, { min: number; max: number }>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: ReadonlyArray<keyof CronFields> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function buildRange(start: number, end: number): number[] {
  if (start > end) return [];
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function parseInteger(
  raw: string,
  fieldName: keyof CronFields,
  min: number,
  max: number,
): number {
  const s = raw.trim();
  if (!/^\d+$/.test(s)) {
    throw new RangeError(
      `Invalid value "${s}" in field "${fieldName}": expected a non-negative integer`,
    );
  }
  const n = parseInt(s, 10);
  if (n < min || n > max) {
    throw new RangeError(
      `Value ${n} out of valid range [${min}–${max}] for field "${fieldName}"`,
    );
  }
  return n;
}

function parseSimple(
  expr: string,
  fieldName: keyof CronFields,
  min: number,
  max: number,
): number[] {
  // Range: "1-5"
  if (expr.includes("-")) {
    const dashParts = expr.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`Invalid range "${expr}" in field "${fieldName}"`);
    }
    const start = parseInteger(dashParts[0], fieldName, min, max);
    const end   = parseInteger(dashParts[1], fieldName, min, max);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field "${fieldName}"`,
      );
    }
    return buildRange(start, end);
  }

  // Single number
  return [parseInteger(expr, fieldName, min, max)];
}

function parseField(
  expr: string,
  fieldName: keyof CronFields,
  min: number,
  max: number,
): number[] {
  if (!expr || expr.trim() === "") {
    throw new SyntaxError(`Empty expression for field "${fieldName}"`);
  }

  // Comma-separated list: "1,3,5" or "1-3,5,9-11"
  // Process before any other rule so "1,3/2" is caught as malformed rather than silently wrong.
  if (expr.includes(",")) {
    const seen = new Set<number>();
    for (const segment of expr.split(",")) {
      const trimmed = segment.trim();
      if (!trimmed) {
        throw new SyntaxError(`Empty segment in comma list for field "${fieldName}"`);
      }
      // Disallow step syntax inside comma lists (ambiguous / non-standard)
      if (trimmed.includes("/")) {
        throw new SyntaxError(
          `Step syntax is not permitted inside a comma list in field "${fieldName}" (segment: "${trimmed}")`,
        );
      }
      for (const v of parseSimple(trimmed, fieldName, min, max)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Step: "*/15" or "1-10/2" or "5/3"
  if (expr.includes("/")) {
    const slashParts = expr.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${expr}" in field "${fieldName}"`);
    }
    const [basePart, stepStr] = slashParts;
    const stepTrimmed = stepStr.trim();
    if (!/^\d+$/.test(stepTrimmed)) {
      throw new SyntaxError(
        `Invalid step "${stepStr}" in field "${fieldName}": expected a positive integer`,
      );
    }
    const step = parseInt(stepTrimmed, 10);
    if (step === 0) {
      throw new RangeError(`Step value cannot be zero in field "${fieldName}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (basePart === "*") {
      rangeStart = min;
      rangeEnd   = max;
    } else if (basePart.includes("-")) {
      const dashParts = basePart.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(`Invalid range "${basePart}" in field "${fieldName}"`);
      }
      rangeStart = parseInteger(dashParts[0], fieldName, min, max);
      rangeEnd   = parseInteger(dashParts[1], fieldName, min, max);
      if (rangeStart > rangeEnd) {
        throw new RangeError(
          `Range start ${rangeStart} exceeds end ${rangeEnd} in field "${fieldName}"`,
        );
      }
    } else {
      // "5/3" → start from 5, step to max
      rangeStart = parseInteger(basePart, fieldName, min, max);
      rangeEnd   = max;
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (expr === "*") {
    return buildRange(min, max);
  }

  // Plain number
  return [parseInteger(expr, fieldName, min, max)];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Split on any whitespace run; guard against extra leading/trailing whitespace already trimmed above.
  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must contain exactly 5 space-separated fields, got ${parts.length}: "${expression}"`,
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name        = FIELD_ORDER[i];
    const { min, max } = FIELD_RANGES[name];
    const parsed      = parseField(parts[i], name, min, max);

    // Deduplicate and sort the final values as a safety net.
    result[name] = Array.from(new Set(parsed)).sort((a, b) => a - b);
  }

  return result;
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError("First argument must be a function");
  }

  if (typeof delay !== "number" || !isFinite(delay) || delay < 0) {
    throw new RangeError("Delay must be a non-negative finite number");
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const argsToCall = pendingArgs;
      pendingArgs = null;
      if (argsToCall !== null) {
        fn(...argsToCall);
      }
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    const argsToCall = pendingArgs;
    pendingArgs = null;
    if (argsToCall !== null) {
      fn(...argsToCall);
    }
  };

  return debounced;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = Math.floor(capacity);
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value as string;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

type AnyFunction = (...args: unknown[]) => unknown;

interface DebouncedFunction<T extends AnyFunction> {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
}

export default function debounce<T extends AnyFunction>(
