}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldMeta = {
  readonly name: keyof CronResult;
  readonly min: number;
  readonly max: number;
};

const FIELD_META: readonly FieldMeta[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  6 },
] as const;

const INTEGER_RE = /^\d+$/;

function buildRange(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new RangeError(`Step must be a positive integer, got ${step}`);
  const out: number[] = [];
  for (let i = start; i <= end; i += step) {
    out.push(i);
  }
  return out;
}

function assertInRange(value: number, meta: FieldMeta): void {
  if (value < meta.min || value > meta.max) {
    throw new RangeError(
      `Field "${meta.name}": value ${value} is outside valid range [${meta.min}, ${meta.max}]`
    );
  }
}

function parseInteger(raw: string, meta: FieldMeta, context: string): number {
  if (!INTEGER_RE.test(raw)) {
    throw new SyntaxError(`Field "${meta.name}": expected an integer in ${context}, got "${raw}"`);
  }
  const n = Number(raw);
  if (!Number.isSafeInteger(n)) {
    throw new RangeError(`Field "${meta.name}": integer overflow in "${raw}"`);
  }
  return n;
}

/**
 * Parses a single atom — either a plain integer or an A-B range.
 * Returns an array of resolved values; does NOT deduplicate.
 */
function parseAtom(atom: string, meta: FieldMeta): number[] {
  const dashIdx = atom.indexOf("-");

  if (dashIdx === -1) {
    // Plain integer
    const n = parseInteger(atom, meta, `"${atom}"`);
    assertInRange(n, meta);
    return [n];
  }

  // Range: A-B
  if (dashIdx === 0 || dashIdx === atom.length - 1) {
    throw new SyntaxError(`Field "${meta.name}": malformed range "${atom}"`);
  }

  const startRaw = atom.slice(0, dashIdx);
  const endRaw   = atom.slice(dashIdx + 1);

  // Guard against multiple dashes being misinterpreted
  if (endRaw.includes("-")) {
    throw new SyntaxError(`Field "${meta.name}": invalid range "${atom}" — only one dash allowed`);
  }

  const start = parseInteger(startRaw, meta, `range "${atom}"`);
  const end   = parseInteger(endRaw,   meta, `range "${atom}"`);

  assertInRange(start, meta);
  assertInRange(end,   meta);

  if (start > end) {
    throw new RangeError(
      `Field "${meta.name}": range start (${start}) must not exceed end (${end})`
    );
  }

  return buildRange(start, end, 1);
}

function parseField(raw: string, meta: FieldMeta): number[] {
  if (raw === "") {
    throw new SyntaxError(`Field "${meta.name}" must not be empty`);
  }

  // Wildcard: * or */step
  if (raw === "*") {
    return buildRange(meta.min, meta.max, 1);
  }

  if (raw.startsWith("*/")) {
    const stepRaw = raw.slice(2);
    if (stepRaw === "") {
      throw new SyntaxError(`Field "${meta.name}": step value missing after "*/"`);
    }
    const step = parseInteger(stepRaw, meta, `step expression "${raw}"`);
    if (step === 0) {
      throw new RangeError(`Field "${meta.name}": step value must not be zero`);
    }
    return buildRange(meta.min, meta.max, step);
  }

  // Comma-separated list: one or more atoms
  if (raw.includes(",")) {
    const parts = raw.split(",");

    // Reject trailing/leading/double commas
    for (const part of parts) {
      if (part === "") {
        throw new SyntaxError(`Field "${meta.name}": empty element in list "${raw}"`);
      }
      // Wildcards and step expressions are not valid inside a list
      if (part.includes("*")) {
        throw new SyntaxError(
          `Field "${meta.name}": wildcard "*" is not permitted inside a list ("${raw}")`
        );
      }
    }

    const seen = new Set<number>();
    for (const part of parts) {
      for (const v of parseAtom(part, meta)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Single atom (plain integer or range)
  return parseAtom(raw, meta);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("parseCron received an empty expression");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `parseCron expects exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_META.length; i++) {
    const meta   = FIELD_META[i];
    const values = parseField(fields[i], meta);

    if (values.length === 0) {
      // Defensive: buildRange / parseAtom should never yield empty, but guard anyway
      throw new RangeError(`Field "${meta.name}" resolved to an empty value set`);
    }

    result[meta.name] = values;
  }

  return result;
}

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, object>
): unknown {
  // Undefined source: leave target intact (explicit undefined ≠ "delete key")
  if (source === undefined) return target;

  // Arrays: concatenate when both sides are arrays; otherwise source wins
  if (Array.isArray(source)) {
    return Array.isArray(target) ? [...target, ...source] : [...source];
  }

  // Plain objects: recursive merge
  if (isPlainObject(source)) {
    // Guard against circular references in source graph
    if (seen.has(source)) {
      return seen.get(source);
    }

    // Start from a shallow clone of target (if it is also a plain object)
    const result: PlainObject = isPlainObject(target) ? { ...target } : {};
    seen.set(source, result);

    for (const key of Object.keys(source)) {
      // Prevent prototype-pollution attacks
      if (UNSAFE_KEYS.has(key)) continue;
      result[key] = mergeInternal(result[key], source[key], seen);
    }

    return result;
  }

  // Primitive, null, Date, Map, Set, class instance, etc. → source overwrites
  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: target must be a plain object (received ${
        target === null ? "null" : typeof target
      })`,
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: source must be a plain object (received ${
        source === null ? "null" : typeof source
      })`,
    );
  }

  return mergeInternal(target, source, new WeakMap()) as T & S;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.detach(node);
    this.prepend(node);

    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError("LRUCache does not accept undefined as a value");
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.detach(existing);
      this.prepend(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evict();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prepend(node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private detach(node: Node<T>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private prepend(node: Node<T>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private evict(): void {
    const lru = this.tail.prev!;
    if (lru === this.head) {
      return;
    }
    this.detach(lru);
    this.map.delete(lru.key);
  }
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: string;
  min: number;
  max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const satisfies readonly FieldConfig[];

function assertInBounds(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${config.min}–${config.max}] for field "${config.name}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new TypeError(`Expected an integer in "${context}", got "${raw}"`);
  }
  return parseInt(raw, 10);
}

function expandWildcard(config: FieldConfig): number[] {
  return Array.from({ length: config.max - config.min + 1 }, (_, i) => config.min + i);
}

function parseSimpleField(token: string, config: FieldConfig): number[] {
  // Wildcard
  if (token === "*") {
    return expandWildcard(config);
  }

  // Step: */n or start/n or start-end/n
  if (token.includes("/")) {
    const slashParts = token.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${token}" for field "${config.name}"`);
    }
    const [rangeRaw, stepRaw] = slashParts;
    const step = parseInteger(stepRaw, token);
    if (step <= 0) {
      throw new RangeError(`Step value must be ≥ 1 in "${token}" for field "${config.name}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangeRaw === "*") {
      rangeMin = config.min;
      rangeMax = config.max;
    } else if (rangeRaw.includes("-")) {
      [rangeMin, rangeMax] = parseRangeBounds(rangeRaw, config);
    } else {
      rangeMin = parseInteger(rangeRaw, token);
      assertInBounds(rangeMin, config);
      rangeMax = config.max;
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (token.includes("-")) {
    const [rangeMin, rangeMax] = parseRangeBounds(token, config);
    return Array.from({ length: rangeMax - rangeMin + 1 }, (_, i) => rangeMin + i);
  }

  // Single integer
  const value = parseInteger(token, `field "${config.name}"`);
  assertInBounds(value, config);
  return [value];
}

function parseRangeBounds(token: string, config: FieldConfig): [number, number] {
  const dashParts = token.split("-");
  if (dashParts.length !== 2) {
    throw new SyntaxError(`Invalid range "${token}" for field "${config.name}"`);
  }
  const start = parseInteger(dashParts[0], token);
  const end   = parseInteger(dashParts[1], token);
  assertInBounds(start, config);
  assertInBounds(end, config);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in "${token}" for field "${config.name}"`
    );
  }
  return [start, end];
}

function parseFieldExpression(expression: string, config: FieldConfig): number[] {
  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError(`Empty expression for field "${config.name}"`);
  }

  // Comma-separated list — split, recurse, deduplicate, sort
  if (trimmed.includes(",")) {
    const parts = trimmed.split(",");
    const seen = new Set<number>();
    for (const part of parts) {
      const partTrimmed = part.trim();
      if (!partTrimmed) {
        throw new SyntaxError(
          `Empty element in list "${trimmed}" for field "${config.name}"`
        );
      }
      for (const v of parseSimpleField(partTrimmed, config)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSimpleField(trimmed, config).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const tokens = trimmed.split(/\s+/);
  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `but received ${tokens.length} field(s): "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = tokens;
  const [minuteCfg, hourCfg, domCfg, monthCfg, dowCfg] = FIELD_CONFIGS;

  return {
    minute:     parseFieldExpression(minuteRaw,     minuteCfg),
    hour:       parseFieldExpression(hourRaw,       hourCfg),
    dayOfMonth: parseFieldExpression(dayOfMonthRaw, domCfg),
    month:      parseFieldExpression(monthRaw,      monthCfg),
    dayOfWeek:  parseFieldExpression(dayOfWeekRaw,  dowCfg),
  };
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive | unknown[] };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: {
    maxDepth?: number;
    preserveArrays?: boolean;
  } = {}
): FlatObject {
  const { maxDepth = Infinity, preserveArrays = true } = options;

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject: expected a plain object, got ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const result: FlatObject = {};

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      result[prefix] = current as Primitive;
      return;
    }

    if (isPlainObject(current)) {
      const keys = Object.keys(current);

      if (keys.length === 0) {
        if (prefix !== "") {
          result[prefix] = {};
        }
        return;
      }

      for (const key of keys) {
        if (key === "") {
          // Preserve empty-string keys with a sentinel to avoid silent data loss
          const nextKey = prefix !== "" ? `${prefix}.[""]` : '[""]';
          recurse(current[key], nextKey, depth + 1);
        } else if (key.includes(".")) {
          // Escape keys that contain dots to avoid ambiguity
          const escapedKey = `["${key}"]`;
          const nextKey = prefix !== "" ? `${prefix}.${escapedKey}` : escapedKey;
          recurse(current[key], nextKey, depth + 1);
        } else {
          const nextKey = prefix !== "" ? `${prefix}.${key}` : key;
          recurse(current[key], nextKey, depth + 1);
        }
      }
    } else if (Array.isArray(current) && !preserveArrays) {
      if (current.length === 0) {
        result[prefix] = [];
        return;
      }
      current.forEach((item, index) => {
        recurse(item, `${prefix}[${index}]`, depth + 1);
      });
    } else {
      if (prefix !== "") {
        result[prefix] = current as Primitive;
      }
    }
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  const normalizedDelay = Number.isFinite(delay) && delay >= 0 ? delay : 0;

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let pendingThis: unknown;

  function debounced(this: unknown, ...args: Parameters<T>): void {
    pendingArgs = args;
    pendingThis = this;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const argsToInvoke = pendingArgs;
      const thisToInvoke = pendingThis;
      pendingArgs = undefined;
      pendingThis = undefined;
      if (argsToInvoke !== undefined) {
        fn.apply(thisToInvoke, argsToInvoke);
      }
    }, normalizedDelay);
  }

  debounced.cancel = function cancel(): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
    pendingThis = undefined;
  };

  debounced.flush = function flush(): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    if (pendingArgs !== undefined) {
      const argsToInvoke = pendingArgs;
      const thisToInvoke = pendingThis;
      pendingArgs = undefined;
      pendingThis = undefined;
      fn.apply(thisToInvoke, argsToInvoke);
    }
  };

  return debounced as DebouncedFunction<T>;
}

export default debounce;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (MRU side) and tail (LRU side) to eliminate null-edge-case branches
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    if (capacity < 0) {
      throw new RangeError(`Capacity must be non-negative, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels carry no meaningful key/value; cast to satisfy the type.
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache: silently accept calls but never retain data.
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict the least-recently-used entry before inserting when at capacity.
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  // ── private helpers ──────────────────────────────────────────────────────────

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    // head.next is always non-null (at minimum it's tail), so this is safe.
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    // Both prev and next are always non-null for real (non-sentinel) nodes.
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    // Guard: lru === head means the list is empty, nothing to evict.
    if (lru === null || lru === this.head) {
      return;
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type AnyFunction = (...args: never[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }
  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Expected a non-negative finite number for delay, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  const flush = (): void => {
    if (timerId !== null && pendingArgs !== null) {
      const argsToCall = pendingArgs;
      cancel();
      fn(...argsToCall);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const argsToCall = pendingArgs;
      pendingArgs = null;
      if (argsToCall !== null) {
        fn(...argsToCall);
      }
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, field: CronField): void {
  const { min, max } = FIELD_RANGES[field];
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseInteger(raw: string, field: CronField): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new SyntaxError(
      `Invalid numeric value "${trimmed}" in field "${field}"`
    );
  }
  const value = parseInt(trimmed, 10);
  assertInRange(value, field);
  return value;
}

function expandRange(
  start: number,
  end: number,
  step: number,
  field: CronField
): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${field}"`
    );
  }
  if (step < 1) {
    throw new RangeError(
      `Step value ${step} must be >= 1 in field "${field}"`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function normalizeValues(values: number[], field: CronField): number[] {
  // For dayOfWeek, 7 is an alias for 0 (Sunday); normalize to 0
  const normalized =
    field === "dayOfWeek"
      ? values.map((v) => (v === 7 ? 0 : v))
      : values;

  // Deduplicate and sort ascending
  return [...new Set(normalized)].sort((a, b) => a - b);
}

function parseSegment(segment: string, field: CronField): number[] {
  const trimmed = segment.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Empty segment in field "${field}"`);
  }

  const { min, max } = FIELD_RANGES[field];

  // Step with optional base: */step or start-end/step
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid step expression "${trimmed}" in field "${field}"`
      );
    }

    const [basePart, stepPart] = slashParts;
    const stepPart_ = stepPart.trim();

    if (!/^\d+$/.test(stepPart_)) {
      throw new SyntaxError(
        `Invalid step value "${stepPart_}" in field "${field}"`
      );
    }
    const step = parseInt(stepPart_, 10);
    if (step < 1) {
      throw new RangeError(
        `Step must be >= 1, got ${step} in field "${field}"`
      );
    }

    const basePart_ = basePart.trim();

    if (basePart_ === "*") {
      return expandRange(min, max, step, field);
    }

    if (basePart_.includes("-")) {
      const dashParts = basePart_.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(
          `Invalid range "${basePart_}" in field "${field}"`
        );
      }
      const rangeStart = parseInteger(dashParts[0], field);
      const rangeEnd = parseInteger(dashParts[1], field);
      return expandRange(rangeStart, rangeEnd, step, field);
    }

    // Single number / step: treat as number-max/step
    const start = parseInteger(basePart_, field);
    return expandRange(start, max, step, field);
  }

  // Wildcard: expand to full range
  if (trimmed === "*") {
    return expandRange(min, max, 1, field);
  }

  // Range: start-end
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid range expression "${trimmed}" in field "${field}"`
      );
    }
    const rangeStart = parseInteger(dashParts[0], field);
    const rangeEnd = parseInteger(dashParts[1], field);
    return expandRange(rangeStart, rangeEnd, 1, field);
  }

  // Plain number
  return [parseInteger(trimmed, field)];
}

function parseField(expression: string, field: CronField): number[] {
  if (typeof expression !== "string") {
    throw new TypeError(`Field "${field}" must be a string`);
  }

  const segments = expression.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty expression for field "${field}"`);
  }

  const allValues: number[] = [];
  for (const segment of segments) {
    const values = parseSegment(segment, field);
    allValues.push(...values);
  }

  return normalizeValues(allValues, field);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Split on whitespace; require exactly 5 fields
  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(parts[i], field);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type Scalar = string | number | boolean | null | undefined;
type PlainObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map || value instanceof Set) return false;
  return true;
}

function flatten(
  obj: PlainObject,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at path "${prefix || "(root)"}"`
    );
  }

  const keys = Object.keys(obj);

  // Treat empty plain objects as leaf values to preserve their presence in output.
  if (keys.length === 0) {
    if (prefix !== "") result[prefix] = obj;
    return;
  }

  ancestors.add(obj);

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    // Reject keys that would corrupt dot-notation paths silently.
    if (key === "") {
      throw new TypeError(
        `Empty string key found at path "${prefix || "(root)"}"`
      );
    }

    const flatKey = prefix === "" ? key : `${prefix}.${key}`;
    const value: unknown = obj[key];

    if (isPlainObject(value)) {
      flatten(value, flatKey, result, ancestors);
    } else {
      result[flatKey] = value;
    }
  }

  ancestors.delete(obj); // allow same reference to appear at distinct, non-cyclic paths
}

export default function flattenObject(input: unknown): FlatObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, got ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlatObject = {};
  flatten(input, "", result, new WeakSet<object>());
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  depth: number = 0
): FlatObject {
  const MAX_DEPTH = 100;

  if (depth > MAX_DEPTH) {
    result[prefix] = "[Max depth exceeded]";
    return result;
  }

  if (input === null || input === undefined) {
    if (prefix !== "") result[prefix] = input as Primitive;
    return result;
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    if (prefix !== "") result[prefix] = input as Primitive | unknown[];
    return result;
  }

  const obj = input as Record<string, unknown>;
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix !== "") result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const sanitizedKey = String(key);
    const newPrefix = prefix !== "" ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, newPrefix, result, depth + 1);
    } else {
      result[newPrefix] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (source === undefined) return target;
  if (target === undefined) return source;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = {};

    const allKeys = new Set([
      ...Object.keys(target),
      ...Object.keys(source),
    ]);

    for (const key of allKeys) {
      const hasInTarget = Object.prototype.hasOwnProperty.call(target, key);
      const hasInSource = Object.prototype.hasOwnProperty.call(source, key);

      if (hasInTarget && hasInSource) {
        result[key] = deepMerge(target[key], source[key]);
      } else if (hasInSource) {
        const sourceVal = source[key];
        result[key] = Array.isArray(sourceVal)
          ? [...sourceVal]
          : isPlainObject(sourceVal)
            ? deepMerge({}, sourceVal)
            : sourceVal;
      } else {
        const targetVal = target[key];
        result[key] = Array.isArray(targetVal)
          ? [...targetVal]
          : isPlainObject(targetVal)
            ? deepMerge({}, targetVal)
            : targetVal;
      }
    }

    return result;
  }

  // Primitive, class instance, mixed type, null, etc.: source overwrites target
  return source;
}

export default deepMerge;

class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("Capacity must be a positive integer");
    }
    this.capacity = Math.floor(capacity);
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) {
      return undefined;
    }
    const value = this.cache.get(key)!;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(val: unknown): val is PlainObject {
  if (val === null || typeof val !== "object") return false;
  const proto = Object.getPrototypeOf(val);
  return proto === Object.prototype || proto === null;
}

function mergeRecursive(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, object>
): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const cached = seen.get(source as object);
    if (cached !== undefined) return cached;

    const result: PlainObject = { ...target };
    seen.set(source as object, result);

    for (const key of Object.keys(source)) {
      if (UNSAFE_KEYS.has(key)) continue;
      result[key] = mergeRecursive(result[key], source[key], seen);
    }

    return result;
  }

  // source === undefined: preserve target rather than wiping it
  if (source === undefined) return target;

  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  return mergeRecursive(target, source, new WeakMap()) as T & S;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  input: unknown,
  prefix = "",
  visited = new WeakSet<object>(),
  maxDepth = 100,
  currentDepth = 0
): FlatObject {
  if (input === null || input === undefined) {
    return prefix ? { [prefix]: input as Primitive } : {};
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    return prefix ? { [prefix]: input as Primitive | unknown[] } : {};
  }

  if (currentDepth > maxDepth) {
    console.warn(`flattenObject: max depth of ${maxDepth} exceeded at key "${prefix}". Stopping recursion.`);
    return prefix ? { [prefix]: input } : {};
  }

  if (visited.has(input as object)) {
    console.warn(`flattenObject: circular reference detected at key "${prefix}". Skipping.`);
    return prefix ? { [prefix]: "[Circular]" } : {};
  }

  visited.add(input as object);

  const result: FlatObject = {};
  const obj = input as Record<string, unknown>;

  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      const nested = flattenObject(value, newKey, visited, maxDepth, currentDepth + 1);
      Object.assign(result, nested);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  visited.delete(input as object);

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value as string;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

type AnyFunction = (...args: any[]) => any;

type DebouncedFunction<T extends AnyFunction> = {
  (this: ThisParameterType<T>, ...args: Parameters<T>): void;
  cancel(): void;
  flush(): ReturnType<T> | undefined;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  // Guard against NaN, Infinity, and negative values — all are unsafe for setTimeout
  const safeDelay = Number.isFinite(delay) && delay >= 0 ? Math.floor(delay) : 0;

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let pendingContext: unknown;
  let hasPending = false;

  function debounced(this: unknown, ...args: Parameters<T>): void {
    // Capture context and args for the latest call
    pendingArgs = args;
    pendingContext = this;
    hasPending = true;

    // Reset the timer — the trailing edge is always the most recent call
    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;

      // Snapshot and clear pending state before invoking — prevents stale
      // references if fn synchronously triggers another debounced call
      const args = pendingArgs!;
      const ctx = pendingContext;
      pendingArgs = undefined;
      pendingContext = undefined;
      hasPending = false;

      fn.apply(ctx, args);
    }, safeDelay);
  }

  function cancel(): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    // Always reset all pending state, even if no timer was running
    hasPending = false;
    pendingArgs = undefined;
    pendingContext = undefined;
  }

  function flush(): ReturnType<T> | undefined {
    // No pending invocation — nothing to flush
    if (!hasPending) {
      return undefined;
    }

    // Snapshot before cancel() wipes state
    const args = pendingArgs!;
    const ctx = pendingContext;

    // Cancel before invoking — if fn synchronously calls the debounced
    // function, it starts a fresh timer rather than corrupting this one
    cancel();

    return fn.apply(ctx, args) as ReturnType<T>;
  }

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced as unknown as DebouncedFunction<T>;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const satisfies Record<string, FieldRange>;

const INTEGER_RE = /^\d+$/;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  if (!INTEGER_RE.test(raw)) {
    throw new SyntaxError(`Expected a non-negative integer, got "${raw}" in field "${context}"`);
  }
  return parseInt(raw, 10);
}

function expandRange(start: number, end: number, step: number, range: FieldRange, context: string): number[] {
  assertInRange(start, range.min, range.max, context);
  assertInRange(end,   range.min, range.max, context);

  if (start > end) {
    throw new RangeError(`Range start (${start}) must be ≤ end (${end}) in field "${context}"`);
  }
  if (step < 1) {
    throw new RangeError(`Step must be ≥ 1, got ${step} in field "${context}"`);
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, range: FieldRange, context: string): number[] {
  // Step expression:  * /n  |  a-b/n  |  a/n
  if (segment.includes('/')) {
    const slashIndex = segment.indexOf('/');
    const lhs = segment.slice(0, slashIndex);
    const rhs = segment.slice(slashIndex + 1);

    if (!rhs || !INTEGER_RE.test(rhs)) {
      throw new SyntaxError(`Invalid step value "${rhs}" in field "${context}"`);
    }
    const step = parseInt(rhs, 10);
    if (step < 1) {
      throw new RangeError(`Step must be ≥ 1, got ${step} in field "${context}"`);
    }

    if (lhs === '*') {
      return expandRange(range.min, range.max, step, range, context);
    }

    if (lhs.includes('-')) {
      const [startStr, endStr] = lhs.split('-', 2);
      const start = parseInteger(startStr, context);
      const end   = parseInteger(endStr,   context);
      return expandRange(start, end, step, range, context);
    }

    // Single-start step: n/step means n to max with given step
    const start = parseInteger(lhs, context);
    return expandRange(start, range.max, step, range, context);
  }

  // Wildcard
  if (segment === '*') {
    return expandRange(range.min, range.max, 1, range, context);
  }

  // Range: a-b
  if (segment.includes('-')) {
    const dashIndex = segment.indexOf('-');
    const startStr = segment.slice(0, dashIndex);
    const endStr   = segment.slice(dashIndex + 1);

    if (!startStr || !endStr) {
      throw new SyntaxError(`Malformed range "${segment}" in field "${context}"`);
    }

    const start = parseInteger(startStr, context);
    const end   = parseInteger(endStr,   context);
    return expandRange(start, end, 1, range, context);
  }

  // Bare integer
  const value = parseInteger(segment, context);
  assertInRange(value, range.min, range.max, context);
  return [value];
}

function parseField(raw: string, range: FieldRange, context: string): number[] {
  if (!raw || !raw.trim()) {
    throw new SyntaxError(`Field "${context}" is empty`);
  }

  const segments = raw.split(',');
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in comma list for field "${context}"`);
    }
    for (const v of parseSegment(trimmed, range, context)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== 'string') {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError('Cron expression must not be empty');
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_RANGES.minute,     'minute'),
    hour:       parseField(hourRaw,   FIELD_RANGES.hour,        'hour'),
    dayOfMonth: parseField(domRaw,    FIELD_RANGES.dayOfMonth,  'dayOfMonth'),
    month:      parseField(monthRaw,  FIELD_RANGES.month,       'month'),
    dayOfWeek:  parseField(dowRaw,    FIELD_RANGES.dayOfWeek,   'dayOfWeek'),
  };
}

type DebounceFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebounceFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  const flush = (): void => {
    if (timerId !== null && pendingArgs !== null) {
      clearTimeout(timerId);
      timerId = null;
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const invokeArgs = pendingArgs;
      pendingArgs = null;
      if (invokeArgs !== null) {
        fn(...invokeArgs);
      }
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (MRU side) and tail (LRU side) to avoid null checks on every operation
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isFinite(capacity)) {
      throw new RangeError(`LRUCache: capacity must be a finite number, got ${capacity}`);
    }

    this.capacity = Math.max(0, Math.floor(capacity));
    this.map = new Map();

    // Sentinels carry no real data; key/value are placeholders
    this.head = { key: "__head__", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "__tail__", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (this.capacity === 0) {
      // Zero-capacity cache: no storage, no-op
      return;
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      // Update in-place and promote to MRU position
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU entry before inserting if at capacity
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertFront(node);
  }

  get size(): number {
    return this.map.size;
  }

  // ── Private helpers ──────────────────────────────────────────────────────────

  private insertFront(node: Node<T>): void {
    // Insert immediately after head sentinel (MRU position)
    node.prev = this.head;
    node.next = this.head.next;

    // head.next is always non-null (at minimum it points to tail)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private detach(node: Node<T>): void {
    // Both prev and next are guaranteed non-null for non-sentinel nodes
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.detach(node);
    this.insertFront(node);
  }

  private evictLRU(): void {
    // The node immediately before the tail sentinel is the LRU entry
    const lru = this.tail.prev;

    if (lru === null || lru === this.head) {
      // Sentinels are adjacent — nothing to evict (should not happen when size > 0)
      return;
    }

    this.detach(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function rangeArray(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function clampAndDedupe(values: number[], min: number, max: number): number[] {
  return [...new Set(values.filter((v) => v >= min && v <= max))].sort(
    (a, b) => a - b
  );
}

function parseSegment(
  segment: string,
  min: number,
  max: number
): number[] {
  // Wildcard
  if (segment === "*") return rangeArray(min, max);

  // Step with wildcard: */n
  const stepWildcard = segment.match(/^\*\/(\d+)$/);
  if (stepWildcard) {
    const step = parseInt(stepWildcard[1], 10);
    if (step <= 0) throw new Error(`Invalid step value: ${segment}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  // Range with optional step: n-m or n-m/s
  const rangeStep = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeStep) {
    const start = parseInt(rangeStep[1], 10);
    const end = parseInt(rangeStep[2], 10);
    const step = rangeStep[3] ? parseInt(rangeStep[3], 10) : 1;
    if (start > end) throw new Error(`Invalid range: ${segment}`);
    if (step <= 0) throw new Error(`Invalid step in range: ${segment}`);
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return clampAndDedupe(result, min, max);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (!isNaN(num) && segment === String(num)) {
    return clampAndDedupe([num], min, max);
  }

  throw new Error(`Unrecognized cron segment: "${segment}"`);
}

function parseField(
  field: string,
  min: number,
  max: number
): number[] {
  const parts = field.split(",");
  const values: number[] = [];
  for (const part of parts) {
    const parsed = parseSegment(part.trim(), min, max);
    values.push(...parsed);
  }
  // Normalize dayOfWeek: treat 7 as 0 (both mean Sunday)
  const normalized = values.map((v) => (max === 7 && v === 7 ? 0 : v));
  return clampAndDedupe(normalized, min, max === 7 ? 6 : max);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;
  const fieldKeys = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const fieldStrings = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronFields;

  for (let i = 0; i < fieldKeys.length; i++) {
    const key = fieldKeys[i];
    const { min, max } = FIELD_RANGES[key];
    result[key] = parseField(fieldStrings[i], min, max);
  }

  return result;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(start: number, end: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Step value: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    if (rangePart === "*") {
      return rangeArray(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range in step expression: "${rangePart}"`);
      }
      validateBounds(start, end, min, max, segment);
      return rangeArray(start, end, step);
    }

    throw new Error(`Invalid step expression: "${segment}"`);
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: "${segment}"`);
    }
    if (start > end) {
      throw new Error(`Range start ${start} is greater than end ${end}`);
    }
    validateBounds(start, end, min, max, segment);
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron value: "${segment}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in segment "${segment}"`);
  }
  return [value];
}

function validateBounds(
  start: number,
  end: number,
  min: number,
  max: number,
  segment: string
): void {
  if (start < min || end > max) {
    throw new Error(
      `Range ${start}-${end} out of bounds [${min}, ${max}] in segment "${segment}"`
    );
  }
}

function parseField(field: string, config: FieldConfig): number[] {
  const segments = field.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) throw new Error(`Empty segment in field: "${field}"`);
    for (const v of parseSegment(trimmed, config)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldNames = Object.keys(FIELD_CONFIGS) as (keyof CronResult)[];

  return {
    minute:     parseField(minuteField, FIELD_CONFIGS.minute),
    hour:       parseField(hourField,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domField,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthField,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowField,    FIELD_CONFIGS.dayOfWeek),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      result[key] = Object.prototype.hasOwnProperty.call(target, key)
        ? deepMerge(target[key], source[key])
        : source[key];
    }

    return result;
  }

  return source !== undefined ? source : target;
}

export default deepMerge;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  const fullRange = range(min, max);

  if (field === "*") return fullRange;

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return fullRange.filter((v) => (v - min) % step === 0);
  }

  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field.includes("-")) {
    const parts = field.split("-");
    if (parts.length !== 2) throw new Error(`Invalid range: ${field}`);
    const [start, end] = parts.map((p) => parseInt(p, 10));
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range values: ${field}`);
    if (start > end) throw new Error(`Range start exceeds end: ${field}`);
    if (start < min || end > max) throw new Error(`Range out of bounds: ${field} (valid: ${min}-${max})`);
    return range(start, end);
  }

  if (/^\d+$/.test(field)) {
    const value = parseInt(field, 10);
    if (value < min || value > max) throw new Error(`Value ${value} out of range (valid: ${min}-${max})`);
    return [value];
  }

  throw new Error(`Unsupported cron field syntax: ${field}`);
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce((acc, name, index) => {
    const [min, max] = FIELD_RANGES[name];
    acc[name] = parseField(parts[index], min, max);
    return acc;
  }, {} as CronFields);
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type NestedObject = {
  [key: string]: Primitive | NestedObject | unknown[] | unknown;
};

type FlattenedObject = Record<string, Primitive | unknown[]>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    preserveArrays?: boolean;
    maxDepth?: number;
  } = {}
): FlattenedObject {
  const {
    delimiter = ".",
    preserveArrays = true,
    maxDepth = 100,
  } = options;

  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  if (delimiter.length === 0) {
    throw new RangeError("delimiter must be a non-empty string");
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(
    current: unknown,
    prefix: string,
    depth: number
  ): void {
    if (depth > maxDepth) {
      result[prefix] = current as Primitive;
      return;
    }

    if (isPlainObject(current)) {
      if (seen.has(current as object)) {
        throw new TypeError(
          `Circular reference detected at key: "${prefix}"`
        );
      }

      seen.add(current as object);

      const keys = Object.keys(current as NestedObject);

      if (keys.length === 0) {
        // Preserve empty objects as-is if they're at a nested level
        if (prefix !== "") {
          result[prefix] = {} as unknown as Primitive;
        }
      } else {
        for (const key of keys) {
          if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

          const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
          recurse((current as NestedObject)[key], newKey, depth + 1);
        }
      }

      seen.delete(current as object);
    } else if (Array.isArray(current) && !preserveArrays) {
      if (current.length === 0) {
        result[prefix] = [] as unknown as Primitive;
      } else {
        for (let i = 0; i < current.length; i++) {
          const newKey = prefix === "" ? String(i) : `${prefix}${delimiter}${i}`;
          recurse(current[i], newKey, depth + 1);
        }
      }
    } else {
      // Primitive, array (when preserveArrays=true), Date, etc.
      result[prefix] = current as Primitive;
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): ReturnType<T> | undefined;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }
  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Expected a non-negative finite number for delay, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let pendingThis: unknown;

  function cancel(): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
    pendingThis = undefined;
  }

  function flush(): ReturnType<T> | undefined {
    if (pendingArgs === undefined) {
      return undefined;
    }
    const args = pendingArgs;
    const ctx = pendingThis;
    cancel();
    return fn.apply(ctx, args) as ReturnType<T>;
  }

  function debounced(this: unknown, ...args: Parameters<T>): void {
    pendingArgs = args;
    pendingThis = this;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const args = pendingArgs!;
      const ctx = pendingThis;
      pendingArgs = undefined;
      pendingThis = undefined;
      fn.apply(ctx, args);
    }, delay);
  }

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced as DebouncedFunction<T>;
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError("First argument must be a function");
  }
  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError("Delay must be a non-negative finite number");
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  function invoke(): void {
    if (pendingArgs === null) return;
    const argsToCall = pendingArgs;
    pendingArgs = null;
    timerId = null;
    fn(...argsToCall);
  }

  function debounced(...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, delay);
  }

  debounced.cancel = function cancel(): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function flush(): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    invoke();
  };

  return debounced;
}

type Scalar = string | number | boolean | bigint | symbol | null | undefined;

function isTraversable(value: unknown): value is Record<string | number, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  // Only recurse into plain objects and arrays; treat Date, RegExp, Map, Set, etc. as leaves
  return proto === Object.prototype || proto === null || Array.isArray(value);
}

function flattenObject(
  input: Record<string, unknown>,
  prefix = "",
  ancestors = new WeakSet<object>()
): Record<string, Scalar | object> {
  if (input === null || typeof input !== "object") {
    throw new TypeError(`flattenObject expects a non-null object, got: ${typeof input}`);
  }

  if (ancestors.has(input)) {
    throw new Error(
      `Circular reference detected at path: "${prefix || "(root)"}"`
    );
  }

  ancestors.add(input);

  const result: Record<string, Scalar | object> = {};

  for (const key of Object.keys(input)) {
    // Dots and backslashes in keys would create ambiguous paths — escape them
    const escapedKey = key.replace(/\\/g, "\\\\").replace(/\./g, "\\.");
    const fullKey = prefix ? `${prefix}.${escapedKey}` : escapedKey;
    const value = input[key];

    if (isTraversable(value)) {
      const childKeys = Object.keys(value);

      if (childKeys.length === 0) {
        // Empty plain object or empty array — preserve as a leaf to avoid silent data loss
        result[fullKey] = value;
      } else {
        const nested = flattenObject(
          value as Record<string, unknown>,
          fullKey,
          ancestors
        );
        Object.assign(result, nested);
      }
    } else {
      result[fullKey] = value as Scalar;
    }
  }

  // Remove from ancestor tracking on the way back up so sibling subtrees
  // that legitimately share a reference don't false-positive as circular
  ancestors.delete(input);

  return result;
}

export default flattenObject;

interface DLinkedNode<T> {
  key: string;
  value: T;
  prev: DLinkedNode<T> | null;
  next: DLinkedNode<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLinkedNode<T>>;
  // Sentinel nodes — eliminates null-guard branches in hot paths
  private readonly head: DLinkedNode<T>; // MRU side
  private readonly tail: DLinkedNode<T>; // LRU side

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, received: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = { key: "__HEAD__", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "__TAIL__", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) return undefined;
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    const existing = this.map.get(key);
    if (existing !== undefined) {
      // Update in place — no eviction, no map churn
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: DLinkedNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  // ── Internal linked-list helpers ──────────────────────────────────────────

  private insertAtFront(node: DLinkedNode<T>): void {
    // Splice between head sentinel and current front
    node.prev = this.head;
    node.next = this.head.next;
    // Non-null assertion is safe: head.next is always tail (or a real node)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: DLinkedNode<T>): void {
    // Sentinels guarantee prev/next are never null for real nodes
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: DLinkedNode<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    // Guard: if lru is the head sentinel, the cache is structurally empty
    if (lru === null || lru === this.head) return;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (MRU side) and tail (LRU side) — never evicted, never in map
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinels simplify edge cases: no null-checks needed when inserting/removing
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    // Promote to MRU position
    this.detach(node);
    this.insertAfterHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    const existing = this.map.get(key);

    if (existing !== undefined) {
      // Update in-place, then promote
      existing.value = value;
      this.detach(existing);
      this.insertAfterHead(existing);
      return;
    }

    // Evict LRU before inserting when at capacity
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev;
      // Guard: lru should never be the head sentinel given capacity >= 1,
      // but be defensive about corrupted list state
      if (lru === null || lru === this.head) {
        throw new Error("LRUCache internal state corrupted: no eviction candidate found");
      }
      this.detach(lru);
      this.map.delete(lru.key);
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertAfterHead(node);
    this.map.set(key, node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private detach(node: Node<T>): void {
    const { prev, next } = node;
    // prev/next should never be null for a node in the list (sentinels guard both ends),
    // but guard defensively to avoid silent memory corruption
    if (prev === null || next === null) {
      throw new Error(`LRUCache internal state corrupted: detached node "${node.key}" has null link`);
    }
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertAfterHead(node: Node<T>): void {
    const after = this.head.next;
    if (after === null) {
      throw new Error("LRUCache internal state corrupted: head.next is null");
    }
    node.prev = this.head;
    node.next = after;
    this.head.next = node;
    after.prev = node;
  }
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (source === undefined) return target;
  if (target === undefined) return source;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

      const sourceVal = source[key];
      const targetVal = result[key];

      result[key] = deepMerge(targetVal, sourceVal);
    }

    return result;
  }

  return source;
}

export default deepMerge;
